#!/usr/bin/env node
/**
 * Build a code index for the Ask-the-Cockpit "what does this do" /
 * "where is X defined" tool (Tier 4d). Walks src/ + the repo's
 * top-level reference docs, captures path + line count + a clipped
 * version of the file content (configurable cap), and writes
 * src/lib/code-index.json. Next.js bundles JSON imports automatically
 * so the runtime never has to touch the filesystem.
 *
 * Run: node scripts/build-code-index.mjs
 * Auto-runs via the `prebuild` npm hook.
 *
 * The index is intentionally KEPT IN GIT so deploys are deterministic
 * and so PR diffs surface code-shape changes. Regenerate when source
 * shifts meaningfully — `prebuild` keeps it fresh on every deploy.
 */
import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");

// Keep individual entries small enough that ~10 of them fit comfortably
// in a single LLM context turn. 8k chars × 10 = 80k chars ≈ 20k tokens.
const MAX_CHARS_PER_FILE = 8000;
const SKIP_DIRS = new Set([
  "node_modules", ".next", ".git", ".vercel", "dist", "build",
  "coverage", ".turbo", ".cache",
]);
const INCLUDE_EXTS = new Set([
  ".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs",
  ".sql",  // migrations
  ".md",   // CLAUDE/ARCHITECTURE/DATA_MODEL/PLAYBOOKS/README
]);

// Roots to walk. Keep this tight — each path here is recursive.
const WALK_ROOTS = ["src", "scripts"];
const TOP_LEVEL_FILES = [
  "CLAUDE.md", "README.md", "AGENTS.md",
  "ARCHITECTURE.md", "DATA_MODEL.md", "PLAYBOOKS.md",
  "GY_COMMAND_OPERATIONS_MANUAL.md",
  "vercel.json", "package.json", "next.config.ts", "tsconfig.json",
];

/** @typedef {{ path: string, lines: number, bytes: number, content: string, truncated: boolean }} CodeEntry */

async function walkDir(dir, acc) {
  let entries;
  try {
    entries = await fs.readdir(dir, { withFileTypes: true });
  } catch {
    return;
  }
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    const rel = path.relative(ROOT, full);
    if (entry.isDirectory()) {
      if (SKIP_DIRS.has(entry.name)) continue;
      await walkDir(full, acc);
    } else if (entry.isFile()) {
      const ext = path.extname(entry.name).toLowerCase();
      if (!INCLUDE_EXTS.has(ext)) continue;
      acc.push(rel);
    }
  }
}

async function readEntry(rel) {
  const abs = path.join(ROOT, rel);
  let buf;
  try {
    buf = await fs.readFile(abs);
  } catch {
    return null;
  }
  // Skip binary-looking files (shouldn't happen given INCLUDE_EXTS, but defensive)
  if (buf.includes(0)) return null;
  const raw = buf.toString("utf8");
  const lines = raw.split("\n").length;
  const truncated = raw.length > MAX_CHARS_PER_FILE;
  const content = truncated
    ? raw.slice(0, MAX_CHARS_PER_FILE) + `\n\n/* ...truncated; full file is ${lines} lines, ${raw.length} chars... */`
    : raw;
  return {
    path: rel.split(path.sep).join("/"), // forward slashes always
    lines,
    bytes: raw.length,
    content,
    truncated,
  };
}

async function main() {
  const paths = [];
  for (const r of WALK_ROOTS) {
    await walkDir(path.join(ROOT, r), paths);
  }
  for (const f of TOP_LEVEL_FILES) {
    const abs = path.join(ROOT, f);
    try {
      const stat = await fs.stat(abs);
      if (stat.isFile()) paths.push(f);
    } catch {
      // missing — skip silently
    }
  }
  paths.sort();

  /** @type {CodeEntry[]} */
  const entries = [];
  for (const p of paths) {
    const e = await readEntry(p);
    if (e) entries.push(e);
  }

  const index = {
    generated_at: new Date().toISOString(),
    file_count: entries.length,
    total_bytes: entries.reduce((acc, e) => acc + e.bytes, 0),
    max_chars_per_file: MAX_CHARS_PER_FILE,
    note: "Auto-generated by scripts/build-code-index.mjs. Do not edit by hand. Regenerate via `npm run build` (prebuild hook).",
    files: entries,
  };

  const out = path.join(ROOT, "src", "lib", "code-index.json");
  await fs.mkdir(path.dirname(out), { recursive: true });
  await fs.writeFile(out, JSON.stringify(index, null, 0)); // single-line for smaller diffs
  console.log(`[build-code-index] wrote ${entries.length} files (${(index.total_bytes / 1024).toFixed(1)} KiB total) → ${path.relative(ROOT, out)}`);
}

main().catch((e) => {
  console.error("[build-code-index] failed:", e);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Sync photos from ~/Desktop/ROBERTO IG/ to Supabase via Vercel API.
 *
 * Run: node scripts/sync-ig-photos.js
 *
 * Uses the deployed /api/instagram/photos/upload endpoint (has service role key).
 * No local Supabase credentials needed.
 */

import { readFileSync, readdirSync } from "fs";
import { join } from "path";
import { homedir } from "os";

const PHOTOS_DIR = join(homedir(), "Desktop", "ROBERTO IG ");
const API_BASE = "https://gy-command-george-biniaris-projects.vercel.app";
const TELEGRAM_BOT_TOKEN = "8773911706:AAFixtS_3kQLWB4G3FL9vMt4v5AKh9sNtqo";
const TELEGRAM_CHAT_ID = "8478263770";

async function sendTelegram(text) {
  await fetch(`https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ chat_id: TELEGRAM_CHAT_ID, text, parse_mode: "HTML" }),
  }).catch(() => {});
}

async function main() {
  console.log(`📁 Scanning: ${PHOTOS_DIR}`);

  // Get local files
  const localFiles = readdirSync(PHOTOS_DIR)
    .filter(f => /\.(jpg|jpeg|png|webp)$/i.test(f));
  console.log(`📷 Found ${localFiles.length} photos locally`);

  // Get already-uploaded filenames from API
  const existingRes = await fetch(`${API_BASE}/api/instagram/photos/upload`);
  const existingData = await existingRes.json();
  const uploadedNames = new Set((existingData.photos || []).map(p => p.filename));
  console.log(`☁️  Already uploaded: ${uploadedNames.size}`);

  // Find new photos
  const newPhotos = localFiles.filter(f => !uploadedNames.has(f));
  console.log(`🆕 New to upload: ${newPhotos.length}`);

  if (newPhotos.length === 0) {
    console.log("✅ All photos already synced.");
    await checkStock(existingData.photos || []);
    return;
  }

  let uploaded = 0;
  for (const filename of newPhotos) {
    const filepath = join(PHOTOS_DIR, filename);
    const bytes = readFileSync(filepath);

    console.log(`  ⬆️  Uploading: ${filename}...`);

    // Upload via Vercel API (multipart form)
    const formData = new FormData();
    formData.append("file", new Blob([bytes], { type: filename.endsWith(".png") ? "image/png" : "image/jpeg" }), filename);

    try {
      const res = await fetch(`${API_BASE}/api/instagram/photos/upload`, {
        method: "POST",
        body: formData,
      });

      const data = await res.json();
      if (data.ok) {
        uploaded++;
        console.log(`  ✅ ${filename}`);
      } else {
        console.error(`  ❌ ${filename}: ${data.error || "unknown error"}`);
      }
    } catch (err) {
      console.error(`  ❌ ${filename}: ${err.message}`);
    }

    // Small delay
    await new Promise(r => setTimeout(r, 800));
  }

  console.log(`\n✅ Uploaded ${uploaded} new photos.`);

  // Recheck stock
  const refreshRes = await fetch(`${API_BASE}/api/instagram/photos/upload`);
  const refreshData = await refreshRes.json();
  await checkStock(refreshData.photos || []);
}

async function checkStock(photos) {
  const unused = photos.filter(p => !p.used_in_post_id).length;
  const total = photos.length;
  console.log(`\n📊 Stock: ${unused} unused / ${total} total`);

  if (unused <= 10) {
    console.log(`⚠️  LOW STOCK! Add more photos to ~/Desktop/ROBERTO IG/`);
    await sendTelegram(
      `⚠️ <b>IG Photo Stock Low</b>\n\n` +
      `Only <b>${unused}</b> unused photos remaining.\n` +
      `Add more to ~/Desktop/ROBERTO IG/`
    );
  }
}

main().catch(err => {
  console.error("❌ Fatal:", err.message);
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Sync videos from ~/Desktop/ROBERTO IG videos/ to Supabase Storage.
 *
 * Run: node scripts/sync-ig-videos.js
 *
 * Uses a 2-step signed-URL upload so we bypass Vercel's 4.5 MB
 * serverless body limit (which the direct /api/instagram/videos/upload
 * endpoint inherits). Flow per file:
 *
 *   1. POST /api/instagram/videos/init-upload { filename, size }
 *      → { signedUrl, storagePath }
 *   2. PUT  <signedUrl> with the file bytes (direct to Supabase,
 *      no ceiling, same bandwidth either way).
 *   3. POST /api/instagram/videos/complete-upload { storagePath, filename, size }
 *      → { video: { id, filename, public_url, ... } }
 *
 * Accepted: .mp4, .mov, .m4v, .webm (max 100 MB — IG Graph API hard cap).
 */

import { readFileSync, readdirSync, statSync } from "fs";
import { join } from "path";
import { homedir } from "os";

const VIDEOS_DIR = join(homedir(), "Desktop", "ROBERTO IG videos");
const API_BASE = "https://gy-command-george-biniaris-projects.vercel.app";
const TELEGRAM_BOT_TOKEN = "8773911706:AAFixtS_3kQLWB4G3FL9vMt4v5AKh9sNtqo";
const TELEGRAM_CHAT_ID = "8478263770";

const MAX_SIZE_MB = 100;
const SUPPORTED_EXT = /\.(mp4|mov|m4v|webm)$/i;

async function sendTelegram(text) {
  await fetch(`https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ chat_id: TELEGRAM_CHAT_ID, text, parse_mode: "HTML" }),
  }).catch(() => {});
}

async function uploadOne(filename, filepath, sizeBytes) {
  // Step 1 — get signed URL
  const initRes = await fetch(`${API_BASE}/api/instagram/videos/init-upload`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ filename, size: sizeBytes }),
  });
  if (!initRes.ok) {
    const txt = await initRes.text().catch(() => "");
    throw new Error(`init-upload ${initRes.status}: ${txt.slice(0, 200)}`);
  }
  const initData = await initRes.json();
  const { signedUrl, storagePath } = initData;
  if (!signedUrl || !storagePath) {
    throw new Error(`init-upload missing fields: ${JSON.stringify(initData).slice(0, 200)}`);
  }

  // Step 2 — PUT bytes directly to Supabase (no Vercel ceiling)
  const bytes = readFileSync(filepath);
  const mime = filename.toLowerCase().endsWith(".mov") ? "video/quicktime" : "video/mp4";
  const putRes = await fetch(signedUrl, {
    method: "PUT",
    headers: { "Content-Type": mime },
    body: bytes,
  });
  if (!putRes.ok) {
    const txt = await putRes.text().catch(() => "");
    throw new Error(`PUT ${putRes.status}: ${txt.slice(0, 200)}`);
  }

  // Step 3 — register metadata + Gemini description
  const completeRes = await fetch(`${API_BASE}/api/instagram/videos/complete-upload`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ storagePath, filename, size: sizeBytes }),
  });
  if (!completeRes.ok) {
    const txt = await completeRes.text().catch(() => "");
    throw new Error(`complete-upload ${completeRes.status}: ${txt.slice(0, 200)}`);
  }
  return await completeRes.json();
}

async function main() {
  console.log(`🎥 Scanning: ${VIDEOS_DIR}`);

  let localFiles = [];
  try {
    localFiles = readdirSync(VIDEOS_DIR).filter((f) => SUPPORTED_EXT.test(f));
  } catch (err) {
    console.error(`❌ Folder not found: ${VIDEOS_DIR}`);
    console.error(`   Create it first: mkdir "${VIDEOS_DIR}"`);
    process.exit(1);
  }
  console.log(`🎬 Found ${localFiles.length} videos locally`);

  const oversized = [];
  const eligible = [];
  for (const f of localFiles) {
    const sizeBytes = statSync(join(VIDEOS_DIR, f)).size;
    const sizeMb = sizeBytes / (1024 * 1024);
    if (sizeMb > MAX_SIZE_MB) {
      oversized.push(`${f} (${sizeMb.toFixed(1)} MB)`);
    } else {
      eligible.push({ filename: f, sizeBytes, sizeMb });
    }
  }
  if (oversized.length > 0) {
    console.error(`⚠  ${oversized.length} file(s) exceed ${MAX_SIZE_MB} MB, skipping:`);
    oversized.forEach((o) => console.error(`   - ${o}`));
  }

  // Dedup vs already-uploaded filenames
  const existingRes = await fetch(`${API_BASE}/api/instagram/videos/upload`);
  if (!existingRes.ok) {
    console.error(`❌ /videos/upload GET returned ${existingRes.status}.`);
    process.exit(1);
  }
  const existingData = await existingRes.json();
  const uploadedNames = new Set((existingData.videos || []).map((v) => v.filename));
  console.log(`☁️  Already uploaded: ${uploadedNames.size}`);

  const newVideos = eligible.filter((v) => !uploadedNames.has(v.filename));
  console.log(`🆕 New to upload: ${newVideos.length}`);

  if (newVideos.length === 0) {
    console.log("✅ All videos already synced.");
    return;
  }

  let uploaded = 0;
  let failed = 0;
  for (const { filename, sizeBytes, sizeMb } of newVideos) {
    const filepath = join(VIDEOS_DIR, filename);
    console.log(`  ⬆️  Uploading: ${filename} (${sizeMb.toFixed(1)} MB)...`);
    try {
      await uploadOne(filename, filepath, sizeBytes);
      uploaded++;
      console.log(`  ✅ ${filename}`);
    } catch (err) {
      failed++;
      console.error(`  ❌ ${filename}: ${err.message}`);
    }
    await new Promise((r) => setTimeout(r, 300));
  }

  console.log(`\n✅ Done. Uploaded ${uploaded} / ${newVideos.length} (${failed} failed)`);
  await sendTelegram(
    `🎬 Video sync complete: uploaded ${uploaded} / ${newVideos.length}` +
      (failed > 0 ? ` (${failed} failed)` : "") +
      (oversized.length > 0 ? `\n\n⚠ ${oversized.length} file(s) > ${MAX_SIZE_MB} MB skipped.` : ""),
  );
}

main().catch((err) => {
  console.error("Fatal:", err);
  process.exit(1);
});

// @ts-nocheck
import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export async function GET() {
  const sb = createServiceClient();

  // Check if column already exists
  const { data: existing } = await sb
    .from("contacts")
    .select("contact_type")
    .limit(1);

  if (existing !== null) {
    return NextResponse.json({
      status: "already_exists",
      message: "contact_type column already exists on contacts table",
    });
  }

  return NextResponse.json({
    status: "needs_migration",
    message: "Run this SQL in Supabase SQL Editor:",
    sql: `
ALTER TABLE contacts ADD COLUMN IF NOT EXISTS contact_type TEXT DEFAULT 'OUTREACH_LEAD';

ALTER TABLE contacts ADD CONSTRAINT contacts_contact_type_check
CHECK (contact_type IN ('CENTRAL_AGENT','B2B_PARTNER','BROKER_CLIENT','DIRECT_CLIENT','PRESS_MEDIA','INDUSTRY','OUTREACH_LEAD'));

CREATE INDEX IF NOT EXISTS idx_contacts_contact_type ON contacts(contact_type);
    `.trim(),
  });
}

// One-shot backfill: scan previously-classified inbox mail and archive
// whatever the new warmup detector now recognises as warmup. Use this
// once after shipping the warmup filter to clean the backlog that the
// first classify pass labelled as NEUTRAL but which is actually fake
// engagement mail from Mailwarm/Lemwarm/Smartlead/etc.
//
// Safe to re-run: we re-check every matched message through the
// detector, so a false positive path can only happen if the detector
// itself is too aggressive (in which case the whole cron is too
// aggressive).

import { NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";
import { detectWarmup } from "@/lib/email-warmup-detector";

export const runtime = "nodejs";
export const maxDuration = 300;

type GmailHeader = { name: string; value: string };
type GmailMessage = {
  id: string;
  snippet?: string;
  payload?: {
    headers?: GmailHeader[];
    parts?: any[];
    body?: { data?: string };
    mimeType?: string;
  };
};

function getHeader(headers: GmailHeader[] | undefined, name: string): string {
  if (!headers) return "";
  return (
    headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ?? ""
  );
}

function extractBody(payload: GmailMessage["payload"]): string {
  if (!payload) return "";
  const walk = (part: any): string => {
    if (!part) return "";
    const mt = (part.mimeType || "").toLowerCase();
    if (part.body?.data && (mt === "text/plain" || mt === "text/html")) {
      const raw = Buffer.from(part.body.data, "base64url").toString("utf8");
      if (mt === "text/plain") return raw;
      return raw.replace(/<style[\s\S]*?<\/style>/gi, "").replace(/<[^>]+>/g, " ");
    }
    if (Array.isArray(part.parts)) {
      const plain = part.parts.find(
        (p: any) => (p.mimeType || "").toLowerCase() === "text/plain",
      );
      if (plain) return walk(plain);
      return part.parts.map(walk).join("\n");
    }
    return "";
  };
  return walk(payload).slice(0, 12000);
}

async function ensureLabel(
  name: string,
  cache: Map<string, string>,
): Promise<string | null> {
  if (cache.has(name)) return cache.get(name)!;
  const listRes = await gmailFetch("/labels");
  if (!listRes.ok) return null;
  const listJson = (await listRes.json()) as { labels?: { id: string; name: string }[] };
  const existing = (listJson.labels ?? []).find((l) => l.name === name);
  if (existing) {
    cache.set(name, existing.id);
    return existing.id;
  }
  const createRes = await gmailFetch("/labels", {
    method: "POST",
    body: JSON.stringify({
      name,
      labelListVisibility: "labelShow",
      messageListVisibility: "show",
    }),
  });
  if (!createRes.ok) return null;
  const created = (await createRes.json()) as { id: string };
  cache.set(name, created.id);
  return created.id;
}

export async function GET() {
  const labelCache = new Map<string, string>();
  const warmupLabelId = await ensureLabel("gy-warmup", labelCache);
  if (!warmupLabelId) {
    return NextResponse.json({ error: "failed to create/find gy-warmup label" }, { status: 500 });
  }
  // Get the IDs of the existing neutral-label so we can find stamped messages
  const listLabelsRes = await gmailFetch("/labels");
  if (!listLabelsRes.ok) return NextResponse.json({ error: "list labels failed" }, { status: 500 });
  const labelsJson = (await listLabelsRes.json()) as { labels?: { id: string; name: string }[] };
  const neutralLabel = (labelsJson.labels ?? []).find((l) => l.name === "gy-classified/neutral");
  if (!neutralLabel) {
    return NextResponse.json({ skipped: "no neutral label yet — cron has not run" });
  }

  // Search: inbox emails previously bucketed as neutral
  const query = "in:inbox label:gy-classified/neutral";
  const listRes = await gmailFetch(
    `/messages?${new URLSearchParams({ q: query, maxResults: "100" })}`,
  );
  if (!listRes.ok) {
    return NextResponse.json(
      { error: "gmail list failed", status: listRes.status },
      { status: 500 },
    );
  }
  const listJson = (await listRes.json()) as { messages?: { id: string }[] };
  const messageIds = listJson.messages ?? [];
  if (messageIds.length === 0) {
    return NextResponse.json({ scanned: 0, archived: 0 });
  }

  let archived = 0;
  let kept = 0;
  const archivedSamples: any[] = [];

  for (const { id } of messageIds) {
    try {
      const res = await gmailFetch(`/messages/${id}?format=full`);
      if (!res.ok) continue;
      const msg = (await res.json()) as GmailMessage;
      const headers = msg.payload?.headers ?? [];
      const from = getHeader(headers, "From");
      const subject = getHeader(headers, "Subject");
      const body = extractBody(msg.payload) || msg.snippet || "";
      const headersMap: Record<string, string> = {};
      for (const h of headers) headersMap[h.name.toLowerCase()] = h.value;

      const verdict = detectWarmup({ from, subject, body, headers: headersMap });
      if (!verdict.isWarmup) {
        kept += 1;
        continue;
      }

      await gmailFetch(`/messages/${id}/modify`, {
        method: "POST",
        body: JSON.stringify({
          addLabelIds: [warmupLabelId],
          removeLabelIds: ["INBOX", "UNREAD", neutralLabel.id],
        }),
      });
      archived += 1;
      if (archivedSamples.length < 10) {
        archivedSamples.push({
          id,
          from: from.slice(0, 80),
          subject: subject.slice(0, 80),
          reason: verdict.reason,
          service: verdict.service,
        });
      }
    } catch (e: any) {
      console.error("[backfill] error on", id, e.message);
    }
  }

  return NextResponse.json({
    scanned: messageIds.length,
    archived,
    kept_as_neutral: kept,
    samples: archivedSamples,
  });
}

// One-shot redo endpoint for blog-to-social.
//
// Deletes the three live posts from yesterday's first-run (which had a
// truncated caption on IG and a plain image with no visible text on the
// story), removes the article URL from the dedup set, and re-fires the
// broadcaster with the hardened captions + burned-in story image.
//
// Pass ?url=<article URL> to target a specific article, or leave blank
// to redo the most recently-broadcast one.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

const KEY = "blog_published_to_social";

async function getPublishedSet(): Promise<Set<string>> {
  const sb = createServiceClient();
  const { data } = await sb.from("settings").select("value").eq("key", KEY).maybeSingle();
  try {
    const arr = JSON.parse((data?.value as string) ?? "[]");
    return new Set(Array.isArray(arr) ? arr : []);
  } catch {
    return new Set();
  }
}

async function savePublishedSet(set: Set<string>): Promise<void> {
  const sb = createServiceClient();
  await sb.from("settings").upsert({ key: KEY, value: JSON.stringify([...set]) });
}

async function deleteIgMedia(mediaId: string): Promise<{ ok: boolean; detail?: any }> {
  const token = process.env.IG_ACCESS_TOKEN;
  if (!token) return { ok: false, detail: "IG_ACCESS_TOKEN missing" };
  const res = await fetch(
    `https://graph.instagram.com/v21.0/${mediaId}?access_token=${encodeURIComponent(token)}`,
    { method: "DELETE" },
  );
  const json = await res.json().catch(() => ({}));
  return { ok: res.ok, detail: json };
}

async function deleteFbPost(postId: string): Promise<{ ok: boolean; detail?: any }> {
  const token = process.env.FB_PAGE_ACCESS_TOKEN;
  if (!token) return { ok: false, detail: "FB_PAGE_ACCESS_TOKEN missing" };
  const res = await fetch(
    `https://graph.facebook.com/v21.0/${postId}?access_token=${encodeURIComponent(token)}`,
    { method: "DELETE" },
  );
  const json = await res.json().catch(() => ({}));
  return { ok: res.ok, detail: json };
}

