import { NextResponse } from "next/server";

export async function GET() {
  // Use Supabase Management API or direct pg connection
  // Since we can't run raw SQL via REST, provide the SQL to run manually
  const sql = `
CREATE TABLE IF NOT EXISTS ig_posts (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  image_url TEXT NOT NULL,
  caption TEXT,
  schedule_time TIMESTAMPTZ,
  status TEXT DEFAULT 'draft' CHECK (status IN ('draft','scheduled','publishing','published','failed')),
  ig_media_id TEXT,
  published_at TIMESTAMPTZ,
  error TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Allow anon/authenticated access
ALTER TABLE ig_posts ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow all" ON ig_posts FOR ALL USING (true) WITH CHECK (true);
`;

  // Try using the Supabase service role with pg endpoint
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

  if (!supabaseUrl || !serviceKey) {
    return NextResponse.json({ sql, message: "Run this SQL in Supabase SQL Editor" });
  }

  try {
    const res = await fetch(`${supabaseUrl}/rest/v1/rpc/`, {
      method: "POST",
      headers: {
        apikey: serviceKey,
        Authorization: `Bearer ${serviceKey}`,
        "Content-Type": "application/json",
      },
    });

    // This won't work for DDL — return SQL for manual execution
    return NextResponse.json({ sql, message: "Run this SQL in Supabase SQL Editor at: " + supabaseUrl.replace('.supabase.co', '.supabase.co/project/default/sql') });
  } catch {
    return NextResponse.json({ sql, message: "Run this SQL in Supabase SQL Editor" });
  }
}

// One-shot: force-mirror a specific ig_posts row to Facebook,
// regardless of facebook_status / age / post_type filters that the
// daily cron applies. Useful when the daily cron skipped a row and
// you want to backfill.
//
// Usage: GET /api/admin/fb-force-mirror?id=<ig_posts.id>
//        GET /api/admin/fb-force-mirror?dump=1&id=<id>  (read-only inspect)

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import {
  publishPhoto,
  publishPhotoCarousel,
  publishVideo,
} from "@/lib/facebook-client";

export const runtime = "nodejs";
export const maxDuration = 120;

export async function GET(req: NextRequest) {
  const id = req.nextUrl.searchParams.get("id");
  if (!id) {
    return NextResponse.json({ error: "?id required" }, { status: 400 });
  }
  const dumpOnly = req.nextUrl.searchParams.get("dump") === "1";

  const sb = createServiceClient();
  const { data: row, error: selErr } = await sb
    .from("ig_posts")
    .select("*")
    .eq("id", id)
    .maybeSingle();
  if (selErr) {
    return NextResponse.json({ error: selErr.message }, { status: 500 });
  }
  if (!row) {
    return NextResponse.json({ error: "row not found" }, { status: 404 });
  }

  if (dumpOnly) {
    return NextResponse.json({
      ok: true,
      row: {
        id: row.id,
        status: row.status,
        post_type: row.post_type,
        published_at: row.published_at,
        facebook_status: row.facebook_status,
        facebook_post_id: row.facebook_post_id,
        facebook_error: row.facebook_error,
        image_url: (row.image_url ?? "").slice(0, 200),
        caption_preview: (row.caption ?? "").slice(0, 200),
      },
    });
  }

  if (row.status !== "published") {
    return NextResponse.json(
      { error: `row status is ${row.status}, not published` },
      { status: 400 },
    );
  }
  if (!row.image_url) {
    return NextResponse.json(
      { error: "row has no image_url to mirror" },
      { status: 400 },
    );
  }

  const caption = (row.caption ?? "").trim();
  let publishRes: any;
  if (row.post_type === "reel") {
    publishRes = await publishVideo({ videoUrl: row.image_url, caption });
  } else if (row.post_type === "fleet_yacht") {
    const photos: string[] = Array.isArray(row?.metadata?.photos)
      ? row.metadata.photos
      : [row.image_url].filter(Boolean);
    publishRes =
      photos.length > 1
        ? await publishPhotoCarousel({ photoUrls: photos, caption })
        : await publishPhoto({ photoUrl: photos[0], caption });
  } else {
    publishRes = await publishPhoto({ photoUrl: row.image_url, caption });
  }

  if (!publishRes.ok) {
    await sb
      .from("ig_posts")
      .update({
        facebook_status: "failed",
        facebook_error: publishRes.error ?? "unknown",
      })
      .eq("id", id);
    return NextResponse.json({
      ok: false,
      published: false,
      error: publishRes.error,
    });
  }

  await sb
    .from("ig_posts")
    .update({
      facebook_status: "published",
      facebook_post_id: publishRes.post_id,
      facebook_error: null,
    })
    .eq("id", id);

  return NextResponse.json({
    ok: true,
    published: true,
    facebook_post_id: publishRes.post_id,
  });
}

// Diagnostic: lists the Pages the IG_ACCESS_TOKEN user manages and
// their per-page access tokens. First call also seeds the cached
// Page token in settings.fb_page_token so the mirror cron can run.
//
// Also probes /me to diagnose token-level issues (common failure
// mode: the stored token is IG-Graph-API-scoped and can't call
// /me/accounts).

import { NextResponse } from "next/server";
import { listPages } from "@/lib/facebook-client";

export const runtime = "nodejs";

const GRAPH = "https://graph.facebook.com/v21.0";

export async function GET() {
  const userToken = process.env.IG_ACCESS_TOKEN;
  const tokenInfo = {
    has_token: !!userToken,
    length: userToken?.length ?? 0,
    prefix: userToken?.slice(0, 8) ?? "",
    looks_like_short_lived: userToken?.startsWith("EAA") ?? false,
  };

  // Probe /me — if this works the token is a valid FB User token;
  // if it errors with 190 the token is expired or not a user token.
  let meProbe: any = { skipped: "no token" };
  if (userToken) {
    try {
      const r = await fetch(
        `${GRAPH}/me?fields=id,name&access_token=${userToken}`
      );
      meProbe = await r.json();
    } catch (e: any) {
      meProbe = { error: e.message };
    }
  }

  // Debug-token to inspect scopes.
  let debugToken: any = { skipped: "no token" };
  if (userToken) {
    try {
      const r = await fetch(
        `${GRAPH}/debug_token?input_token=${userToken}&access_token=${userToken}`
      );
      debugToken = await r.json();
    } catch (e: any) {
      debugToken = { error: e.message };
    }
  }

  const pages = await listPages();
  const safePages = {
    ...pages,
    data: (pages.data ?? []).map((p: any) => ({
      id: p.id,
      name: p.name,
      category: p.category,
      has_access_token: !!p.access_token,
      tasks: p.tasks,
    })),
  };

  return NextResponse.json({
    token: tokenInfo,
    me: meProbe,
    debug_token: debugToken,
    pages: safePages,
  });
}

