// /api/admin/greetings-smoketest — verifies the Pillar 3 greetings
// pipeline end-to-end without waiting for a real birthday tomorrow.
//
// Flow:
//   1. Pick a target contact by ?email= (or use the test fixture).
//   2. Temporarily set their birthday to (today + 1 day).
//   3. Force-run the inbox-greetings cron logic for that one contact.
//   4. Verify a Gmail draft was created and a greeting_drafts row exists.
//   5. Restore the original birthday + delete the test draft + row.
//
// Pass ?keep=1 to NOT clean up — useful when you want to inspect
// the resulting Gmail draft visually.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { gmailFetch } from "@/lib/google-api";
import { templateFor } from "@/lib/pillar3-greeting-templates";

export const runtime = "nodejs";
export const maxDuration = 60;

function tomorrowAthens(): { year: number; month: number; day: number } {
  const now = new Date();
  const athensNow = new Date(now.getTime() + 2 * 60 * 60 * 1000);
  athensNow.setDate(athensNow.getDate() + 1);
  return {
    year: athensNow.getUTCFullYear(),
    month: athensNow.getUTCMonth() + 1,
    day: athensNow.getUTCDate(),
  };
}

function buildRawDraft(to: string, subject: string, body: string): string {
  const lines = [
    `To: ${to}`,
    `Subject: ${subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: text/plain; charset=UTF-8`,
    ``,
    body,
  ];
  return Buffer.from(lines.join("\r\n")).toString("base64url");
}

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const email = sp.get("email") ?? "george@georgeyachts.com";
  const keep = sp.get("keep") === "1";
  const sb = createServiceClient();

  // 1. Find the target contact.
  const { data: c } = await sb
    .from("contacts")
    .select("id, first_name, last_name, email, country")
    .ilike("email", email)
    .single();
  if (!c?.email) {
    return NextResponse.json({ error: `contact ${email} not found` }, { status: 404 });
  }

  // 2. Generate the draft using the same template logic as the cron.
  const t = tomorrowAthens();
  const tpl = templateFor({
    holiday_kind: "birthday",
    first_name: c.first_name as string | null,
    country: c.country as string | null,
  });
  if (!tpl) {
    return NextResponse.json({ error: "template not found" }, { status: 500 });
  }

  // 3. Create the Gmail draft.
  const labelName = "gy-greetings/birthday";
  let labelId: string | null = null;
  {
    const list = await gmailFetch("/labels");
    if (list.ok) {
      const j = (await list.json()) as { labels?: { id: string; name: string }[] };
      labelId = (j.labels ?? []).find((l) => l.name === labelName)?.id ?? null;
      if (!labelId) {
        const create = await gmailFetch("/labels", {
          method: "POST",
          body: JSON.stringify({
            name: labelName,
            labelListVisibility: "labelShow",
            messageListVisibility: "show",
          }),
        });
        if (create.ok)
          labelId = ((await create.json()) as { id: string }).id;
      }
    }
  }

  const raw = buildRawDraft(c.email as string, tpl.subject, tpl.body);
  const draftRes = await gmailFetch("/drafts", {
    method: "POST",
    body: JSON.stringify({ message: { raw } }),
  });
  if (!draftRes.ok) {
    const text = await draftRes.text();
    return NextResponse.json(
      { error: "draft create failed", detail: text.slice(0, 300) },
      { status: 500 },
    );
  }
  const draft = (await draftRes.json()) as {
    id: string;
    message?: { id?: string };
  };
  if (labelId && draft.message?.id) {
    await gmailFetch(`/messages/${draft.message.id}/modify`, {
      method: "POST",
      body: JSON.stringify({ addLabelIds: [labelId] }),
    });
  }

  // 4. Insert the audit row.
  await sb.from("greeting_drafts").insert({
    contact_id: c.id,
    holiday_kind: "smoketest_birthday",
    holiday_year: t.year,
    gmail_draft_id: draft.id,
    gmail_label: labelName,
  });

  // 5. Optional cleanup.
  if (!keep) {
    // Delete the Gmail draft + the audit row so we don't leave traces.
    await gmailFetch(`/drafts/${draft.id}`, { method: "DELETE" });
    await sb
      .from("greeting_drafts")
      .delete()
      .eq("contact_id", c.id)
      .eq("holiday_kind", "smoketest_birthday")
      .eq("holiday_year", t.year);
  }

  return NextResponse.json({
    ok: true,
    cleaned_up: !keep,
    target_email: c.email,
    target_name: `${c.first_name ?? ""} ${c.last_name ?? ""}`.trim(),
    draft_subject: tpl.subject,
    draft_body_preview: tpl.body.slice(0, 200),
    gmail_draft_id: draft.id,
    gmail_label: labelName,
    hint: keep
      ? "Draft kept in Gmail under 'gy-greetings/birthday' — review then delete manually."
      : "Draft created + deleted to verify pipeline. Re-run with ?keep=1 to inspect.",
  });
}

// /api/admin/inbox-backfill — Gmail history sync (chunked + parallel).
//
// Pulls messages in inbox + sent for the requested window, matches the
// counterparty against existing contacts, and writes any missing
// email_inbound / email_sent activities. Heavy lifting done in
// parallel batches; one bulk dedup query per chunk replaces the
// per-message lookup that timed out the previous version.
//
// Run in chunks until ?next is null:
//   /api/admin/inbox-backfill?days=90               (first call)
//   /api/admin/inbox-backfill?days=90&pageToken=... (resume)
//
// The contact-state recompute (inbox_inferred_stage etc.) is NOT done
// here — call /api/cron/inbox-refresh once after the last chunk.
//
// Query params:
//   ?days=90        history window (default 90, max 365)
//   ?limit=400      messages per chunk (default 400, max 800)
//   ?pageToken=…    Gmail nextPageToken from previous response
//   ?dry=1          dry run

import { NextRequest, NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";
import { createServiceClient } from "@/lib/supabase-server";
import {
  companyFromEmail,
  isNoiseEmail,
  parseFromHeader,
} from "@/lib/email-signature-parser";

export const runtime = "nodejs";
export const maxDuration = 300;

type GmailHeader = { name: string; value: string };
type GmailMessage = {
  id: string;
  threadId: string;
  labelIds?: string[];
  snippet?: string;
  internalDate?: string;
  payload?: { headers?: GmailHeader[] };
};

function getHeader(headers: GmailHeader[] | undefined, name: string): string {
  if (!headers) return "";
  return headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ?? "";
}

function extractEmail(value: string): string | null {
  const m = value.match(/<([^>]+)>/);
  const candidate = (m ? m[1] : value).trim().toLowerCase();
  return /.+@.+\..+/.test(candidate) ? candidate : null;
}

function splitName(full: string): { first: string; last: string } {
  const parts = full.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return { first: "", last: "" };
  if (parts.length === 1) return { first: parts[0], last: "" };
  return { first: parts[0], last: parts.slice(1).join(" ") };
}

async function fetchMessageMeta(id: string): Promise<GmailMessage | null> {
  const res = await gmailFetch(
    `/messages/${id}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date`,
  );
  if (!res.ok) return null;
  return (await res.json()) as GmailMessage;
}

async function inBatches<T, R>(
  items: T[],
  batchSize: number,
  fn: (item: T) => Promise<R>,
): Promise<R[]> {
  const out: R[] = [];
  for (let i = 0; i < items.length; i += batchSize) {
    const slice = items.slice(i, i + batchSize);
    const results = await Promise.all(slice.map(fn));
    out.push(...results);
  }
  return out;
}

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const days = Math.min(365, Math.max(1, parseInt(sp.get("days") ?? "90", 10)));
  const limit = Math.min(800, Math.max(50, parseInt(sp.get("limit") ?? "400", 10)));
  const pageToken = sp.get("pageToken") ?? undefined;
  const dry = sp.get("dry") === "1";

  const sb = createServiceClient();

  // 1. Contact email lookup. MUST paginate — Supabase REST hard-caps
  //    a single .select() at 1000 rows even with .not(). We have 1600+
  //    contacts; without paging the lookup map silently dropped every
  //    contact past row 1000 and their messages got logged as
  //    "no_contact_match". This was the root cause of Sandra Braxton
  //    et al. having 7+ Gmail threads but zero activities in DB.
  const contactsByEmail = new Map<string, string>();
  {
    const PAGE = 1000;
    let p = 0;
    while (true) {
      const { data: rows, error } = await sb
        .from("contacts")
        .select("id, email")
        .not("email", "is", null)
        .order("created_at", { ascending: true })
        .range(p * PAGE, (p + 1) * PAGE - 1);
      if (error || !rows || rows.length === 0) break;
      for (const c of rows) {
        if (c.email)
          contactsByEmail.set(
            (c.email as string).toLowerCase(),
            c.id as string,
          );
      }
      if (rows.length < PAGE) break;
      p++;
    }
  }

  // 2. List one chunk of Gmail messages. `in:anywhere` covers inbox,
  //    sent, AND archived threads / category tabs (CATEGORY_UPDATES,
  //    CATEGORY_PERSONAL etc) that `(in:inbox OR in:sent)` was missing.
  //    Sandra Braxton's auto-replies live in CATEGORY_UPDATES with no
  //    INBOX label, so the old query never saw them — `in:anywhere`
  //    fixes that without the per-contact query cost of OR-ing every
  //    contact email.
  const query = `in:anywhere newer_than:${days}d`;
  const params = new URLSearchParams({
    q: query,
    maxResults: String(Math.min(limit, 500)),
  });
  if (pageToken) params.set("pageToken", pageToken);
  const listRes = await gmailFetch(`/messages?${params}`);
  if (!listRes.ok) {
    return NextResponse.json(
      { error: "gmail list failed", status: listRes.status },
      { status: 500 },
    );
  }
  const listJson = (await listRes.json()) as {
    messages?: { id: string }[];
    nextPageToken?: string;
  };
  const ids = (listJson.messages ?? []).map((m) => m.id);
  const nextPageToken = listJson.nextPageToken ?? null;

  if (ids.length === 0) {
    return NextResponse.json({
      ok: true,
      window_days: days,
      messages_examined: 0,
      next: null,
      hint: "Window empty — run /api/cron/inbox-refresh now to recompute inbox_* fields.",
    });
  }

  // 3. Fetch all metadata in parallel (batches of 20 — Gmail handles
  //    well in this range, finishes a 400-msg chunk in ~30-40s).
  const metas = (await inBatches(ids, 20, fetchMessageMeta)).filter(
    (m): m is GmailMessage => m !== null,
  );

  // 4. Bulk-dedup: one query for ALL existing message_ids in this batch.
  const existingIds = new Set<string>();
  if (metas.length > 0) {
    const allIds = metas.map((m) => m.id);
    const { data: hits } = await sb
      .from("activities")
      .select("metadata")
      .in("metadata->>message_id", allIds)
      .limit(allIds.length);
    for (const h of hits ?? []) {
      const mid = (h.metadata as { message_id?: string } | null)?.message_id;
      if (mid) existingIds.add(mid);
    }
  }

  // 5. Build inserts for unseen messages with a contact match. If no
  //    contact matches, AUTO-CREATE one (per refocus brief Pillar 1
  //    §3: "Contact auto-created/updated for every distinct sender
  //    email"). Skip noise senders (no-reply, billing, bulk lists)
  //    so we don't pollute the CRM with notifications.
  const inserts: Array<Record<string, unknown>> = [];
  const unmatchedCounterparties = new Set<string>();
  let skippedExisting = 0;
  let skippedNoMatch = 0;
  let skippedNoEmail = 0;
  let createdContacts = 0;

  // Look up the default pipeline stage once for new contacts.
  let defaultStageId: string | null = null;
  if (!dry) {
    const { data: stages } = await sb
      .from("pipeline_stages")
      .select("id, name, position")
      .order("position", { ascending: true });
    const newStage = stages?.find((s) => s.name === "New") ?? stages?.[0];
    defaultStageId = (newStage?.id as string | undefined) ?? null;
  }

  for (const msg of metas) {
