// /api/admin/inbox-classify — classifies all email_inbound activities
// that haven't been classified yet, plus updates contact lifecycle
// fields (parked_until, declined_at, lifecycle_state).
//
// Heuristics-only by default to keep cost down on the bulk pass.
// Pass ?ai=1 to let unclassified-by-heuristic rows fall through to
// the AI verifier. Time-budgeted with resumable cursor.
//
// Run pattern:
//   /api/admin/inbox-classify              first chunk (heuristics only)
//   /api/admin/inbox-classify?offset=NNN   resume
//   /api/admin/inbox-classify?ai=1         heuristics + AI fallback
//
// Idempotent: skips rows that already have message_class set unless
// ?force=1 is passed.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { classifyMessage, type MessageClass } from "@/lib/message-classifier";

export const runtime = "nodejs";
export const maxDuration = 300;

const INBOUND_TYPES = [
  "email_inbound",
  "email_received",
  "email_reply_hot_or_warm",
  "email_reply_cold",
  "reply",
];

const SELF_EMAIL = "george@georgeyachts.com";

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const startOffset = parseInt(sp.get("offset") ?? "0", 10);
  const useAi = sp.get("ai") === "1";
  const force = sp.get("force") === "1";
  const budgetMs = 250_000;
  const startedAt = Date.now();

  const sb = createServiceClient();

  // Pull candidate activity IDs. The default mode (no ?force) filters
  // for message_class IS NULL — so after each update those rows leave
  // the view and we ALWAYS query from offset 0 (the next unclassified
  // batch). With ?force the cursor advances normally because the view
  // is stable.
  const PAGE = 500;
  let cursor = startOffset;
  let processed = 0;
  let updated = 0;
  const counts: Record<string, number> = {};
  const lifecycleUpdates = new Map<
    string,
    { parked_until?: string; declined_at?: string; declined_reason?: string }
  >();

  while (Date.now() - startedAt < budgetMs) {
    // When filtering, always read from row 0 — updated rows fall out
    // of the view, so the next batch of unclassified is at the top.
    const from = force ? cursor : 0;
    const to = from + PAGE - 1;
    let query = sb
      .from("activities")
      .select("id, contact_id, created_at, description, metadata")
      .in("type", INBOUND_TYPES)
      .order("created_at", { ascending: false })
      .range(from, to);
    if (!force) query = query.is("message_class", null);
    const { data: rows, error } = await query;
    if (error || !rows || rows.length === 0) {
      // No more rows — done.
      break;
    }
    for (const r of rows) {
      if (Date.now() - startedAt >= budgetMs) {
        return NextResponse.json({
          ok: true,
          processed,
          updated,
          counts,
          next_offset: cursor,
          hint: `Resume with ?offset=${cursor}`,
        });
      }
      const meta = (r.metadata ?? {}) as Record<string, unknown>;
      const subject = (meta.subject as string) ?? "";
      const snippet = (meta.snippet as string) ?? r.description ?? "";
      const fromHeader = (meta.from as string) ?? "";

      const cls = await classifyMessage(
        {
          from: fromHeader,
          self_email: SELF_EMAIL,
          subject,
          body: snippet,
          headers: {},
        },
        { useAi },
      );

      counts[cls.message_class] = (counts[cls.message_class] ?? 0) + 1;

      await sb
        .from("activities")
        .update({
          message_class: cls.message_class,
          message_class_confidence: cls.confidence,
          message_class_reason: cls.reason,
        })
        .eq("id", r.id);
      updated++;
      processed++;

      // Lifecycle side-effects on the contact.
      if (
        r.contact_id &&
        (cls.message_class === "parked" || cls.message_class === "declined")
      ) {
        const cid = r.contact_id as string;
        const cur = lifecycleUpdates.get(cid) ?? {};
        if (cls.message_class === "parked" && cls.parked_until) {
          cur.parked_until = cls.parked_until;
        }
        if (cls.message_class === "declined") {
          cur.declined_at = r.created_at as string;
          if (cls.decline_reason) cur.declined_reason = cls.decline_reason;
        }
        lifecycleUpdates.set(cid, cur);
      }
      cursor++;
    }
    if (rows.length < PAGE) break;
  }

  // Apply lifecycle updates in bulk per contact.
  for (const [cid, upd] of lifecycleUpdates.entries()) {
    const patch: Record<string, unknown> = {};
    if (upd.parked_until) {
      patch.parked_until = upd.parked_until;
      patch.lifecycle_state = "parked";
    }
    if (upd.declined_at) {
      patch.declined_at = upd.declined_at;
      patch.lifecycle_state = "declined";
      if (upd.declined_reason) patch.declined_reason = upd.declined_reason;
    }
    if (Object.keys(patch).length > 0) {
      await sb.from("contacts").update(patch).eq("id", cid);
    }
  }

  return NextResponse.json({
    ok: true,
    processed,
    updated,
    counts: counts as Record<MessageClass, number>,
    lifecycle_updates: lifecycleUpdates.size,
    next_offset: null,
    hint: "All eligible activities classified.",
  });
}

// /api/admin/inbox-cleanup-noise-emails — purge contacts whose
// email matches the (now-broader) noise localpart patterns.
//
// Contacts created before the noise filter was strengthened can sit
// in the cockpit polluting the owed_reply pile (DMARC reports,
// invoice@, support@, dealermessage@, etc). This deletes them and
// cascade-removes their backfilled activities.
//
// Safe-to-delete: source=outreach_bot, no notes, no charter_fee.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { isNoiseEmail } from "@/lib/email-signature-parser";

export const runtime = "nodejs";
export const maxDuration = 120;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const apply = sp.get("apply") === "1";
  const sb = createServiceClient();

  const candidateIds: string[] = [];
  const sample: Array<{ id: string; email: string; reason?: string }> = [];
  let page = 0;
  const PAGE = 1000;
  while (true) {
    const { data: rows, error } = await sb
      .from("contacts")
      .select("id, email, first_name, last_name")
      .eq("source", "outreach_bot")
      .is("notes", null)
      .or("charter_fee.is.null,charter_fee.eq.0")
      .not("email", "is", null)
      .order("created_at", { ascending: true })
      .range(page * PAGE, (page + 1) * PAGE - 1);
    if (error || !rows || rows.length === 0) break;
    for (const r of rows) {
      const email = r.email as string;
      const verdict = isNoiseEmail({
        from: email,
        fromEmail: email.toLowerCase(),
        subject: "",
        headers: {},
      });
      if (verdict.noise) {
        candidateIds.push(r.id as string);
        if (sample.length < 25)
          sample.push({ id: r.id as string, email, reason: verdict.reason });
      }
    }
    if (rows.length < PAGE) break;
    page++;
  }

  if (!apply) {
    return NextResponse.json({
      ok: true,
      dry: true,
      noise_email_contacts: candidateIds.length,
      sample,
      hint: "Add &apply=1 to delete (cascades activities).",
    });
  }

  // Delete dependent rows first — email_classifications doesn't have
  // ON DELETE CASCADE configured, so contact deletes hit a FK error
  // unless we clear it manually.
  let deleted = 0;
  const CHUNK = 500;
  for (let i = 0; i < candidateIds.length; i += CHUNK) {
    const slice = candidateIds.slice(i, i + CHUNK);
    await sb.from("email_classifications").delete().in("contact_id", slice);
    const { error } = await sb.from("contacts").delete().in("id", slice);
    if (error) {
      return NextResponse.json(
        { error: error.message, deleted_before_error: deleted },
        { status: 500 },
      );
    }
    deleted += slice.length;
  }
  return NextResponse.json({ ok: true, deleted });
}

// /api/admin/inbox-cleanup-noise — undoes the over-eager auto-create
// from the d0292e5 backfill run.
//
// Targets: contacts created after a cutoff timestamp via the auto-
// create path (source=outreach_bot, contact_type=OUTREACH_LEAD) that
// have no human-curated state on them — no notes, no pipeline_stage
// other than the default 'New', no charter_fee. Their backfilled
// activities cascade-delete.
//
// Usage:
//   /api/admin/inbox-cleanup-noise?since=2026-04-27T11:50:00Z         (count)
//   /api/admin/inbox-cleanup-noise?since=2026-04-27T11:50:00Z&apply=1 (delete)

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";
export const maxDuration = 120;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const since = sp.get("since");
  const apply = sp.get("apply") === "1";
  if (!since) {
    return NextResponse.json(
      { error: "pass ?since=ISO8601 (e.g. 2026-04-27T11:50:00Z)" },
      { status: 400 },
    );
  }

  const sb = createServiceClient();

  // Count what would be deleted.
  const { count: totalAfter } = await sb
    .from("contacts")
    .select("id", { count: "exact", head: true })
    .gte("created_at", since);

  const { data: candidates } = await sb
    .from("contacts")
    .select("id, email, first_name, last_name, charter_fee, notes, created_at")
    .gte("created_at", since)
    .eq("source", "outreach_bot")
    .is("notes", null)
    .or("charter_fee.is.null,charter_fee.eq.0")
    .limit(10000);

  const ids = (candidates ?? []).map((c) => c.id as string);
  const sample = (candidates ?? []).slice(0, 10).map((c) => ({
    email: c.email,
    name: `${c.first_name ?? ""} ${c.last_name ?? ""}`.trim(),
    created_at: c.created_at,
  }));

  if (!apply) {
    return NextResponse.json({
      ok: true,
      dry: true,
      total_contacts_created_after_cutoff: totalAfter,
      cleanup_candidates: ids.length,
      sample,
      hint: "Add &apply=1 to actually delete (cascades activities).",
    });
  }

  // Delete in chunks to stay under any per-request row cap.
  let deleted = 0;
  const CHUNK = 500;
  for (let i = 0; i < ids.length; i += CHUNK) {
    const slice = ids.slice(i, i + CHUNK);
    const { error } = await sb.from("contacts").delete().in("id", slice);
    if (error) {
      return NextResponse.json(
        { error: error.message, deleted_before_error: deleted },
        { status: 500 },
      );
    }
    deleted += slice.length;
  }

  return NextResponse.json({ ok: true, deleted, sample });
}

// /api/admin/inbox-cleanup-warmup — purge warmup-only contacts.
//
// Deletes contacts whose ONLY email_* activities are cold-email warmup
// pings (subject contains a 'wbx XXX' / 'wbx-XXX' / 'wbx_XXX' token).
// Cascades activities.
//
// Implementation: one paginated bulk fetch of email activities,
// grouped per contact_id in memory, classified as
// warmup-only / mixed / clean. No per-contact queries.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";
export const maxDuration = 120;

const EMAIL_TYPES = [
  "email_sent",
  "email_inbound",
  "email_received",
  "email_reply_hot_or_warm",
  "email_reply_cold",
  "reply",
];

const WARMUP_RE = /\bwbx[\s_-]/i;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const apply = sp.get("apply") === "1";
  const sb = createServiceClient();

  // 1. Pull all email activities, paginated. We need both a "looks
  //    like warmup?" classification AND a "do they have any non-
  //    warmup email?" check per contact.
  const counts = new Map<string, { total: number; warmup: number }>();
  let actPage = 0;
  const ACT_PAGE = 1000;
  while (true) {
    const { data: rows, error } = await sb
      .from("activities")
      .select("contact_id, metadata")
      .in("type", EMAIL_TYPES)
      .not("contact_id", "is", null)
      .order("created_at", { ascending: false })
      .range(actPage * ACT_PAGE, (actPage + 1) * ACT_PAGE - 1);
    if (error || !rows || rows.length === 0) break;
    for (const r of rows) {
      const cid = r.contact_id as string;
      const subj = (r.metadata as { subject?: string } | null)?.subject ?? "";
      const isWarmup = WARMUP_RE.test(subj);
      const cur = counts.get(cid) ?? { total: 0, warmup: 0 };
      cur.total++;
      if (isWarmup) cur.warmup++;
      counts.set(cid, cur);
    }
    if (rows.length < ACT_PAGE) break;
    actPage++;
  }

  // 2. Eligible: total>0 AND warmup === total (every activity is warmup).
  const warmupOnly: string[] = [];
  for (const [cid, c] of counts.entries()) {
    if (c.total > 0 && c.warmup === c.total) warmupOnly.push(cid);
  }

  // 3. Restrict to safe-to-delete contacts (source=outreach_bot, no
  //    notes, no charter_fee). Walk paginated.
  const safeToDelete: string[] = [];
  if (warmupOnly.length > 0) {
    for (let i = 0; i < warmupOnly.length; i += 200) {
      const slice = warmupOnly.slice(i, i + 200);
      const { data: rows } = await sb
        .from("contacts")
        .select("id, email")
        .in("id", slice)
        .eq("source", "outreach_bot")
        .is("notes", null)
        .or("charter_fee.is.null,charter_fee.eq.0");
      for (const r of rows ?? []) safeToDelete.push(r.id as string);
    }
  }

  if (!apply) {
    return NextResponse.json({
      ok: true,
      dry: true,
      total_emailed_contacts: counts.size,
      warmup_only_classified: warmupOnly.length,
      safe_to_delete: safeToDelete.length,
      hint: "Add &apply=1 to delete (cascades activities).",
    });
  }

  let deleted = 0;
  const CHUNK = 500;
  for (let i = 0; i < safeToDelete.length; i += CHUNK) {
    const slice = safeToDelete.slice(i, i + CHUNK);
    await sb.from("email_classifications").delete().in("contact_id", slice);
    const { error } = await sb.from("contacts").delete().in("id", slice);
    if (error) {
      return NextResponse.json(
        { error: error.message, deleted_before_error: deleted },
        { status: 500 },
      );
    }
    deleted += slice.length;
  }
  return NextResponse.json({ ok: true, deleted });
}

// /api/admin/inbox-create-contact — manual contact create + Gmail import.
//
// For benchmark contacts the auto-create filter missed (e.g. Iordanis,
// only 1 message in CATEGORY_PROMOTIONS spread across multiple chunks).
// Creates the contact, then imports their last 90 days of Gmail
// activity, then refreshes their inbox state.
//
// Usage:
//   /api/admin/inbox-create-contact?email=arzoglou.iordanis@gmail.com&first=Iordanis&last=Arzoglou

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { gmailFetch } from "@/lib/google-api";
import { companyFromEmail } from "@/lib/email-signature-parser";
import { refreshContactInbox } from "@/lib/inbox-analyzer";

export const runtime = "nodejs";
export const maxDuration = 120;

type GmailHeader = { name: string; value: string };

function getHeader(headers: GmailHeader[] | undefined, n: string): string {
  if (!headers) return "";
  return (
    headers.find((h) => h.name.toLowerCase() === n.toLowerCase())?.value ?? ""
  );
}

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const email = sp.get("email")?.toLowerCase();
  const first = sp.get("first") ?? null;
  const last = sp.get("last") ?? null;
  if (!email) {
    return NextResponse.json(
      { error: "pass ?email=...&first=...&last=..." },
      { status: 400 },
    );
  }

  const sb = createServiceClient();

  // 1. Create or fetch the contact.
  let contactId: string;
  {
    const { data: existing } = await sb
      .from("contacts")
      .select("id")
      .ilike("email", email)
      .maybeSingle();
    if (existing) {
      contactId = existing.id as string;
    } else {
      const { data: stages } = await sb
        .from("pipeline_stages")
        .select("id, name, position")
        .order("position", { ascending: true });
      const newStage = stages?.find((s) => s.name === "New") ?? stages?.[0];
      const { data: inserted, error: insErr } = await sb
        .from("contacts")
        .insert({
          first_name: first,
          last_name: last,
          email,
          company: companyFromEmail(email) ?? null,
          source: "outreach_bot",
          pipeline_stage_id: (newStage?.id as string | undefined) ?? null,
          contact_type: "OUTREACH_LEAD",
          last_activity_at: new Date().toISOString(),
        })
        .select("id")
        .single();
      if (insErr || !inserted) {
        return NextResponse.json(
          { error: insErr?.message ?? "insert failed" },
          { status: 500 },
        );
      }
      contactId = inserted.id as string;
    }
  }

  // 2. Probe Gmail for their messages in last 90 days.
  const probe = await gmailFetch(
    `/messages?${new URLSearchParams({
      q: `(from:${email} OR to:${email}) newer_than:90d`,
      maxResults: "30",
    })}`,
  );
  if (!probe.ok) {
    return NextResponse.json({ ok: true, contact_id: contactId, gmail: "probe failed" });
  }
  const probeJson = (await probe.json()) as { messages?: { id: string }[] };
  const ids = probeJson.messages ?? [];

  // 3. For each, dedup against existing activities, then insert.
  let inserted = 0;
  let skipped = 0;
  for (const m of ids) {
    const { data: existing } = await sb
      .from("activities")
      .select("id")
      .eq("contact_id", contactId)
      .eq("metadata->>message_id", m.id)
      .maybeSingle();
    if (existing) {
      skipped++;
      continue;
    }
    const meta = await gmailFetch(
      `/messages/${m.id}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date`,
    );
    if (!meta.ok) continue;
    const mj = (await meta.json()) as {
      threadId: string;
      internalDate?: string;
      snippet?: string;
      labelIds?: string[];
      payload?: { headers?: GmailHeader[] };
    };
    const headers = mj.payload?.headers ?? [];
    const subject = getHeader(headers, "Subject");
    const isSent = mj.labelIds?.includes("SENT") ?? false;
    const createdAt = mj.internalDate
      ? new Date(parseInt(mj.internalDate, 10)).toISOString()
      : new Date().toISOString();
    await sb.from("activities").insert({
      contact_id: contactId,
      type: isSent ? "email_sent" : "email_inbound",
      description: `${isSent ? "Sent" : "Inbound"} — ${subject}`.slice(0, 500),
      metadata: {
        message_id: m.id,
        thread_id: mj.threadId,
        subject,
        snippet: (mj.snippet ?? "").slice(0, 300),
        direction: isSent ? "outbound" : "inbound",
        backfilled: true,
        manual_create: true,
      },
      created_at: createdAt,
    });
    inserted++;
  }

  // 4. Recompute inbox state for this contact.
  const state = await refreshContactInbox(sb, contactId);

  return NextResponse.json({
    ok: true,
    contact_id: contactId,
    gmail_messages_found: ids.length,
    activities_inserted: inserted,
    activities_skipped: skipped,
    inbox_state: state,
  });
}

// /api/admin/inbox-debug — diagnostic for "why isn't this contact
// surfacing in the cockpit?".
//
// Usage:
//   /api/admin/inbox-debug?email=sandra@thebraxtonagency.com
//   /api/admin/inbox-debug?name=braxton
//
// Returns the contact row, the full activity timeline, the freshly
// computed inbox state (so you can see if the analyzer would set
// anything different), and a Gmail search probe to spot threads that
// exist in mail but never made it into activities.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { gmailFetch } from "@/lib/google-api";
import { analyzeActivities } from "@/lib/inbox-analyzer";

export const runtime = "nodejs";
export const maxDuration = 60;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const email = sp.get("email");
  const name = sp.get("name");
  if (!email && !name) {
    return NextResponse.json(
      { error: "pass ?email=... or ?name=..." },
      { status: 400 },
    );
  }

  const sb = createServiceClient();

  let q = sb.from("contacts").select("*");
  if (email) q = q.ilike("email", email);
  else if (name) q = q.or(`first_name.ilike.%${name}%,last_name.ilike.%${name}%,company.ilike.%${name}%`);
  const { data: contacts } = await q.limit(20);

  const out: Array<Record<string, unknown>> = [];
  for (const c of contacts ?? []) {
    const { data: acts } = await sb
      .from("activities")
      .select("type, description, metadata, created_at")
      .eq("contact_id", c.id)
      .order("created_at", { ascending: false })
      .limit(50);

    const liveState = analyzeActivities(
      (acts ?? []).map((a) => ({
        type: a.type,
        created_at: a.created_at,
        description: a.description,
        metadata: a.metadata,
      })),
    );

    // Probe Gmail directly for threads with this email — and fetch
    // each message's From/To/Subject so we can see how the backfill
    // would (or wouldn't) match it.
    let gmailHits: Array<{
      id: string;
      from?: string;
      to?: string;
      subject?: string;
      labels?: string[];
    }> = [];
    if (c.email) {
      try {
        const probeRes = await gmailFetch(
          `/messages?${new URLSearchParams({
            q: `(from:${c.email} OR to:${c.email}) newer_than:180d`,
            maxResults: "5",
          })}`,
        );
        if (probeRes.ok) {
          const probe = (await probeRes.json()) as {
            messages?: { id: string }[];
          };
          for (const m of (probe.messages ?? []).slice(0, 5)) {
            try {
              const metaRes = await gmailFetch(
                `/messages/${m.id}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject`,
              );
              if (metaRes.ok) {
                const meta = (await metaRes.json()) as {
                  payload?: { headers?: { name: string; value: string }[] };
                  labelIds?: string[];
                };
                const h = meta.payload?.headers ?? [];
                const get = (n: string) =>
                  h.find((x) => x.name.toLowerCase() === n.toLowerCase())
                    ?.value ?? "";
                gmailHits.push({
                  id: m.id,
                  from: get("From"),
                  to: get("To"),
                  subject: get("Subject"),
                  labels: meta.labelIds,
                });
              } else {
                gmailHits.push({ id: m.id });
              }
            } catch {
              gmailHits.push({ id: m.id });
            }
          }
        }
      } catch {}
    }

    out.push({
      contact: {
        id: c.id,
        name: `${c.first_name ?? ""} ${c.last_name ?? ""}`.trim(),
        email: c.email,
        company: c.company,
        inbox_inferred_stage: c.inbox_inferred_stage,
        inbox_gap_days: c.inbox_gap_days,
        inbox_message_count: c.inbox_message_count,
        inbox_last_direction: c.inbox_last_direction,
        inbox_analyzed_at: c.inbox_analyzed_at,
      },
      activities_in_db: (acts ?? []).map((a) => ({
        type: a.type,
        subj: (a.metadata as { subject?: string } | null)?.subject ?? null,
        msg_id:
          (a.metadata as { message_id?: string } | null)?.message_id ?? null,
        backfilled:
          (a.metadata as { backfilled?: boolean } | null)?.backfilled ?? false,
        at: a.created_at,
      })),
      live_state_if_recomputed_now: liveState,
      gmail_search_180d_message_ids: gmailHits,
      gmail_msg_count_in_window: gmailHits.length,
      verdict:
        liveState.message_count === 0 && gmailHits.length > 0
          ? "GMAIL HAS THREADS BUT ACTIVITIES TABLE IS EMPTY — backfill missed this contact"
          : liveState.message_count === 0
            ? "no email activity in DB or in Gmail (>180d, or different address)"
            : liveState.message_count !==
                (c.inbox_message_count ?? 0)
              ? "STALE: live recompute differs from cached inbox_*"
              : "in sync",
    });
  }

  return NextResponse.json({
    matched: out.length,
    results: out,
  });
}

// /api/admin/inbox-tag-debug — return the raw AI response for one
// contact, plus the parsed result. Used to diagnose why every contact
// was getting tagged as cold_lead.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { aiChat } from "@/lib/ai";

export const runtime = "nodejs";

const SYSTEM = `You categorize George Yachts contacts. George is a yacht charter broker in Greece.

CRITICAL OUTPUT RULES:
- Output ONLY the raw JSON object. NO markdown fences. NO \`\`\`json. NO prose before or after.
- Start your response with the open brace { and end with the close brace }. Nothing else.
- Schema: {"tags":[{"tag":"<TAG>","confidence":<0..1>}, ...]}
- Allowed TAG values: travel_advisor, charter_client, b2b_partner, press, vendor, cold_lead

REMEMBER: raw JSON only. No fences.`;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const email = sp.get("email");
  if (!email) {
    return NextResponse.json({ error: "pass ?email=..." }, { status: 400 });
  }
  const sb = createServiceClient();
  const { data: c } = await sb
    .from("contacts")
    .select("email, first_name, last_name, company, notes")
    .ilike("email", email)
    .single();
  if (!c) return NextResponse.json({ error: "not found" }, { status: 404 });

  const { data: acts } = await sb
    .from("activities")
    .select("metadata")
    .eq("contact_id", (await sb.from("contacts").select("id").ilike("email", email).single()).data?.id ?? "")
    .in("type", ["email_inbound", "email_received", "email_sent", "reply"])
    .order("created_at", { ascending: false })
    .limit(10);
  const subjects = (acts ?? [])
    .map((a) => (a.metadata as { subject?: string } | null)?.subject ?? null)
    .filter((s): s is string => !!s);

  const userMsg = JSON.stringify({
    email: c.email,
    name: [c.first_name, c.last_name].filter(Boolean).join(" "),
    company: c.company,
    notes: c.notes,
    domain_kind: c.email?.includes("@gmail.") ? "personal" : "business",
    recent_subjects: subjects.slice(0, 8),
  });

  const raw = await aiChat(SYSTEM, userMsg, {
    maxTokens: 2000,
    temperature: 0.2,
  });

  const match = raw.match(/\{[\s\S]*\}/);
  let parsed: unknown = null;
  let parseError: string | null = null;
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e) {
      parseError = e instanceof Error ? e.message : String(e);
    }
  } else {
    parseError = "no JSON object found in response";
  }

  return NextResponse.json({
    contact: c,
    activities_subjects: subjects,
    user_message_to_ai: userMsg,
    raw_ai_response: raw,
    json_match: match?.[0] ?? null,
    parsed,
    parse_error: parseError,
  });
}

// /api/admin/inbox-tag — runs the Pillar 2 AI tagger over contacts.
//
// Time-budgeted with resumable offset cursor (same pattern as
// inbox-refresh). Skips contacts where tags_overridden = true.
// Default: only contacts that have at least one email_* activity AND
// have not been tagged yet (or were tagged > 30 days ago).
//
// Usage:
//   /api/admin/inbox-tag                          (first chunk)
//   /api/admin/inbox-tag?offset=NNN               (resume)
//   /api/admin/inbox-tag?force=1                  (re-tag everyone)

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { tagOneContact } from "@/lib/pillar2-tagger";

export const runtime = "nodejs";
export const maxDuration = 300;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const startOffset = parseInt(sp.get("offset") ?? "0", 10);
  const force = sp.get("force") === "1";
  const budgetMs = 250_000;
  const startedAt = Date.now();

  const sb = createServiceClient();

  // Eligibility: contacts with email activity. Same pagination
  // pattern as inbox-analyzer; the 1000-row Supabase cap bites here
  // too if we don't .range() through it.
  const idSet = new Set<string>();
  let actPage = 0;
  const ACT_PAGE = 1000;
  while (true) {
    const { data: rows } = await sb
      .from("activities")
      .select("contact_id")
      .in("type", [
        "email_sent",
        "email_inbound",
        "email_received",
        "email_reply_hot_or_warm",
        "email_reply_cold",
        "reply",
      ])
      .not("contact_id", "is", null)
      .order("created_at", { ascending: false })
      .range(actPage * ACT_PAGE, (actPage + 1) * ACT_PAGE - 1);
    if (!rows || rows.length === 0) break;
    for (const r of rows) {
      const id = r.contact_id as string | null;
      if (id) idSet.add(id);
    }
    if (rows.length < ACT_PAGE) break;
    actPage++;
  }
  const all = Array.from(idSet).sort();

  let cursor = startOffset;
  let processed = 0;
  let skipped = 0;
  const tagCounts: Record<string, number> = {};

  while (cursor < all.length && Date.now() - startedAt < budgetMs) {
    const id = all[cursor];
    cursor++;

    if (!force) {
      // Skip rows we tagged in the last 30 days.
      const { data: c } = await sb
        .from("contacts")
        .select("tags_overridden, tags_analyzed_at")
        .eq("id", id)
        .single();
      if (c?.tags_overridden) {
        skipped++;
        continue;
      }
      if (c?.tags_analyzed_at) {
        const ageDays =
          (Date.now() - new Date(c.tags_analyzed_at).getTime()) / 86_400_000;
        if (ageDays < 30) {
          skipped++;
          continue;
        }
      }
    }

    const { tags } = await tagOneContact(sb, id);
    if (tags) {
      processed++;
      for (const t of tags) {
        tagCounts[t.tag] = (tagCounts[t.tag] ?? 0) + 1;
      }
    } else {
      skipped++;
    }
  }

  return NextResponse.json({
    ok: true,
    eligible: all.length,
    processed,
    skipped,
    tag_counts: tagCounts,
    next_offset: cursor < all.length ? cursor : null,
    hint:
      cursor < all.length
        ? `Resume with ?offset=${cursor}`
        : "All eligible contacts tagged.",
  });
}

