      return NextResponse.json({ ok: true, entry });
    }
    if (action === "edit") {
      const entry = await editQueueEntry({
        stream,
        id: body.id,
        text: body.text,
        notes: body.notes,
      });
      return NextResponse.json({ ok: true, entry });
