async function tableCount(
  sb: ReturnType<typeof createServiceClient>,
  table: string,
): Promise<{ ok: boolean; count?: number; error?: string }> {
  const { count, error } = await sb
    .from(table)
    .select("id", { count: "exact", head: true });
