    detail: campaigns.error,
  });
  const sends = await tableCount(sb, "newsletter_sends");
  checks.push({
    pillar: "4 Newsletter",
    name: "newsletter_sends table",
    ok: sends.ok,
    count: sends.count,
  });
  const segments = await tableCount(sb, "audience_segments");
  checks.push({
    pillar: "4 Newsletter",
    name: "audience_segments table (≥2 seeded)",
    ok: segments.ok && (segments.count ?? 0) >= 2,
    count: segments.count,
  });

  // Pillar 5 — Health Score
  const healthHistory = await tableCount(sb, "health_score_history");
  checks.push({
    pillar: "5 Health",
    name: "health_score_history table",
    ok: healthHistory.ok,
    count: healthHistory.count,
    detail: healthHistory.error,
  });

  // Pillar 4-old / Sprint 2.3 — Commitments
  const commitments = await tableCount(sb, "commitments");
  checks.push({
    pillar: "Commitments",
    name: "commitments table (Sprint 2.3)",
    ok: commitments.ok,
    count: commitments.count,
    detail: commitments.error,
  });

  // v3 Pillar 7 — Charter Lifecycle
  const milestones = await tableCount(sb, "charter_lifecycle_milestones");
  checks.push({
    pillar: "v3/7 Charter Lifecycle",
    name: "charter_lifecycle_milestones table",
    ok: milestones.ok,
    count: milestones.count,
    detail: milestones.error,
  });

  // v3 Pillar 8 — Document-Driven Setup
  const deals = await tableCount(sb, "deals");
  checks.push({
    pillar: "v3/8 Documents",
    name: "deals table (v3 normalized)",
    ok: deals.ok,
    count: deals.count,
    detail: deals.error,
  });
  const docs = await tableCount(sb, "charter_documents");
  checks.push({
    pillar: "v3/8 Documents",
    name: "charter_documents table",
    ok: docs.ok,
    count: docs.count,
    detail: docs.error,
  });

  // v3 Pillar 9 — Multi-Guest Network
  const guests = await tableCount(sb, "charter_guests");
  checks.push({
    pillar: "v3/9 Network",
    name: "charter_guests table",
    ok: guests.ok,
    count: guests.count,
    detail: guests.error,
  });
  const networkSourceColumn = await columnExists(
    sb,
    "contacts",
    "network_source",
  );
  checks.push({
    pillar: "v3/9 Network",
    name: "contacts.network_source column",
    ok: networkSourceColumn,
  });
  const subscribedColumn = await columnExists(
    sb,
    "contacts",
    "subscribed_to_newsletter",
  );
  checks.push({
    pillar: "v3/9 + 4",
    name: "contacts.subscribed_to_newsletter column",
    ok: subscribedColumn,
  });

  const passed = checks.filter((c) => c.ok).length;
  const failed = checks.filter((c) => !c.ok).length;

  return NextResponse.json({
    ok: failed === 0,
    passed,
    failed,
    total: checks.length,
    checks,
    next_steps:
      failed > 0
        ? "Apply the missing migration(s) in Supabase Studio. v3 schema lives in src/lib/v3-charter-engine-migration.sql and src/lib/v3-newsletter-migration.sql."
        : "Schema is clean. Pillars are wired end-to-end.",
  });
}

// /api/admin/religion-infer — populates contacts.inferred_religion
// using the heuristic in pillar3-religion-inferrer.ts.
//
// Skips contacts where religion_overridden=true (George corrected
// it manually). Cheap (no AI calls). Idempotent — re-run anytime
// to pick up newly-added country/name data.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { inferReligion } from "@/lib/pillar3-religion-inferrer";

export const runtime = "nodejs";
export const maxDuration = 120;

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const dry = sp.get("dry") === "1";
  const sb = createServiceClient();

  // Walk all contacts, group required updates by target religion,
  // then issue ONE bulk update per religion group via .in('id', […]).
  // Avoids the 1800 round-trips that hit Vercel's 300s cap.
  const counts: Record<string, number> = {};
  let skipped = 0;
  const updatesByReligion = new Map<string, string[]>();

  const PAGE = 1000;
  let p = 0;
  while (true) {
    const { data: rows, error } = await sb
      .from("contacts")
      .select(
        "id, country, first_name, last_name, email, inferred_religion, religion_overridden",
      )
      .order("created_at", { ascending: true })
      .range(p * PAGE, (p + 1) * PAGE - 1);
    if (error || !rows || rows.length === 0) break;

    for (const c of rows) {
      if (c.religion_overridden) {
        skipped++;
        continue;
      }
      const rel = inferReligion({
        country: c.country as string | null,
        first_name: c.first_name as string | null,
        last_name: c.last_name as string | null,
        email: c.email as string | null,
      });
      counts[rel] = (counts[rel] ?? 0) + 1;
      if (rel !== c.inferred_religion) {
        const list = updatesByReligion.get(rel) ?? [];
        list.push(c.id as string);
        updatesByReligion.set(rel, list);
      }
    }
    if (rows.length < PAGE) break;
    p++;
  }

  let updated = 0;
  if (!dry) {
    for (const [rel, ids] of updatesByReligion.entries()) {
      // Chunk to keep PostgREST URL length reasonable.
      const CHUNK = 200;
      for (let i = 0; i < ids.length; i += CHUNK) {
        const slice = ids.slice(i, i + CHUNK);
        await sb
          .from("contacts")
          .update({ inferred_religion: rel })
          .in("id", slice);
        updated += slice.length;
      }
    }
  } else {
    for (const ids of updatesByReligion.values()) updated += ids.length;
  }

  return NextResponse.json({
    ok: true,
    dry,
    updated,
    skipped_overridden: skipped,
    by_religion: counts,
  });
}

// @ts-nocheck
import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

// GET /api/admin/scraper-audit
//
// Retroactive audit per George 2026-04-20. Re-applies the Phase F
// scraper-spam heuristic against the last 14 days of auto-replies so
// we can quantify how many slipped through BEFORE the webhook filter
// shipped. Read-only — no cleanup.
//
// Returns JSON with:
//   - comment_replies: total auto-reply rows in window
//   - comment_replies_scraper_match: how many of those retro-match
//     the new heuristic (would have been skipped under Phase F)
//   - dm_replies_total / dm_replies_scraper_match: same for DMs
//   - followers_unknown: note (we don't store follower counts — the
//     <1000-follower split needs a separate Graph API backfill).

const WINDOW_MS = 14 * 24 * 60 * 60 * 1000;

// Duplicate of the webhook heuristic. Intentionally inline so this
// endpoint runs without pulling extra deps.
function isLikelyScraperSpam(
  commentText: string,
  commenterUsername: string | null,
): { scraper: boolean; reason?: string } {
  const text = (commentText ?? "").trim().toLowerCase();
  const user = (commenterUsername ?? "").toLowerCase();
  if (!text) return { scraper: false };

  const sendMePatterns = [
    /\bsend\s+(?:me|to\s+me)\s+(?:this|the\s+)?post\b/,
    /\bsend\s+it\s+to\s+me\b/,
    /\bdm\s+me\s+this\b/,
    /\bshare\s+(?:it|this)\s+to\s+me\b/,
    /\bcan\s+you\s+send\s+(?:me|this)\b/,
  ];
  for (const p of sendMePatterns) {
    if (p.test(text)) return { scraper: true, reason: "send-me-this" };
  }

  const oneWordProbes = ["price?", "info?", "link?", "cost?"];
  if (oneWordProbes.includes(text)) {
    return { scraper: true, reason: "one-word-probe" };
  }
  if (/^link\s+in\s+bio\s*\??$/i.test(text)) {
    return { scraper: true, reason: "redundant-link-in-bio" };
  }

  const botUserPatterns = [
    /_buzz$/,
    /_daily$/,
    /^travel_\w+_\d+$/,
    /^luxury_\w+_\w+$/,
    /^\w+_vibes(_\w+)?$/,
    /^\w+city_\w+$/,
    /\d{4,}$/,
  ];
  const botUserMatch = botUserPatterns.some((p) => p.test(user));
  if (botUserMatch) {
    const hypeOnly =
      text.length < 50 &&
      /^[\s❤️🤍🖤💕❤️‍🔥💯🔥✨🙌👏👌😍🤩💃😘😁😂❗❣️]+$|\b(?:beautiful|amazing|stunning|incredible|wow|gorgeous|lovely|perfect|nice)[\s.!❤️🔥✨👏]*$/i.test(
        text,
      );
    if (hypeOnly) return { scraper: true, reason: "botlike-username-hype" };
  }

  return { scraper: false };
}

export async function GET() {
  const sb = createServiceClient();
  const since = new Date(Date.now() - WINDOW_MS).toISOString();

  const [{ data: comments, error: cErr }, { data: dms, error: dErr }] = await Promise.all([
    sb
      .from("ig_comment_replies")
      .select("comment_id, commenter_username, comment_text, status, created_at")
      .gte("created_at", since)
      .limit(5000),
    sb
      .from("ig_dm_replies")
      .select("sender_id, message_text, intent, sent_at")
      .gte("sent_at", since)
      .limit(5000),
  ]);

  const commentRows = comments ?? [];
  const dmRows = dms ?? [];

  // Comments breakdown
  const commentTotal = commentRows.length;
  const commentAutoReplied = commentRows.filter(
    (r) => r.status !== "scraper_spam" && r.status !== "skipped",
  ).length; // rows that either already got a reply or were claimed but not yet status-flipped
  const commentScraperHits = commentRows.filter((r) => {
    const { scraper } = isLikelyScraperSpam(r.comment_text ?? "", r.commenter_username);
    return scraper;
  });
  const commentScraperReasons: Record<string, number> = {};
  for (const r of commentRows) {
    const res = isLikelyScraperSpam(r.comment_text ?? "", r.commenter_username);
    if (res.scraper) {
      const reason = res.reason ?? "unknown";
      commentScraperReasons[reason] = (commentScraperReasons[reason] ?? 0) + 1;
    }
  }

  // DMs: we don't store username on DM rows (only sender_id), so the
  // botlike-username heuristic is not applicable. The send-me-this
  // pattern still works against message_text.
  const dmTotal = dmRows.length;
  const dmScraperHits = dmRows.filter((r) => {
    const { scraper } = isLikelyScraperSpam(r.message_text ?? "", null);
    return scraper;
  });
  const dmScraperReasons: Record<string, number> = {};
  for (const r of dmRows) {
    const res = isLikelyScraperSpam(r.message_text ?? "", null);
    if (res.scraper) {
      const reason = res.reason ?? "unknown";
      dmScraperReasons[reason] = (dmScraperReasons[reason] ?? 0) + 1;
    }
  }

  // Sample 10 scraper hits so George can eyeball them.
  const commentSamples = commentScraperHits.slice(0, 10).map((r) => ({
    user: r.commenter_username,
    text: (r.comment_text ?? "").slice(0, 100),
    status: r.status,
    at: r.created_at,
  }));

  return NextResponse.json({
    window_days: 14,
    since,
    errors: { comments: cErr?.message ?? null, dms: dErr?.message ?? null },
    comments: {
      total: commentTotal,
      auto_replied_or_claimed: commentAutoReplied,
      retro_scraper_hits: commentScraperHits.length,
      retro_scraper_reasons: commentScraperReasons,
      samples: commentSamples,
    },
    dms: {
      total: dmTotal,
      retro_scraper_hits: dmScraperHits.length,
      retro_scraper_reasons: dmScraperReasons,
      followers_filter_note:
        "Follower count is not stored in ig_dm_replies. <1000-follower split needs Graph API backfill — separate task.",
    },
  });
}

// /api/admin/sentiment-backfill — populate activities.sentiment_*
// for all email_inbound activities that don't have it yet.
//
// Time-budgeted with always-from-row-0 pattern (the filter ensures
// updated rows leave the view).

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { classifySentiment } from "@/lib/sentiment-classifier";

export const runtime = "nodejs";
export const maxDuration = 300;

const INBOUND_TYPES = [
  "email_inbound",
  "email_received",
  "email_reply_hot_or_warm",
  "email_reply_cold",
  "reply",
];

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const limit = Math.min(500, Math.max(10, parseInt(sp.get("limit") ?? "200", 10)));
  const sb = createServiceClient();
  const startedAt = Date.now();
  const budgetMs = 250_000;
  let processed = 0;
  const counts: Record<string, number> = {};

  while (Date.now() - startedAt < budgetMs && processed < limit) {
    const { data: rows } = await sb
      .from("activities")
      .select("id, metadata")
      .in("type", INBOUND_TYPES)
      .is("sentiment_warmth", null)
      .order("created_at", { ascending: false })
      .range(0, 49);
    if (!rows || rows.length === 0) break;
    for (const r of rows) {
      if (Date.now() - startedAt >= budgetMs || processed >= limit) break;
      const snippet =
        (r.metadata as { snippet?: string } | null)?.snippet ?? "";
      const result = await classifySentiment(snippet);
      if (result) {
        await sb
          .from("activities")
          .update({
            sentiment_warmth: result.warmth,
            sentiment_engagement: result.engagement,
            sentiment_intent: result.intent,
          })
          .eq("id", r.id);
        counts[result.warmth] = (counts[result.warmth] ?? 0) + 1;
      } else {
        // Mark as 'neutral' to skip on next pass if AI failed.
        await sb
          .from("activities")
          .update({
            sentiment_warmth: "neutral",
            sentiment_engagement: "substantive",
            sentiment_intent: "static",
          })
          .eq("id", r.id);
      }
      processed++;
    }
    if (rows.length < 50) break;
  }

  return NextResponse.json({ ok: true, processed, warmth_counts: counts });
}

// One-shot: shift every upcoming scheduled ig_posts row from any UTC
// hour to the canonical PUBLISH_HOUR_UTC (15 → 18:00 Athens summer).
//
// Run after a hour-policy change so the queue stays consistent. Updates
// BOTH schedule_time and scheduled_for so the trigger that mirrors them
// is happy. Idempotent — rows already at the target hour are no-ops.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";
export const maxDuration = 60;

export async function GET(req: NextRequest) {
  const sb = createServiceClient();
  const targetHour = parseInt(
    req.nextUrl.searchParams.get("hour") ?? "15",
    10,
  );
  if (targetHour < 0 || targetHour > 23) {
    return NextResponse.json({ error: "hour must be 0..23" }, { status: 400 });
  }

  const now = new Date().toISOString();
  const { data: rows } = await sb
    .from("ig_posts")
    .select("id, schedule_time, scheduled_for, status")
    .gte("schedule_time", now)
    .in("status", ["scheduled", "pending_approval"])
    .limit(500);

  type Row = {
    id: string;
    schedule_time: string;
    scheduled_for: string | null;
    status: string;
  };
  let shifted = 0;
  const results: { id: string; from: string; to: string }[] = [];

  for (const r of (rows ?? []) as Row[]) {
    const dt = new Date(r.schedule_time);
    if (dt.getUTCHours() === targetHour) continue; // already correct
    const newDt = new Date(dt);
    newDt.setUTCHours(targetHour, 0, 0, 0);
    const newIso = newDt.toISOString();
    const { error } = await sb
      .from("ig_posts")
      .update({ schedule_time: newIso, scheduled_for: newIso })
      .eq("id", r.id);
    if (!error) {
      shifted += 1;
      results.push({ id: r.id, from: r.schedule_time, to: newIso });
    }
  }

  return NextResponse.json({
    ok: true,
    target_hour_utc: targetHour,
    examined: (rows ?? []).length,
    shifted,
    sample: results.slice(0, 10),
  });
}

// One-shot retroactive cleanup for fake "HOT/WARM lead" contacts that
// were created from Instantly.ai warm-up emails BEFORE the
// f7a14d7 detector landed. Pairs with archive-warmup-backfill (which
// only re-scanned NEUTRAL-labelled mail); this scans HOT/WARM/COLD too
// and removes the matching contact rows in Supabase when their only
// touchpoint is the warmup email.
//
// USAGE
//   GET  /api/admin/warmup-cleanup?secret=<CRON_SECRET>            (dry-run)
//   POST /api/admin/warmup-cleanup  body: { secret, confirm: true } (executes)
//
// SAFETY
// - Dry-run by default — returns the list of suspected fake contacts
//   so George can eyeball before letting it delete anything.
// - Only deletes contacts whose ONLY activity is the auto-created
//   "Inbound email" row from the warmup message itself. Real
//   contacts with calls, replies, deal records, etc. are kept and
//   the warmup-archive logic still runs on the email.
// - Logs every deletion to settings.warmup_cleanup_log_<timestamp>
//   so we have an audit trail if anything looks off.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { gmailFetch } from "@/lib/google-api";
import { detectWarmup } from "@/lib/email-warmup-detector";

export const runtime = "nodejs";
export const maxDuration = 300;

type GmailHeader = { name: string; value: string };

function getHeader(headers: GmailHeader[] | undefined, name: string): string {
  if (!headers) return "";
  return (
    headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ?? ""
  );
}

function extractBody(payload: any): string {
  if (!payload) return "";
  const walk = (part: any): string => {
    if (!part) return "";
    const mt = (part.mimeType || "").toLowerCase();
    if (part.body?.data && (mt === "text/plain" || mt === "text/html")) {
      const raw = Buffer.from(part.body.data, "base64url").toString("utf8");
      if (mt === "text/plain") return raw;
      return raw.replace(/<style[\s\S]*?<\/style>/gi, "").replace(/<[^>]+>/g, " ");
    }
    if (Array.isArray(part.parts)) {
      const plain = part.parts.find(
        (p: any) => (p.mimeType || "").toLowerCase() === "text/plain",
      );
      if (plain) return walk(plain);
      return part.parts.map(walk).join("\n");
    }
    return "";
  };
  return walk(payload).slice(0, 12000);
}

function emailFromHeader(from: string): string {
  const m = from.match(/<([^>]+)>/);
  if (m) return m[1].trim().toLowerCase();
  return from.trim().toLowerCase();
}

interface SuspectedFake {
  message_id: string;
  email: string;
  subject: string;
  reason: string;
  service: string;
  contact_id: string | null;
  contact_name: string | null;
  contact_activity_count: number;
  delete_safe: boolean; // true if we'd delete in --confirm mode
}

async function findSuspects(): Promise<SuspectedFake[]> {
  const sb = createServiceClient();
  // Scan all the lead-bucket labels — we already have warmup-detected
  // mail correctly archived, so missing those is fine. The interesting
  // set is mail that was wrongly classified as a real lead.
  const query =
    "label:gy-classified/hot OR label:gy-classified/warm OR label:gy-classified/cold OR label:gy-classified/neutral newer_than:30d";
  const listRes = await gmailFetch(
    `/messages?${new URLSearchParams({ q: query, maxResults: "200" })}`,
  );
  if (!listRes.ok) return [];
  const listJson = (await listRes.json()) as { messages?: { id: string }[] };
  const messageIds = listJson.messages ?? [];

  const suspects: SuspectedFake[] = [];

  for (const { id } of messageIds) {
    try {
      const res = await gmailFetch(`/messages/${id}?format=full`);
      if (!res.ok) continue;
      const msg = (await res.json()) as any;
      const headers = msg.payload?.headers ?? [];
      const from = getHeader(headers, "From");
      const subject = getHeader(headers, "Subject");
      const body = extractBody(msg.payload) || msg.snippet || "";
      const headersMap: Record<string, string> = {};
      for (const h of headers) headersMap[h.name.toLowerCase()] = h.value;

      const verdict = detectWarmup({ from, subject, body, headers: headersMap });
      if (!verdict.isWarmup) continue;

      // It's a warmup. Look up the contact + count activities.
      const senderEmail = emailFromHeader(from);
      let contactId: string | null = null;
      let contactName: string | null = null;
      let activityCount = 0;
      if (senderEmail) {
        const { data: contact } = await sb
          .from("contacts")
          .select("id, first_name, last_name")
          .eq("email", senderEmail)
          .maybeSingle();
        if (contact?.id) {
          contactId = contact.id;
          contactName = [contact.first_name, contact.last_name].filter(Boolean).join(" ") || null;
          const { count } = await sb
            .from("activities")
            .select("id", { count: "exact", head: true })
            .eq("contact_id", contactId);
          activityCount = count ?? 0;
        }
      }

      suspects.push({
        message_id: id,
        email: senderEmail,
        subject: subject.slice(0, 100),
        reason: verdict.reason ?? "unknown",
        service: verdict.service ?? "unknown",
        contact_id: contactId,
        contact_name: contactName,
        contact_activity_count: activityCount,
        delete_safe: contactId !== null && activityCount <= 1,
      });
    } catch (e: any) {
      console.error("[warmup-cleanup] message error", id, e?.message);
    }
  }

  return suspects;
}

async function executeCleanup(suspects: SuspectedFake[]) {
  const sb = createServiceClient();
  const deletedContacts: string[] = [];
  const skippedContacts: { contact_id: string; reason: string }[] = [];

  for (const s of suspects) {
    if (!s.delete_safe || !s.contact_id) {
      if (s.contact_id) {
        skippedContacts.push({
          contact_id: s.contact_id,
          reason: `${s.contact_activity_count} activities — keeping`,
        });
      }
      continue;
    }
    // Delete activities first (FK), then contact.
    await sb.from("activities").delete().eq("contact_id", s.contact_id);
    const { error } = await sb.from("contacts").delete().eq("id", s.contact_id);
    if (error) {
      skippedContacts.push({ contact_id: s.contact_id, reason: error.message });
      continue;
    }
    deletedContacts.push(s.contact_id);
  }

  // Audit log
  await sb.from("settings").upsert({
    key: `warmup_cleanup_log_${Date.now()}`,
    value: JSON.stringify({
      ran_at: new Date().toISOString(),
      total_suspects: suspects.length,
      deleted: deletedContacts,
      skipped: skippedContacts,
    }),
  });

  return { deleted: deletedContacts.length, skipped: skippedContacts };
}

function authOk(secret: string | null) {
  return secret && secret === process.env.CRON_SECRET;
}

export async function GET(req: NextRequest) {
  const secret = req.nextUrl.searchParams.get("secret");
  if (!authOk(secret)) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 });
  }
  const suspects = await findSuspects();
  return NextResponse.json({
    mode: "dry-run",
    total_suspects: suspects.length,
    safe_to_delete: suspects.filter((s) => s.delete_safe).length,
    keep_for_review: suspects.filter((s) => !s.delete_safe).length,
    suspects,
    hint: "POST same endpoint with { secret, confirm: true } to execute",
  });
}

export async function POST(req: NextRequest) {
  let body: any = {};
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: "bad json" }, { status: 400 });
