// OAuth callback — exchanges the code for an access token, fetches
// George's member URN + organizations, and caches everything in
// Supabase settings.linkedin_oauth for the publish crons to use.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { sendTelegram } from "@/lib/telegram";

export const runtime = "nodejs";

// George Yachts Company Page ID. Configurable via env so we don't have
// to redeploy if LinkedIn ever issues a new org URN. Falls back to the
// known ID (extracted from the admin URL) for backwards compatibility
// with existing deployments where the env wasn't set.
const LINKEDIN_ORG_ID_HINT = process.env.LINKEDIN_ORG_ID || "110876447";

export async function GET(request: Request) {
  const url = new URL(request.url);
  const code = url.searchParams.get("code");
  const error = url.searchParams.get("error");

  if (error) {
    return NextResponse.json({ error, description: url.searchParams.get("error_description") });
  }
  if (!code) {
    return NextResponse.json({ error: "missing code parameter" }, { status: 400 });
  }

  const clientId = process.env.LINKEDIN_CLIENT_ID!;
  const clientSecret = process.env.LINKEDIN_CLIENT_SECRET!;
  const redirectUri = process.env.LINKEDIN_REDIRECT_URI!;

  // 1. Exchange code → access_token
  const tokenRes = await fetch("https://www.linkedin.com/oauth/v2/accessToken", {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body: new URLSearchParams({
      grant_type: "authorization_code",
      code,
      redirect_uri: redirectUri,
      client_id: clientId,
      client_secret: clientSecret,
    }),
  });
  const tokenJson = await tokenRes.json();
  if (!tokenRes.ok) {
    return NextResponse.json({ error: "token exchange failed", details: tokenJson });
  }
  const accessToken = tokenJson.access_token as string;
  const expiresIn = tokenJson.expires_in as number; // seconds
  const refreshToken = tokenJson.refresh_token as string | undefined;

  // 2. Fetch member identity (sub = LinkedIn member id)
  const meRes = await fetch("https://api.linkedin.com/v2/userinfo", {
    headers: { Authorization: `Bearer ${accessToken}` },
  });
  const me = await meRes.json();
  const memberUrn = `urn:li:person:${me.sub}`;

  // 3. Organization lookup skipped until Community Management API is
  //    approved (the r_organization_admin scope isn't on this token
  //    yet). We hardcode the known org id hint from the admin URL —
  //    it's only used by the future Company Page publish crons, which
  //    are also gated on that approval. Post-approval, re-run OAuth and
  //    this block flips to the live /organizationalEntityAcls query.
  const organizationUrn: string | undefined = `urn:li:organization:${LINKEDIN_ORG_ID_HINT}`;

  // 4. Persist
  const sb = createServiceClient();
  const expiresAt = new Date(Date.now() + expiresIn * 1000).toISOString();
  await sb.from("settings").upsert({
    key: "linkedin_oauth",
    value: JSON.stringify({
      access_token: accessToken,
      expires_at: expiresAt,
      refresh_token: refreshToken,
      member_urn: memberUrn,
      organization_urn: organizationUrn,
      connected_at: new Date().toISOString(),
    }),
  });

  await sendTelegram(
    [
      `🔗 <b>LinkedIn connected</b>`,
      `Member: ${me.name ?? me.given_name ?? "unknown"}`,
      `Member URN: <code>${memberUrn}</code>`,
      `Organization: <code>${organizationUrn ?? "(not found)"}</code>`,
      `Token expires: ${expiresAt}`,
    ].join("\n"),
  ).catch(() => {});

  return NextResponse.json({
    ok: true,
    member_urn: memberUrn,
    organization_urn: organizationUrn,
    expires_at: expiresAt,
    next_steps: [
      "Hit /api/cron/linkedin-blog-digest manually to test the Tue/Thu draft flow.",
      "Crons are Tue+Thu 08:45 + 11:00 Athens and Fri 10:00 Athens.",
    ],
  });
}

// OAuth login entry — redirects George to LinkedIn consent screen.
//
// One-time setup: George visits this URL once, grants the app the
// required scopes (openid, profile, email, w_member_social,
// r_organization_admin, w_organization_social), and the callback
// route stores the resulting access token in Supabase settings.
//
// Scopes requested:
//   - openid + profile + email       — member identity (George's person urn)
//   - w_member_social                — post to George's personal profile
//   - w_organization_social          — post to George Yachts Company Page
//   - r_organization_admin           — list admin'd organizations to find the org urn
//
// LinkedIn app product requirement:
//   - "Sign In with LinkedIn using OpenID Connect" — free, instant
//   - "Share on LinkedIn"                          — free, instant
//   - "Community Management API"                   — free, instant for
//     admins of their own pages

import { NextResponse } from "next/server";

export const runtime = "nodejs";

export async function GET(request: Request) {
  const clientId = process.env.LINKEDIN_CLIENT_ID;
  const redirectUri = process.env.LINKEDIN_REDIRECT_URI;
  if (!clientId || !redirectUri) {
    return NextResponse.json(
      {
        error:
          "Missing LINKEDIN_CLIENT_ID or LINKEDIN_REDIRECT_URI env vars. Configure the LinkedIn app first.",
      },
      { status: 500 },
    );
  }

  // Community Management API (w_organization_social + r_organization_admin)
  // is still pending LinkedIn approval. Until it's granted, request only
  // the scopes we actually have — Sign In with LinkedIn (openid profile
  // email) + Share on LinkedIn (w_member_social). Personal profile
  // posting works end to end with these; Company Page auto-post is on
  // hold until the CMA approval lands, at which point we append the
  // org scopes here and George re-runs OAuth once.
  const scopes = ["openid", "profile", "email", "w_member_social"].join(" ");

  const state = Math.random().toString(36).slice(2);
  const params = new URLSearchParams({
    response_type: "code",
    client_id: clientId,
    redirect_uri: redirectUri,
    scope: scopes,
    state,
  });

  const url = `https://www.linkedin.com/oauth/v2/authorization?${params.toString()}`;
  return NextResponse.redirect(url);
}

// @ts-nocheck
// TikTok OAuth callback — one-time connect for @george.yachts.
//
// Flow:
//   1. George visits /api/auth/tiktok/login (wrapper that redirects to
//      TikTok's authorize endpoint with our client key + scopes).
//   2. TikTok bounces back here with ?code=... after he taps Allow on
//      @george.yachts.
//   3. We exchange the code for access + refresh tokens and persist
//      them in Supabase settings (key='tiktok_oauth').
//   4. From there, every publish call uses getValidAccessToken() which
//      refreshes automatically.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";

export async function GET(request: Request) {
  const url = new URL(request.url);
  const code = url.searchParams.get("code");
  const errParam = url.searchParams.get("error");
  if (errParam) {
    return new Response(
      `<h1>TikTok auth error</h1><p>${errParam}</p>`,
      { status: 400, headers: { "content-type": "text/html" } }
    );
  }
  if (!code) {
    return new Response("Missing code", { status: 400 });
  }

  const clientKey = process.env.TIKTOK_CLIENT_KEY;
  const clientSecret = process.env.TIKTOK_CLIENT_SECRET;
  const redirectUri =
    process.env.TIKTOK_REDIRECT_URI ||
    "https://gy-command.vercel.app/api/auth/tiktok/callback";
  if (!clientKey || !clientSecret) {
    return new Response("TikTok client not configured", { status: 500 });
  }

  const body = new URLSearchParams({
    client_key: clientKey,
    client_secret: clientSecret,
    code,
    grant_type: "authorization_code",
    redirect_uri: redirectUri,
  });

  let tokenJson: any = null;
  try {
    const res = await fetch("https://open.tiktokapis.com/v2/oauth/token/", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
    });
    tokenJson = await res.json();
  } catch (e) {
    return new Response(`Token exchange failed: ${e}`, { status: 500 });
  }

  if (!tokenJson?.access_token) {
    return new Response(
      `<pre>${JSON.stringify(tokenJson, null, 2)}</pre>`,
      { status: 400, headers: { "content-type": "text/html" } }
    );
  }

  const row = {
    access_token: tokenJson.access_token,
    refresh_token: tokenJson.refresh_token,
    expires_at: Date.now() + (tokenJson.expires_in ?? 3600) * 1000,
    open_id: tokenJson.open_id,
    scope: tokenJson.scope,
  };
  const sb = createServiceClient();
  await sb
    .from("settings")
    .upsert(
      { key: "tiktok_oauth", value: JSON.stringify(row) },
      { onConflict: "key" }
    );

  return new Response(
    `<!doctype html><html><body style="font-family:system-ui;padding:40px;background:#0b1020;color:#e7ecf2">
<h1 style="color:#d8b65d">TikTok connected</h1>
<p>@george.yachts OAuth stored. Scope: <code>${row.scope}</code></p>
<p>You can close this tab. The publish cron will use this token automatically.</p>
</body></html>`,
    { status: 200, headers: { "content-type": "text/html" } }
  );
}

