// PATCH — Update a contact's pipeline stage (used by Kanban drag-drop)
export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const body = await req.json();
    const supabase = createServiceClient();

    if (!body.pipeline_stage_id) {
      return NextResponse.json(
        { error: "pipeline_stage_id required" },
        { status: 400 }
      );
    }

    // Get old stage name for logging
    const { data: contact } = await supabase
      .from("contacts")
      .select("pipeline_stage_id, first_name, last_name, company, charter_vessel, pipeline_stage:pipeline_stages(name)")
      .eq("id", id)
      .single();

    // Get new stage name
    const { data: newStage } = await supabase
      .from("pipeline_stages")
      .select("name")
      .eq("id", body.pipeline_stage_id)
      .single();

    // Update the contact
    const { data, error } = await supabase
      .from("contacts")
      .update({
        pipeline_stage_id: body.pipeline_stage_id,
        last_activity_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      })
      .eq("id", id)
      .select("*")
      .single();

    if (error) {
      return NextResponse.json({ error: error.message }, { status: 400 });
    }

    // Log stage change activity
    const oldName = (contact?.pipeline_stage as { name?: string } | null)?.name ?? "Unknown";
    const newName = newStage?.name ?? "Unknown";

    await supabase.from("activities").insert({
      contact_id: id,
      type: "stage_change",
      description: `Stage changed from "${oldName}" to "${newName}"`,
      metadata: {
        from_stage: contact?.pipeline_stage_id,
        to_stage: body.pipeline_stage_id,
        from_name: oldName,
        to_name: newName,
      },
    });

    // Send Telegram alerts for key stage changes
    const contactName = [contact?.first_name, contact?.last_name]
      .filter(Boolean)
      .join(" ") || "Unknown";
    const company = contact?.company ?? "Unknown company";
    const vessel = contact?.charter_vessel ?? "TBD";

    if (newName === "Meeting Booked") {
      await sendTelegram(
        `\u{1F4C5} <b>MEETING BOOKED:</b> ${contactName} from ${company}`
      );
    } else if (newName === "Closed Won") {
      await sendTelegram(
        `\u{1F389} <b>DEAL CLOSED:</b> ${contactName} \u2014 ${vessel}`
      );
    }

    return NextResponse.json(data);
  } catch (err) {
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

// /api/crm/contacts/:id/tags-v2 — manual override of Pillar 2 AI tags.
//
// PUT body: { tags: ["travel_advisor", "b2b_partner", ...] }
// Sets contacts.tags_v2 to the given list (with confidence=1.0,
// source='manual') AND tags_overridden=true so the AI tagger never
// reverts the choice.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";

const ALLOWED = new Set([
  "travel_advisor",
  "charter_client",
  "b2b_partner",
  "press",
  "vendor",
  "cold_lead",
]);

export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> },
) {
  const { id } = await params;
  const body = (await request.json()) as { tags?: string[] };
  const cleaned = (body.tags ?? [])
    .filter((t) => ALLOWED.has(t))
    .map((tag) => ({ tag, confidence: 1, source: "manual" as const }));

  const sb = createServiceClient();
  const { error } = await sb
    .from("contacts")
    .update({
      tags_v2: cleaned,
      tags_overridden: true,
      tags_analyzed_at: new Date().toISOString(),
    })
    .eq("id", id);
  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
  return NextResponse.json({ ok: true, tags: cleaned });
}

// /api/crm/contacts/export — CSV export of contacts, optionally
// filtered by AI tag (Pillar 2 acceptance criterion: "Resulting list
// is exportable as CSV or directly usable for newsletter send").
//
// Query params:
//   ?tag=travel_advisor          filter to one tag
//   ?stage=Hot                   filter to a CRM stage name
//   ?country=Greece              filter to a country
//   ?replied_within_days=90      only contacts who emailed in last N days

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";

export const runtime = "nodejs";
export const maxDuration = 60;

function csvEscape(v: unknown): string {
  if (v === null || v === undefined) return "";
  const s = String(v);
  if (/[",\n]/.test(s)) return `"${s.replace(/"/g, '""')}"`;
  return s;
}

export async function GET(request: NextRequest) {
  const sp = request.nextUrl.searchParams;
  const tag = sp.get("tag");
  const stageName = sp.get("stage");
  const country = sp.get("country");
  const repliedWithinDays = parseInt(sp.get("replied_within_days") ?? "0", 10);

  const sb = createServiceClient();

  // Walk paginated.
  type Row = {
    id: string;
    first_name: string | null;
    last_name: string | null;
    email: string | null;
    company: string | null;
    country: string | null;
    phone: string | null;
    inbox_inferred_stage: string | null;
    inbox_last_inbound_at: string | null;
    tags_v2: Array<{ tag: string; confidence: number }> | null;
    pipeline_stage: { name: string } | null;
  };
  const rows: Row[] = [];
  const PAGE = 1000;
  let p = 0;
  while (true) {
    const { data, error } = await sb
      .from("contacts")
      .select(
        "id, first_name, last_name, email, company, country, phone, inbox_inferred_stage, inbox_last_inbound_at, tags_v2, pipeline_stage:pipeline_stages(name)",
      )
      .order("created_at", { ascending: true })
      .range(p * PAGE, (p + 1) * PAGE - 1);
    if (error || !data || data.length === 0) break;
    for (const r of data as unknown as Row[]) rows.push(r);
    if (data.length < PAGE) break;
    p++;
  }

  // Apply filters in JS (faster + simpler than fighting jsonb filters).
  const cutoff =
    repliedWithinDays > 0
      ? Date.now() - repliedWithinDays * 86_400_000
      : null;
  const filtered = rows.filter((r) => {
    if (tag) {
      const has =
        Array.isArray(r.tags_v2) && r.tags_v2.some((t) => t.tag === tag);
      if (!has) return false;
    }
    if (stageName && r.pipeline_stage?.name !== stageName) return false;
    if (country && (r.country ?? "") !== country) return false;
    if (cutoff !== null) {
      const t = r.inbox_last_inbound_at
        ? new Date(r.inbox_last_inbound_at).getTime()
        : 0;
      if (t < cutoff) return false;
    }
    return true;
  });

  const headers = [
    "first_name",
    "last_name",
    "email",
    "company",
    "country",
    "phone",
    "crm_stage",
    "inbox_stage",
    "last_inbound_at",
    "ai_tags",
  ];
  const lines = [headers.join(",")];
  for (const r of filtered) {
    const tags = (r.tags_v2 ?? [])
      .map((t) => `${t.tag}(${t.confidence.toFixed(2)})`)
      .join("|");
    lines.push(
      [
        r.first_name,
        r.last_name,
        r.email,
        r.company,
        r.country,
        r.phone,
        r.pipeline_stage?.name ?? "",
        r.inbox_inferred_stage ?? "",
        r.inbox_last_inbound_at ?? "",
        tags,
      ]
        .map(csvEscape)
        .join(","),
    );
  }
  const csv = lines.join("\n");
  return new NextResponse(csv, {
    headers: {
      "Content-Type": "text/csv; charset=utf-8",
      "Content-Disposition": `attachment; filename="gy-contacts-${new Date()
        .toISOString()
        .slice(0, 10)}.csv"`,
    },
  });
}

