// ─── Gmail send helper ──────────────────────────────────────────────────────

function createRawEmail(to: string, subject: string, body: string): string {
  const lines: string[] = [
    `From: George Yachts <george@georgeyachts.com>`,
    `To: ${to}`,
    `Subject: ${subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: text/plain; charset=UTF-8`,
    "",
    body,
  ];
  const raw = lines.join("\r\n");
  return Buffer.from(raw).toString("base64url");
}

async function sendEmail(
  to: string,
  subject: string,
  body: string
): Promise<boolean> {
  try {
    const raw = createRawEmail(to, subject, body);
    const res = await gmailFetch("/messages/send", {
      method: "POST",
      body: JSON.stringify({ raw }),
    });
    return res.ok;
  } catch (err) {
    console.error("[Birthdays] Email send error:", err);
    return false;
  }
}

// ─── Contact row shape ──────────────────────────────────────────────────────

interface BirthdayContact {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string | null;
  date_of_birth: string;
}

/**
 * Daily cron (08:00 UTC): Birthday auto-emails.
 * Queries contacts where date_of_birth matches today's month+day,
 * sends a birthday greeting, logs activity, and notifies via Telegram.
 */
async function _observedImpl(request: NextRequest): Promise<Response> {
  const authHeader = request.headers.get("authorization");
  const cronSecret = process.env.CRON_SECRET;

  if (cronSecret && authHeader !== `Bearer ${cronSecret}`) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const supabase = createServiceClient();

    const now = new Date();
    const month = String(now.getMonth() + 1).padStart(2, "0");
    const day = String(now.getDate()).padStart(2, "0");

    // Find contacts with matching birthday (month-day).
    // date_of_birth is stored as YYYY-MM-DD text.
    // We filter by the MM-DD suffix.
    const { data: allContacts } = await supabase
      .from("contacts")
      .select("id, first_name, last_name, email, date_of_birth")
      .not("date_of_birth", "is", null);

    if (!allContacts || allContacts.length === 0) {
      return NextResponse.json({
        ok: true,
        message: "No contacts with date_of_birth",
        emails_sent: 0,
      });
    }

    // Filter for today's birthdays (match MM-DD portion)
    const birthdayContacts = (allContacts as unknown as BirthdayContact[]).filter(
      (c) => {
        if (!c.date_of_birth) return false;
        const dob = c.date_of_birth; // "YYYY-MM-DD"
        return dob.slice(5, 7) === month && dob.slice(8, 10) === day;
      }
    );

    if (birthdayContacts.length === 0) {
      return NextResponse.json({
        ok: true,
        message: "No birthdays today",
        emails_sent: 0,
      });
    }

    let emailsSent = 0;
    const results: { contact: string; sent: boolean; reason?: string }[] = [];

    for (const contact of birthdayContacts) {
      const firstName = contact.first_name ?? "Friend";
      const name =
        [contact.first_name, contact.last_name].filter(Boolean).join(" ") ||
        "Valued Client";

      if (!contact.email) {
        results.push({ contact: name, sent: false, reason: "No email" });
        continue;
      }

      // Check if we already sent a birthday email today
      const todayStart = new Date();
      todayStart.setHours(0, 0, 0, 0);

      const { data: existingEmails } = await supabase
        .from("activities")
        .select("id")
        .eq("contact_id", contact.id)
        .eq("type", "email_sent")
        .gte("created_at", todayStart.toISOString())
        .ilike("description", "%birthday%")
        .limit(1);

      if (existingEmails && existingEmails.length > 0) {
        results.push({
          contact: name,
          sent: false,
          reason: "Already sent today",
        });
        continue;
      }

      const subject = `Happy Birthday, ${firstName}`;
      const body = `Dear ${firstName},

From all of us at George Yachts -- wishing you a wonderful birthday. May this year bring calm seas, warm sun, and another unforgettable voyage.

Best,
George`;

      const sent = await sendEmail(contact.email, subject, body);

      if (sent) {
        // Log activity
        await supabase.from("activities").insert({
          contact_id: contact.id,
          type: "email_sent",
          description: `Birthday email sent: "${subject}"`,
          metadata: {
            subject,
            generated_by: "cron",
            occasion: "birthday",
          },
        });

        // Update last_activity_at
        await supabase
          .from("contacts")
          .update({ last_activity_at: new Date().toISOString() })
          .eq("id", contact.id);

        // Telegram notification
        await sendTelegram(
          `\u{1F382} <b>${name}</b>'s birthday today -- email sent`
        );

        emailsSent++;
        results.push({ contact: name, sent: true });
      } else {
        results.push({ contact: name, sent: false, reason: "Email send failed" });
      }
    }

    return NextResponse.json({
      ok: true,
      birthdays_found: birthdayContacts.length,
      emails_sent: emailsSent,
      results,
    });
  } catch (err) {
    console.error("[Birthdays] Error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

export async function GET(request: NextRequest): Promise<Response> {
  return observeCron("birthdays", () => _observedImpl(request));
}

// Blog → all-social broadcaster.
//
// Tue + Thu 17:30 Athens (14:30 UTC). Picks the newest blog article on
// georgeyachts.com that hasn't yet been broadcast, then publishes it to:
//   - Facebook Page (full link, clickable, rich preview)
//   - Instagram Feed (image + caption with visible blog URL)
//   - Instagram Story (image; no clickable link — API limitation)
//   - Telegram digest for LinkedIn personal (existing Tue/Thu 08:45 cron
//     already surfaces the same article earlier in the day; we skip a
//     second LI ping to avoid double-surface)
//   - TikTok: queued for when app approval lands (logged only)
//
// Dedup: settings.blog_published_to_social stores the list of article
// URLs already processed. Each run picks the first unseen article from
// the sitemap (most recent first), broadcasts it, then appends the URL.
//
// Every real broadcast fires a Telegram summary with per-platform
// success / fail counts so George sees exactly what went out.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { sendTelegram } from "@/lib/telegram";
import { pickNextArticleForLinkedIn } from "@/lib/blog-fetcher";
import {
  publishBlogToFacebook,
  publishBlogToInstagramFeed,
  publishBlogToInstagramStory,
} from "@/lib/blog-social-publisher";
import { observeCron } from "@/lib/cron-observer";

export const runtime = "nodejs";
export const maxDuration = 300;

const KEY = "blog_published_to_social";

async function getPublishedUrls(): Promise<Set<string>> {
  const sb = createServiceClient();
  const { data } = await sb
    .from("settings")
    .select("value")
    .eq("key", KEY)
    .maybeSingle();
  try {
    const arr = JSON.parse((data?.value as string) ?? "[]");
    return new Set(Array.isArray(arr) ? arr : []);
  } catch {
    return new Set();
  }
}

async function addPublishedUrl(url: string): Promise<void> {
  const sb = createServiceClient();
  const current = await getPublishedUrls();
  current.add(url);
  await sb
    .from("settings")
    .upsert({ key: KEY, value: JSON.stringify([...current]) });
}

function escapeHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

async function _observedImpl() {
  try {
    const sb = createServiceClient();
    // Flag-gate so George can mute without a redeploy.
    const { data: flag } = await sb
      .from("settings")
      .select("value")
      .eq("key", "blog_to_social_enabled")
      .maybeSingle();
    if (flag?.value === "false") {
      return NextResponse.json({ skipped: "flag_off" });
    }

    const posted = await getPublishedUrls();
    const article = await pickNextArticleForLinkedIn(posted);
    if (!article) {
      return NextResponse.json({ skipped: "no_new_article", already_posted: posted.size });
    }

    // Fire broadcasters in parallel; swallow per-platform errors so one
    // failure doesn't block the others. Catch branch shape matches the
    // publisher Result type so downstream narrowing works in the
    // summary block.
    type PlatformResult =
      | { ok: true; id?: string }
      | { ok: false; error: string };
    const [fb, igFeed, igStory] = (await Promise.all([
      publishBlogToFacebook(article).catch<PlatformResult>((e) => ({
        ok: false,
        error: e?.message ?? "fb exception",
      })),
      publishBlogToInstagramFeed(article).catch<PlatformResult>((e) => ({
        ok: false,
        error: e?.message ?? "ig feed exception",
      })),
      publishBlogToInstagramStory(article).catch<PlatformResult>((e) => ({
        ok: false,
        error: e?.message ?? "ig story exception",
      })),
    ])) as [PlatformResult, PlatformResult, PlatformResult];

    // Always mark the article as broadcast so we don't retry tomorrow
    // even if one platform failed — a partial broadcast is still more
    // useful than looping the same article forever. Per-platform retry
    // is a separate concern for a future observer cron.
    await addPublishedUrl(article.url);

    const lines = [
      `📣 <b>Blog broadcast</b>`,
      `<b>Article:</b> ${escapeHtml(article.title)}`,
      `<b>URL:</b> ${article.url}`,
      ``,
      `FB:     ${fb.ok ? "✅ " + (fb.id ?? "") : "❌ " + escapeHtml(fb.error)}`,
      `IG feed: ${igFeed.ok ? "✅ " + (igFeed.id ?? "") : "❌ " + escapeHtml(igFeed.error)}`,
      `IG story: ${igStory.ok ? "✅ " + (igStory.id ?? "") : "❌ " + escapeHtml(igStory.error)}`,
      `TikTok:  ⏸ queued (awaiting app review)`,
      `LinkedIn: ℹ surfaced via Tue/Thu 08:45 Telegram digest`,
    ];
    await sendTelegram(lines.join("\n")).catch(() => {});

    return NextResponse.json({
      ok: true,
      article: { url: article.url, title: article.title },
      results: { facebook: fb, instagram_feed: igFeed, instagram_story: igStory },
    });
  } catch (e: any) {
    await sendTelegram(
      `⚠️ <b>Blog broadcast crashed</b>\n<code>${escapeHtml((e.message ?? "unknown").slice(0, 400))}</code>`,
    ).catch(() => {});
    return NextResponse.json({ error: e.message ?? "unknown" }, { status: 500 });
  }
}

export async function GET() {
  return observeCron("blog-to-social", () => _observedImpl());
}

// @ts-nocheck
import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { aiChat } from "@/lib/ai";
import { BRAND, COMPETITORS, QUERIES } from "@/lib/brand-radar-queries";
import { observeCron } from "@/lib/cron-observer";

// Cron: Weekly AI Brand Radar scan — Sundays at 06:00 UTC
// Sends queries to Gemini, checks if George Yachts is mentioned in responses

const SYSTEM_PROMPT = `You are a helpful AI assistant. Answer the user's question about yacht charters naturally and helpfully. Recommend specific companies, websites, or brokers when relevant. Be specific with names.`;

async function _observedImpl(): Promise<Response> {
  const sb = createServiceClient();
  const today = new Date().toISOString().slice(0, 10);

  // Check if already scanned today — return the latest weekly summary so the
  // client can still display real numbers instead of "undefined".
  const { data: existing } = await sb
    .from("brand_radar_scans")
    .select("id")
    .eq("scan_date", today)
    .limit(1);

  if (existing?.length) {
    const { data: latestWeekly } = await sb
      .from("brand_radar_weekly")
      .select("*")
      .order("week_start", { ascending: false })
      .limit(1)
      .maybeSingle();

    return NextResponse.json({
      status: "already_scanned",
      date: today,
      scanned: latestWeekly?.total_queries ?? QUERIES.length,
      brand_mentions: latestWeekly?.brand_mentions ?? 0,
      share_of_voice: `${latestWeekly?.share_of_voice ?? 0}%`,
      top_competitor: latestWeekly?.top_competitor ?? "N/A",
      top_competitor_mentions: latestWeekly?.top_competitor_mentions ?? 0,
      competitor_breakdown: latestWeekly?.competitor_breakdown ?? {},
    });
  }

  let scanned = 0;
  let brandMentions = 0;
  const competitorCounts: Record<string, number> = {};
  COMPETITORS.forEach((c) => (competitorCounts[c] = 0));

  for (const query of QUERIES) {
    try {
      // Ask Gemini the query
      const response = await aiChat(SYSTEM_PROMPT, query);
      const responseLower = response.toLowerCase();

      // Check brand mention
      const brandMentioned =
        responseLower.includes("george yachts") ||
        responseLower.includes("georgeyachts");

      if (brandMentioned) brandMentions++;

      // Check competitor mentions
      const mentionedCompetitors: string[] = [];
      const allMentioned: string[] = [];

      if (brandMentioned) allMentioned.push(BRAND);

      for (const comp of COMPETITORS) {
        if (responseLower.includes(comp.toLowerCase())) {
          mentionedCompetitors.push(comp);
          allMentioned.push(comp);
          competitorCounts[comp]++;
        }
      }

      // Store scan result
      await sb.from("brand_radar_scans").insert({
        scan_date: today,
        query,
        response_preview: response.slice(0, 500),
        brand_mentioned: brandMentioned,
        competitors_mentioned: mentionedCompetitors,
        all_brands_mentioned: allMentioned,
        model: "gemini",
      });

      scanned++;

      // Small delay to avoid rate limiting
      await new Promise((r) => setTimeout(r, 1000));
    } catch (err) {
      console.error(`[Brand Radar] Failed query: "${query}"`, err);
    }
  }

  // Calculate share of voice
  const totalMentionableResponses = QUERIES.length;
  const sov = totalMentionableResponses > 0
    ? Math.round((brandMentions / totalMentionableResponses) * 10000) / 100
    : 0;

  // Find top competitor
  const topCompetitor = Object.entries(competitorCounts)
    .sort(([, a], [, b]) => b - a)[0];

  // Store weekly summary
  const weekStart = new Date();
  weekStart.setDate(weekStart.getDate() - weekStart.getDay());

  await sb.from("brand_radar_weekly").insert({
    week_start: weekStart.toISOString().slice(0, 10),
    total_queries: QUERIES.length,
    brand_mentions: brandMentions,
    share_of_voice: sov,
    top_competitor: topCompetitor?.[0] || null,
    top_competitor_mentions: topCompetitor?.[1] || 0,
    competitor_breakdown: competitorCounts,
  });

  // Weekly Telegram summary — added 2026-04-24. Was silent before;
  // tracking SoV that nobody reads defeats the purpose. Now George
  // gets one Telegram every Sunday morning with the headline numbers.
  try {
    const { sendTelegram } = await import("@/lib/telegram");
    const lines = [
      `🛰️ <b>Brand Radar — Weekly</b>`,
      `Share of Voice: <b>${sov}%</b> (${brandMentions}/${QUERIES.length} queries)`,
      `Top competitor: <b>${topCompetitor?.[0] ?? "—"}</b> (${topCompetitor?.[1] ?? 0} mentions)`,
      `Scanned: ${scanned}`,
      `Week of: ${weekStart.toISOString().slice(0, 10)}`,
    ];
    await sendTelegram(lines.join("\n"));
  } catch (e) {
    console.error("[brand-radar] Telegram summary failed:", e);
  }

  return NextResponse.json({
    status: "ok",
    scanned,
    brand_mentions: brandMentions,
    share_of_voice: `${sov}%`,
    top_competitor: topCompetitor?.[0] ?? "N/A",
    top_competitor_mentions: topCompetitor?.[1] ?? 0,
    competitor_breakdown: competitorCounts,
    date: today,
  });
}

export async function GET(): Promise<Response> {
  return observeCron("brand-radar", _observedImpl);
}

import { NextRequest, NextResponse } from "next/server";
import { calendarFetch, getSetting } from "@/lib/google-api";
import { createServiceClient } from "@/lib/supabase-server";
import { observeCron } from "@/lib/cron-observer";

interface CalendarEvent {
  id: string;
  summary?: string;
  start?: { dateTime?: string; date?: string };
  end?: { dateTime?: string; date?: string };
  attendees?: { email: string }[];
}

async function _observedImpl(request: NextRequest): Promise<Response> {
  // Verify cron secret in production
  const authHeader = request.headers.get("authorization");
  if (
    process.env.CRON_SECRET &&
    authHeader !== `Bearer ${process.env.CRON_SECRET}`
  ) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    // Check if Gmail/Calendar is connected
    const refreshToken = await getSetting("gmail_refresh_token");
    if (!refreshToken) {
      return NextResponse.json({ skipped: true, reason: "Calendar not connected" });
    }

    // Fetch events from the last hour to catch new meetings
    const timeMin = new Date(Date.now() - 60 * 60 * 1000).toISOString();
    const timeMax = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();

    const params = new URLSearchParams({
      timeMin,
      timeMax,
      singleEvents: "true",
      orderBy: "startTime",
      maxResults: "50",
    });

    const res = await calendarFetch(`/calendars/primary/events?${params.toString()}`);
    if (!res.ok) {
      const text = await res.text();
      return NextResponse.json({ error: text }, { status: 500 });
    }

    const data = await res.json();
    const events: CalendarEvent[] = data.items ?? [];

    const sb = createServiceClient();
    let matched = 0;

    for (const event of events) {
      const attendees = event.attendees ?? [];
      if (attendees.length === 0) continue;

      // Check if any attendee email matches a CRM contact
      for (const attendee of attendees) {
        const { data: contact } = await sb
          .from("contacts")
          .select("id, pipeline_stage_id")
          .ilike("email", attendee.email.toLowerCase())
          .single();

        if (!contact) continue;

        // Find "Meeting Booked" pipeline stage
        const { data: meetingStage } = await sb
          .from("pipeline_stages")
          .select("id")
          .eq("name", "Meeting Booked")
          .single();

        if (meetingStage && contact.pipeline_stage_id !== meetingStage.id) {
          await sb
            .from("contacts")
            .update({
              pipeline_stage_id: meetingStage.id,
              last_activity_at: new Date().toISOString(),
            })
            .eq("id", contact.id);

          // Check for existing activity to avoid duplicates
          const { data: existingActivity } = await sb
            .from("activities")
            .select("id")
            .eq("contact_id", contact.id)
            .eq("type", "meeting_booked")
            .gte("created_at", new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
            .single();

          if (!existingActivity) {
            await sb.from("activities").insert({
              contact_id: contact.id,
              type: "meeting_booked",
              description: `Meeting scheduled: ${event.summary ?? "Calendar event"}`,
              metadata: {
                event_id: event.id,
                event_summary: event.summary,
                event_start: event.start?.dateTime ?? event.start?.date,
              },
            });
          }

          matched++;
        }
      }
    }

    return NextResponse.json({
      success: true,
      eventsChecked: events.length,
      contactsMatched: matched,
    });
  } catch (err) {
    console.error("[Calendar Sync] Error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

export async function GET(request: NextRequest): Promise<Response> {
  return observeCron("calendar-sync", () => _observedImpl(request));
}

// v3 Pillar 7 — Daily charter lifecycle firing.
//
// Runs every morning ~06:30 Athens. For every charter_lifecycle_milestone
// whose due_date <= today (Athens) AND status = 'pending', generate a
// Gmail draft using the personalized template and write back gmail_draft_id.
//
// Auto-DRAFTS only — never auto-sends. Matches the rest of the codebase
// (greetings, commitments). George reviews drafts before pressing send.
//
// Idempotent — milestones already linked to a gmail_draft_id are skipped.
//
// Resilient — if the v3 schema isn't applied yet (table missing), the
// route returns a graceful 200 with hint instead of crashing the cron.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { gmailFetch } from "@/lib/google-api";
import {
  generateMilestoneDraft,
  type TemplateContext,
} from "@/lib/charter-lifecycle";
import { observeCron } from "@/lib/cron-observer";

export const runtime = "nodejs";
export const maxDuration = 300;

interface MilestoneRow {
  id: string;
  deal_id: string | null;
  contact_id: string | null;
  milestone_type: string;
  due_date: string;
  status: string;
  auto_action: string | null;
  gmail_draft_id: string | null;
}

interface DealRow {
  id: string;
  primary_contact_id: string | null;
  vessel_name: string | null;
  charter_start_date: string | null;
  charter_end_date: string | null;
  embark_port: string | null;
  disembark_port: string | null;
}

interface ContactRow {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string | null;
}

// Map milestone_type → template key in charter-lifecycle.ts.
// Milestones without a template (research-only ones like T-60, T-21) are
// recorded but no draft is generated — George sees them in the cockpit
// for awareness.
const TEMPLATE_KEY: Record<string, string | null> = {
  "T-60": null,
  "T-45": "T-45_reference_list",
  "T-40": "T-40_send_references",
  "T-30": "T-30_pif_and_captain_call",
  "T-21": null,
  "T-15": null,
  "T-14": "T-14_personal_video",
  "T-7": "T-7_final_logistics",
  "T-3": "T-3_looking_forward",
  "T-1": null,
  "T+0": "T+0_embarkation",
  "T+midpoint": "T+midpoint_checkin",
  "T+disembark+1": "T+disembark+1_thank_you",
  "T+7": "T+7_testimonial",
  "T+30": "T+30_settled",
  "T+90": "T+90_next_season",
  "T+annual": "T+annual_anniversary",
};

function todayAthens(): string {
  const now = new Date();
  // +2h winter / +3h summer; use +2 as conservative floor.
  const athens = new Date(now.getTime() + 2 * 60 * 60 * 1000);
  return athens.toISOString().slice(0, 10);
}

function buildRawDraft(to: string, subject: string, body: string): string {
  const lines = [
    `To: ${to}`,
    `Subject: ${subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: text/plain; charset=UTF-8`,
    ``,
    body,
  ];
  return Buffer.from(lines.join("\r\n")).toString("base64url");
}

async function getOrCreateLabelId(name: string): Promise<string | null> {
  try {
    const list = await gmailFetch("/labels");
    if (!list.ok) return null;
    const j = (await list.json()) as { labels?: { id: string; name: string }[] };
    const existing = (j.labels ?? []).find((l) => l.name === name);
    if (existing) return existing.id;
    const create = await gmailFetch("/labels", {
      method: "POST",
      body: JSON.stringify({
        name,
        labelListVisibility: "labelShow",
        messageListVisibility: "show",
      }),
    });
    if (!create.ok) return null;
    return ((await create.json()) as { id: string }).id;
  } catch {
    return null;
  }
}

async function createDraft(args: {
  to: string;
  subject: string;
  body: string;
  labelId: string | null;
}): Promise<{ id: string } | null> {
  const raw = buildRawDraft(args.to, args.subject, args.body);
  const draftRes = await gmailFetch("/drafts", {
    method: "POST",
    body: JSON.stringify({ message: { raw } }),
  });
  if (!draftRes.ok) return null;
  const draft = (await draftRes.json()) as {
    id: string;
    message?: { id?: string };
  };
  if (args.labelId && draft.message?.id) {
