// Pillar 5 — nightly health-score recompute.
//
// Walks all contacts that have at least one email activity
// (eligibility set the same as inbox-tag), refreshes their
// health_score + history snapshot. Time-budgeted with resumable
// offset cursor.

import { NextRequest, NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { refreshHealthScore } from "@/lib/health-scorer";
import { observeCron } from "@/lib/cron-observer";

export const runtime = "nodejs";
export const maxDuration = 300;

const EMAIL_TYPES = [
  "email_sent",
  "email_inbound",
  "email_received",
  "email_reply_hot_or_warm",
  "email_reply_cold",
  "reply",
];

async function _observedImpl(request: NextRequest): Promise<Response> {
  const sp = request.nextUrl.searchParams;
  const startOffset = parseInt(sp.get("offset") ?? "0", 10);
  const startedAt = Date.now();
  const budgetMs = 250_000;
  const sb = createServiceClient();

  // Eligible contact ids — same paginated walk as inbox-tag.
  const idSet = new Set<string>();
  let actPage = 0;
  const ACT_PAGE = 1000;
  while (true) {
    const { data: rows } = await sb
      .from("activities")
      .select("contact_id")
      .in("type", EMAIL_TYPES)
      .not("contact_id", "is", null)
      .order("created_at", { ascending: false })
      .range(actPage * ACT_PAGE, (actPage + 1) * ACT_PAGE - 1);
    if (!rows || rows.length === 0) break;
    for (const r of rows) {
      const id = r.contact_id as string | null;
      if (id) idSet.add(id);
    }
    if (rows.length < ACT_PAGE) break;
    actPage++;
  }
  const all = Array.from(idSet).sort();

  let cursor = startOffset;
  let processed = 0;
  const buckets = { red: 0, orange: 0, green: 0 };
  while (cursor < all.length && Date.now() - startedAt < budgetMs) {
    const id = all[cursor];
    cursor++;
    try {
      const c = await refreshHealthScore(sb, id);
      if (c) {
        if (c.total < 40) buckets.red++;
        else if (c.total < 70) buckets.orange++;
        else buckets.green++;
        processed++;
      }
    } catch (err) {
      console.error("[health-score] failed for", id, err);
    }
  }

  return NextResponse.json({
    ok: true,
    processed,
    eligible: all.length,
    buckets,
    next_offset: cursor < all.length ? cursor : null,
    hint:
      cursor < all.length
        ? `Resume with ?offset=${cursor}`
        : "All contacts scored.",
  });
}

export async function GET(request: NextRequest): Promise<Response> {
  return observeCron("health-score-recompute", () => _observedImpl(request));
}

// Pillar 5 — weekly digest of top 10 warming + top 10 cooling
// contacts. Sent via Telegram Sunday 09:00 Athens.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { sendTelegram } from "@/lib/telegram";
import { observeCron } from "@/lib/cron-observer";

export const runtime = "nodejs";
export const maxDuration = 60;

interface Row {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string | null;
  health_score: number | null;
  health_score_trend: string | null;
}

function escapeHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

function name(r: Row): string {
  return (
    `${r.first_name ?? ""} ${r.last_name ?? ""}`.trim() ||
    r.email ||
    "(contact)"
  );
}

async function _observedImpl(): Promise<Response> {
  try {
    const sb = createServiceClient();

    const { data: warming } = await sb
      .from("contacts")
      .select(
        "id, first_name, last_name, email, health_score, health_score_trend",
      )
      .eq("health_score_trend", "up")
      .not("health_score", "is", null)
      .order("health_score", { ascending: false })
      .limit(10);

    const { data: cooling } = await sb
      .from("contacts")
      .select(
        "id, first_name, last_name, email, health_score, health_score_trend",
      )
      .eq("health_score_trend", "down")
      .not("health_score", "is", null)
      .order("health_score", { ascending: true })
      .limit(10);

    const lines: string[] = ["🌡️ <b>Weekly relationship health digest</b>", ""];
    if ((warming?.length ?? 0) > 0) {
      lines.push("<b>📈 Warming up — invest here</b>");
      for (const r of warming as Row[]) {
        lines.push(`· ${escapeHtml(name(r))} — ${r.health_score}/100`);
      }
      lines.push("");
    }
    if ((cooling?.length ?? 0) > 0) {
      lines.push("<b>📉 Cooling — soft-ghost watch</b>");
      for (const r of cooling as Row[]) {
        lines.push(`· ${escapeHtml(name(r))} — ${r.health_score}/100`);
      }
      lines.push("");
    }
    if ((warming?.length ?? 0) === 0 && (cooling?.length ?? 0) === 0) {
      lines.push("<i>All relationships steady this week.</i>");
    }
    lines.push(
      `<a href="https://command.georgeyachts.com">→ Open cockpit</a>`,
    );

    await sendTelegram(lines.join("\n")).catch(() => {});

    return NextResponse.json({
      ok: true,
      warming: warming?.length ?? 0,
      cooling: cooling?.length ?? 0,
    });
  } catch (e: unknown) {
    const msg = e instanceof Error ? e.message : "unknown";
    return NextResponse.json({ error: msg }, { status: 500 });
  }
}

export async function GET(): Promise<Response> {
  return observeCron("health-weekly-digest", _observedImpl);
}

