// Tue + Thu 08:45 Athens — Blog article digest to Telegram.
//
// This cron fetches the newest blog article George hasn't surfaced to
// LinkedIn yet, generates a personal-profile draft in his voice (using
// the linkedin-caption library and the Meltemi post exemplar), and
// Telegrams it to him as a copy/paste block. The companion
// linkedin-company-amplify cron runs 2 hours later to auto-post the
// brokerage-voice version on the Company Page.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { observeCron } from "@/lib/cron-observer";
import { sendTelegram } from "@/lib/telegram";
import { pickNextArticleForLinkedIn } from "@/lib/blog-fetcher";
import {
  formatDraftForTelegram,
  generatePersonalDraft,
} from "@/lib/linkedin-caption";

export const runtime = "nodejs";
export const maxDuration = 120;

async function getPostedUrls(): Promise<Set<string>> {
  const sb = createServiceClient();
  const { data } = await sb
    .from("settings")
    .select("value")
    .eq("key", "linkedin_posted_urls")
    .maybeSingle();
  try {
    const arr = JSON.parse((data?.value as string) ?? "[]");
    return new Set(Array.isArray(arr) ? arr : []);
  } catch {
    return new Set();
  }
}

async function addPostedUrl(url: string): Promise<void> {
  const sb = createServiceClient();
  const current = await getPostedUrls();
  current.add(url);
  await sb
    .from("settings")
    .upsert({ key: "linkedin_posted_urls", value: JSON.stringify([...current]) });
}

async function stageArticleForAmplify(url: string, slug: string): Promise<void> {
  // Store the URL the amplify cron should pick up ~2h later. Overwrites
  // the previous staged article — we only amplify one at a time.
  const sb = createServiceClient();
  await sb.from("settings").upsert({
    key: "linkedin_amplify_pending",
    value: JSON.stringify({
      url,
      slug,
      stagedAt: new Date().toISOString(),
    }),
  });
}

async function _observedImpl() {
  try {
    const posted = await getPostedUrls();
    const article = await pickNextArticleForLinkedIn(posted);
    if (!article) {
      return NextResponse.json({ skipped: "no_new_article", posted: posted.size });
    }

    const draft = await generatePersonalDraft(article);
    const telegramBody = formatDraftForTelegram(draft, article.url);

    await sendTelegram(
      [
        `📝 <b>LinkedIn Tue/Thu — new blog article ready</b>`,
        `<b>Article:</b> ${escapeHtml(article.title)}`,
        `<b>URL:</b> ${article.url}`,
        "",
        telegramBody,
      ].join("\n"),
    );

    // Mark article as surfaced so we don't re-draft the same one.
    await addPostedUrl(article.url);
    // Stage it for the amplify cron (Company Page post ~2h later).
    await stageArticleForAmplify(article.url, article.slug);

    return NextResponse.json({
      ok: true,
      article: article.url,
      mainPostChars: draft.mainPost.length,
    });
  } catch (e: any) {
    await sendTelegram(
      `⚠️ <b>LinkedIn blog digest failed</b>\n<code>${escapeHtml(e.message ?? "unknown")}</code>`,
    ).catch(() => {});
    return NextResponse.json({ error: e.message }, { status: 500 });
  }
}

function escapeHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

export async function GET() {
  return observeCron("linkedin-blog-digest", () => _observedImpl());
}

// Tue + Thu 11:00 Athens — Company Page amplify.
//
// ~2h after the personal-profile digest fires, this cron takes the
// article staged by linkedin-blog-digest and publishes a brokerage-voice
// version on the George Yachts Company Page via the LinkedIn API.
// Different framing from the personal post so the algorithm doesn't
// flag duplicate content — personal = George's first-person insight,
// Company = third-person agent-facing commercial angle.

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { observeCron } from "@/lib/cron-observer";
import { sendTelegram } from "@/lib/telegram";
import { fetchArticle } from "@/lib/blog-fetcher";
import { generateCompanyDraft } from "@/lib/linkedin-caption";
import { publishAsOrganization } from "@/lib/linkedin-client";

export const runtime = "nodejs";
export const maxDuration = 120;

type StagedArticle = {
  url: string;
  slug: string;
  stagedAt: string;
};

async function getStaged(): Promise<StagedArticle | null> {
  const sb = createServiceClient();
  const { data } = await sb
    .from("settings")
    .select("value")
    .eq("key", "linkedin_amplify_pending")
    .maybeSingle();
  if (!data?.value) return null;
  try {
    return typeof data.value === "string"
      ? (JSON.parse(data.value) as StagedArticle)
      : (data.value as StagedArticle);
  } catch {
    return null;
  }
}

async function clearStaged(): Promise<void> {
  const sb = createServiceClient();
  await sb.from("settings").delete().eq("key", "linkedin_amplify_pending");
}

async function _observedImpl() {
  try {
    const staged = await getStaged();
    if (!staged) {
      return NextResponse.json({ skipped: "no_staged_article" });
    }

    // Freshness check — only amplify if staged within the last 6 hours.
    // Anything older is stale (George probably didn't post manually).
    const ageHours =
      (Date.now() - new Date(staged.stagedAt).getTime()) / (3600 * 1000);
    if (ageHours > 6) {
      await clearStaged();
      return NextResponse.json({
        skipped: "staged_too_old",
        ageHours: Number(ageHours.toFixed(1)),
      });
    }

    const article = await fetchArticle(staged.url);
    const draft = await generateCompanyDraft(article);

    // Compose final post: body + blank line + hashtags. Company Page
    // posts can link directly in the body (unlike personal profile
    // best practice), so the link should already be in draft.mainPost.
    const hashtagLine = draft.hashtags
      .map((h) => `#${h.replace(/^#/, "")}`)
      .join(" ");
    const commentary = `${draft.mainPost}\n\n${hashtagLine}`.trim();

    const result = await publishAsOrganization({
      commentary,
      mediaUrl: article.coverImageUrl ?? undefined,
    });

    if (!result.ok) {
      await sendTelegram(
        `⚠️ <b>LinkedIn Company amplify failed</b>\n<code>${escapeHtml(result.error)}</code>\nArticle: ${article.url}`,
      ).catch(() => {});
      return NextResponse.json({ error: result.error }, { status: 500 });
    }

    await clearStaged();
    await sendTelegram(
      [
        `💼 <b>LinkedIn Company Page post live</b>`,
        `Article: ${escapeHtml(article.title)}`,
        `Post URN: <code>${result.urn}</code>`,
      ].join("\n"),
    ).catch(() => {});

    return NextResponse.json({ ok: true, urn: result.urn, article: article.url });
  } catch (e: any) {
    await sendTelegram(
      `⚠️ <b>LinkedIn Company amplify crashed</b>\n<code>${escapeHtml(e.message ?? "unknown")}</code>`,
    ).catch(() => {});
    return NextResponse.json({ error: e.message }, { status: 500 });
  }
}

function escapeHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

export async function GET() {
  return observeCron("linkedin-company-amplify", () => _observedImpl());
}

