    return NextResponse.json({
      ok: true,
      yacht: yacht.name,
      urn: result.urn,
    });
  } catch (e: any) {
    await sendTelegram(
      `⚠️ <b>LinkedIn fleet brief crashed</b>\n<code>${escapeHtml(e.message ?? "unknown")}</code>`,
    ).catch(() => {});
    return NextResponse.json({ error: e.message }, { status: 500 });
