// Sprint 2.2 — nightly per-thread suggested action generator.
//
// Walks the top-N (cap 30) cockpit-eligible threads sorted by
// composite_priority_score, generates an AI one-liner per row,
// caches on contacts.next_touch_suggestion. Re-runs only on rows
// where the suggestion is missing OR older than the contact's
// inbox_analyzed_at (i.e. state changed since last suggestion).

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import {
  suggestAction,
  compositePriorityScore,
} from "@/lib/thread-suggester";
import { observeCron } from "@/lib/cron-observer";

export const runtime = "nodejs";
export const maxDuration = 300;

const TOP_N = 30;

async function _observedImpl(): Promise<Response> {
  const sb = createServiceClient();

  // Pull contacts that have an inbox state worth suggesting on.
  const { data: rows } = await sb
    .from("contacts")
    .select(
      "id, first_name, last_name, email, charter_fee, inbox_inferred_stage, inbox_gap_days, inbox_last_direction, inbox_last_subject, inbox_last_snippet, inbox_starred, parked_until, declined_at, pipeline_stage:pipeline_stages(name), health_score, next_touch_suggestion, next_touch_suggestion_at, inbox_analyzed_at",
    )
    .not("inbox_inferred_stage", "is", null)
    .neq("inbox_inferred_stage", "unknown")
    .limit(500);

  type Row = {
    id: string;
    first_name: string | null;
    last_name: string | null;
    email: string | null;
    charter_fee: number | null;
    inbox_inferred_stage: string;
    inbox_gap_days: number | null;
    inbox_last_direction: "inbound" | "outbound" | null;
    inbox_last_subject: string | null;
    inbox_last_snippet: string | null;
    inbox_starred: boolean | null;
    parked_until: string | null;
    declined_at: string | null;
    pipeline_stage: { name: string } | null;
    health_score: number | null;
    next_touch_suggestion: string | null;
    next_touch_suggestion_at: string | null;
    inbox_analyzed_at: string | null;
  };

  // Score everything first, persist composite_priority_score.
  const scored: Array<{ row: Row; score: number }> = [];
  for (const r of (rows ?? []) as unknown as Row[]) {
    // Look up open commitments for this contact (cheap — single
    // query per row, but only N=500 rows so OK).
    const { data: commits } = await sb
      .from("commitments")
      .select("deadline_date, fulfilled_at, dismissed_at")
      .eq("contact_id", r.id)
      .is("fulfilled_at", null)
      .is("dismissed_at", null);
    const today = new Date().toISOString().slice(0, 10);
    const hasOpen = (commits ?? []).length > 0;
    const hasOverdue = (commits ?? []).some(
      (c) => c.deadline_date && (c.deadline_date as string) < today,
    );
    const score = compositePriorityScore({
      inbox_stage: r.inbox_inferred_stage,
      gap_days: r.inbox_gap_days ?? 0,
      starred: !!r.inbox_starred,
      pipeline_stage: r.pipeline_stage?.name ?? null,
      charter_fee: r.charter_fee,
      health_score: r.health_score,
      has_open_commitment: hasOpen,
      has_overdue_commitment: hasOverdue,
      parked_until: r.parked_until,
      declined_at: r.declined_at,
    });
    scored.push({ row: r, score });
    await sb
      .from("contacts")
      .update({ composite_priority_score: score })
      .eq("id", r.id);
  }

  // Top-N by score → generate / refresh suggestion.
  scored.sort((a, b) => b.score - a.score);
  const top = scored.slice(0, TOP_N);
  let regenerated = 0;
  let kept = 0;
  for (const { row } of top) {
    const stale =
      !row.next_touch_suggestion_at ||
      (row.inbox_analyzed_at &&
        row.inbox_analyzed_at > row.next_touch_suggestion_at);
    if (!stale && row.next_touch_suggestion) {
      kept++;
      continue;
    }
    const suggestion = await suggestAction({
      contact_name:
        `${row.first_name ?? ""} ${row.last_name ?? ""}`.trim() ||
        row.email ||
        "(contact)",
      inbox_stage: row.inbox_inferred_stage,
      gap_days: row.inbox_gap_days ?? 0,
      last_direction: row.inbox_last_direction,
      last_subject: row.inbox_last_subject,
      last_snippet: row.inbox_last_snippet?.slice(0, 280) ?? null,
      pipeline_stage: row.pipeline_stage?.name ?? null,
      charter_fee: row.charter_fee,
      open_commitments: [],
      health_score: row.health_score,
    });
    if (suggestion) {
      await sb
        .from("contacts")
        .update({
          next_touch_suggestion: suggestion,
          next_touch_suggestion_at: new Date().toISOString(),
        })
        .eq("id", row.id);
      regenerated++;
    }
  }

  return NextResponse.json({
    ok: true,
    scored: scored.length,
    top_n: top.length,
    regenerated,
    kept_cached: kept,
  });
}

export async function GET(): Promise<Response> {
  return observeCron("thread-suggestions", _observedImpl);
}

// @ts-nocheck
// TikTok mirror cron.
//
// Pulls rows from ig_posts where:
//   status = 'published' (on Instagram)
//   post_type IN ('reel', 'fleet_yacht')   ← videos + photo carousels only
//   tiktok_status IS NULL                  ← not yet mirrored
//   published_at > NOW() - interval '3 hours'  ← only recent posts
//
// and publishes the same asset to @george.yachts on TikTok. Every
// mirrored post shares the SAME Telegram approval lineage as its IG
// sibling — if George approved the IG caption, it's approved for TT
// too. Separate caption-style adaptation (hashtag swap, opener tweak)
// runs in adaptCaptionForTikTok().
//
// Schedule: `15 16 * * 1-5` in vercel.json = 19:15 Athens, 1h after
// the IG publish window. Gives IG time to render + lets us read
// engagement signals before duplicating (future optimisation: skip
// mirror if IG post flatlined).

import { NextResponse } from "next/server";
import { createServiceClient } from "@/lib/supabase-server";
import { observeCron } from "@/lib/cron-observer";
import { sendTelegram } from "@/lib/telegram";
import { publishVideo, publishPhotos, pollPublishStatus } from "@/lib/tiktok-client";
import { assertPublishAllowed } from "@/lib/ig-window-guard";

export const runtime = "nodejs";
export const maxDuration = 300;

function adaptCaptionForTikTok(igCaption: string): string {
  // Swap IG-specific hashtags for TikTok-native equivalents. Rough
  // mapping only — the right long-term answer is an LLM call that's
  // prompted with TikTok's current trending tags. For now, a static
  // find/replace gets us 80% of the benefit.
  const swaps: Array<[RegExp, string]> = [
    [/#YachtCharterGreece/gi, "#YachtCharterGreece #GreekYachtTok"],
    [/#CycladesIslands/gi, "#CycladesIslands #GreekIslands"],
    [/#FountainePajot/gi, "#FountainePajot #Catamaran"],
    [/#LuxuryCharter\w*/gi, "#LuxuryYachtLife #YachtLife"],
    [/#MediterraneanCharter/gi, "#MediterraneanSea"],
  ];
  let out = igCaption;
  for (const [re, val] of swaps) out = out.replace(re, val);
  // Trim to TikTok's 2200 char limit.
  return out.slice(0, 2200);
}

async function _impl() {
  // Same window guard — TikTok posts stay inside brand-safe hours.
  const gate = await assertPublishAllowed({ postType: "reel" });
  if (!gate.allowed) {
    return NextResponse.json({
      skipped: "window_guard",
      reason: gate.reason,
      detail: gate.detail,
    });
  }

  const sb = createServiceClient();
  const since = new Date(Date.now() - 3 * 60 * 60 * 1000).toISOString();
  const { data: candidates } = await sb
    .from("ig_posts")
    .select("*")
    .eq("status", "published")
    .in("post_type", ["reel", "fleet_yacht", "image"])
    .is("tiktok_status", null)
    .gte("published_at", since)
    .limit(2);

  if (!candidates || candidates.length === 0) {
    return NextResponse.json({ skipped: "no_candidates" });
  }

  const results: any[] = [];
  for (const row of candidates) {
    const caption = adaptCaptionForTikTok(row.caption ?? "");
    let publishRes: any;
    if (row.post_type === "reel") {
      publishRes = await publishVideo({
        videoUrl: row.image_url, // the library stores video URL here for reels
        caption,
      });
    } else {
      // fleet_yacht + image → photo carousel on TikTok. For fleet we
      // have the full Sanity photo list in row.metadata.photos; fall
      // back to a single-image post if only the hero exists.
      const photos: string[] = Array.isArray(row?.metadata?.photos)
        ? row.metadata.photos
        : [row.image_url].filter(Boolean);
      publishRes = await publishPhotos({ photoUrls: photos, caption });
    }

    if (!publishRes.ok) {
      await sb
        .from("ig_posts")
        .update({
          tiktok_status: "failed",
          tiktok_error: publishRes.error ?? "unknown",
        })
        .eq("id", row.id);
      await sendTelegram(
        `⚠️ TikTok mirror failed for post ${row.id.slice(0, 8)}: ${publishRes.error}`
      ).catch(() => {});
      results.push({ id: row.id, ok: false, error: publishRes.error });
      continue;
    }

    const status = await pollPublishStatus(publishRes.publish_id!);
    await sb
      .from("ig_posts")
      .update({
        tiktok_status: status.status === "PUBLISH_COMPLETE" ? "published" : "pending",
        tiktok_publish_id: publishRes.publish_id,
      })
      .eq("id", row.id);

    await sendTelegram(
      `🎵 <b>TikTok mirror OK</b>\nPost: ${row.id.slice(0, 8)}\nStatus: ${status.status}\n@george.yachts`
    ).catch(() => {});

    results.push({ id: row.id, ok: true, status: status.status });
  }

  return NextResponse.json({ mirrored: results.length, results });
}

async function _observedImpl() {
  // Flag-gate: until TikTok app review completes + tiktok_oauth token
  // is stored in settings, every daily invocation just burns compute
  // + risks 500s. Flip settings.tiktok_enabled=true after first OAuth
  // to activate.
  try {
    const sb = createServiceClient();
    const { data: flag } = await sb
      .from("settings")
      .select("value")
      .eq("key", "tiktok_enabled")
      .maybeSingle();
    if (flag?.value !== "true") {
      return NextResponse.json({ skipped: "tiktok_disabled_flag_off" });
    }
  } catch {
    // If settings lookup fails, fall through rather than block silently.
  }

  try {
    return await _impl();
  } catch (e: any) {
    await sendTelegram(
      `⚠️ <b>TikTok mirror crashed</b>\n<code>${(e?.message ?? "unknown").slice(0, 400)}</code>`,
    ).catch(() => {});
    return NextResponse.json({ error: e?.message ?? "unknown" }, { status: 500 });
  }
}

export async function GET() {
  return observeCron("tiktok-mirror", () => _observedImpl());
}

