interface ClassifyRequest {
  messageId: string;
  from: string;
  subject: string;
  body: string;
  headers?: Record<string, string>;
}

interface ClassifyResult {
  classification: "HOT" | "WARM" | "COLD" | "NEUTRAL";
  reason: string;
  suggested_response: string;
}

const CLASSIFICATION_PROMPT = `You are an AI assistant for George Yachts, a luxury yacht brokerage. Classify the following email reply based on the sender's level of interest in partnership or yacht services.

CLASSIFICATION RULES:
- HOT: Sender explicitly wants to proceed, book a call, sign a partnership, or make a purchase decision. Shows strong urgency.
- WARM: Sender is interested, asking questions, requesting more info, or engaging positively but not yet committing.
- COLD: Sender is politely declining, asking to be removed, saying not interested, or giving a vague non-committal response.
- NEUTRAL: Auto-replies, out-of-office messages, newsletters, or messages unrelated to business.

Respond ONLY with valid JSON in this exact format:
{
  "classification": "HOT" | "WARM" | "COLD" | "NEUTRAL",
  "reason": "Brief explanation of why this classification was chosen",
  "suggested_response": "A short suggested reply George could send back"
}

EMAIL:
From: {FROM}
Subject: {SUBJECT}
Body:
{BODY}`;

async function classifyWithAI(email: ClassifyRequest): Promise<ClassifyResult> {
  const prompt = CLASSIFICATION_PROMPT
    .replace("{FROM}", email.from)
    .replace("{SUBJECT}", email.subject)
    .replace("{BODY}", email.body.slice(0, 3000)); // Limit body length

  const content = await aiChat(
    "You classify emails for a luxury yacht brokerage. Respond only with valid JSON.",
    prompt
  );

  // Extract JSON from response. Be forgiving: on any parse failure, fall
  // back to NEUTRAL so the caller doesn't 500 (which previously caused
  // the 5-min poll to hammer the same message forever).
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    return {
      classification: "NEUTRAL",
      reason: "AI returned non-JSON content — defaulted to NEUTRAL",
      suggested_response: "",
    };
  }
  try {
    return JSON.parse(jsonMatch[0]) as ClassifyResult;
  } catch {
    return {
      classification: "NEUTRAL",
      reason: "AI JSON parse failed — defaulted to NEUTRAL",
      suggested_response: "",
    };
  }
}

export async function POST(request: NextRequest) {
  try {
    const { messageId, from, subject, body, headers }: ClassifyRequest =
      await request.json();

    if (!messageId || !from) {
      return NextResponse.json(
        { error: "Missing required fields: messageId, from" },
        { status: 400 }
      );
    }

    const sb = createServiceClient();

    // Check if already classified
    const { data: existing } = await sb
      .from("email_classifications")
      .select("*")
      .eq("message_id", messageId)
      .single();

    if (existing) {
      return NextResponse.json(existing);
    }

    // Short-circuit auto-replies / out-of-office BEFORE spending AI credits
    // or touching pipeline stages. The follow-up sequence must continue
    // as if this email had never arrived.
    const autoCheck = detectAutoReply(subject, body, headers);
    if (autoCheck.isAutoReply) {
      const neutralResult: ClassifyResult = {
        classification: "NEUTRAL",
        reason: `Auto-reply detected (${autoCheck.reason}) — follow-up sequence will continue.`,
        suggested_response: "",
      };

      await sb.from("email_classifications").upsert({
        message_id: messageId,
        contact_id: null,
        classification: neutralResult.classification,
        reason: neutralResult.reason,
        suggested_response: neutralResult.suggested_response,
      });

      return NextResponse.json(neutralResult);
    }

    // Classify with AI
    const result = await classifyWithAI({ messageId, from, subject, body });

    // Extract sender email
    const emailMatch = from.match(/<([^>]+)>/) ?? [null, from];
    const senderEmail = (emailMatch[1] ?? "").toLowerCase().trim();

    // Try to find matching contact
    let contactId: string | null = null;
    if (senderEmail) {
      const { data: contact } = await sb
        .from("contacts")
        .select("id")
        .ilike("email", senderEmail)
        .single();
      contactId = contact?.id ?? null;
    }

    // Save classification
    await sb.from("email_classifications").upsert({
      message_id: messageId,
      contact_id: contactId,
      classification: result.classification,
      reason: result.reason,
      suggested_response: result.suggested_response,
    });

    // Send Telegram alert + in-app notification for HOT/WARM leads
    if (result.classification === "HOT" || result.classification === "WARM") {
      const emoji = result.classification === "HOT" ? "🔴" : "🟡";
      const senderName = from.replace(/<.*>/, "").trim() || senderEmail;
      await sendTelegram(
        `${emoji} <b>${result.classification} Lead Reply</b>\n` +
          `From: ${senderName}\n` +
          `Subject: ${subject}\n` +
          `Reason: ${result.reason}`
      );

      await createNotification(sb, {
        type: "reply",
        title: `${result.classification} reply from ${senderName}`,
        description: subject || result.reason,
        link: contactId ? `/dashboard/contacts/${contactId}` : "/dashboard/email",
        contact_id: contactId ?? null,
      });
    }

    // Update contact pipeline stage if matched
    if (contactId && (result.classification === "HOT" || result.classification === "WARM")) {
      const stageName = result.classification === "HOT" ? "Hot" : "Warm";
      const { data: stage } = await sb
        .from("pipeline_stages")
        .select("id")
        .eq("name", stageName)
        .single();

      if (stage) {
        await sb
          .from("contacts")
          .update({
            pipeline_stage_id: stage.id,
            last_activity_at: new Date().toISOString(),
          })
          .eq("id", contactId);

        await sb.from("activities").insert({
          contact_id: contactId,
          type: "ai_classification",
          description: `Email classified as ${result.classification}: ${result.reason}`,
          metadata: {
            message_id: messageId,
            classification: result.classification,
          },
        });
      }
    }

    return NextResponse.json(result);
  } catch (err) {
    console.error("[Gmail Classify] Error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";

interface GmailHeader {
  name: string;
  value: string;
}

interface GmailPart {
  mimeType: string;
  filename?: string;
  body?: { data?: string; size?: number; attachmentId?: string };
  parts?: GmailPart[];
  headers?: GmailHeader[];
}

interface GmailFullMessage {
  id: string;
  threadId: string;
  labelIds?: string[];
  snippet: string;
  internalDate: string;
  payload: GmailPart;
}

function getHeader(headers: GmailHeader[], name: string): string {
  return headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ?? "";
}

function decodeBase64Url(data: string): string {
  const base64 = data.replace(/-/g, "+").replace(/_/g, "/");
  return Buffer.from(base64, "base64").toString("utf-8");
}

function extractBody(part: GmailPart): { html: string; text: string } {
  let html = "";
  let text = "";

  if (part.mimeType === "text/html" && part.body?.data) {
    html = decodeBase64Url(part.body.data);
  } else if (part.mimeType === "text/plain" && part.body?.data) {
    text = decodeBase64Url(part.body.data);
  }

  if (part.parts) {
    for (const sub of part.parts) {
      const result = extractBody(sub);
      if (result.html) html = result.html;
      if (result.text && !text) text = result.text;
    }
  }

  return { html, text };
}

function extractAttachments(part: GmailPart, list: { filename: string; mimeType: string; size: number }[] = []) {
  if (part.filename && part.body?.attachmentId) {
    list.push({
      filename: part.filename,
      mimeType: part.mimeType,
      size: part.body.size ?? 0,
    });
  }
  if (part.parts) {
    for (const sub of part.parts) {
      extractAttachments(sub, list);
    }
  }
  return list;
}

/** Strip <script> tags and on* event handlers for XSS prevention */
function sanitizeHtml(html: string): string {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<script[^>]*>/gi, "")
    .replace(/\son\w+\s*=\s*"[^"]*"/gi, "")
    .replace(/\son\w+\s*=\s*'[^']*'/gi, "")
    .replace(/\son\w+\s*=[^\s>]*/gi, "")
    .replace(/javascript\s*:/gi, "blocked:");
}

export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params;

  try {
    const res = await gmailFetch(`/messages/${id}?format=full`);
    if (!res.ok) {
      const text = await res.text();
      return NextResponse.json({ error: text }, { status: res.status });
    }

    const msg: GmailFullMessage = await res.json();
    const headers = msg.payload.headers ?? [];
    const { html, text } = extractBody(msg.payload);
    const attachments = extractAttachments(msg.payload);

    return NextResponse.json({
      id: msg.id,
      threadId: msg.threadId,
      from: getHeader(headers, "From"),
      to: getHeader(headers, "To"),
      subject: getHeader(headers, "Subject"),
      date: getHeader(headers, "Date") || new Date(parseInt(msg.internalDate)).toISOString(),
      labelIds: msg.labelIds ?? [],
      isStarred: (msg.labelIds ?? []).includes("STARRED"),
      body: html ? sanitizeHtml(html) : text,
      bodyType: html ? "html" : "text",
      attachments,
    });
  } catch (err) {
    console.error("[Gmail] Get message error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";

interface GmailHeader {
  name: string;
  value: string;
}

interface GmailMessagePart {
  headers?: GmailHeader[];
}

interface GmailMessage {
  id: string;
  threadId: string;
  labelIds?: string[];
  snippet: string;
  internalDate: string;
  payload?: GmailMessagePart;
}

function getHeader(headers: GmailHeader[], name: string): string {
  return headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ?? "";
}

export async function GET(request: NextRequest) {
  const { searchParams } = request.nextUrl;
  const q = searchParams.get("q") ?? "in:inbox";
  const maxResults = searchParams.get("maxResults") ?? "20";
  const pageToken = searchParams.get("pageToken") ?? "";

  try {
    // List message IDs
    const listParams = new URLSearchParams({
      q,
      maxResults,
      ...(pageToken ? { pageToken } : {}),
    });

    const listRes = await gmailFetch(`/messages?${listParams.toString()}`);
    if (!listRes.ok) {
      const text = await listRes.text();
      return NextResponse.json({ error: text }, { status: listRes.status });
    }

    const listData = await listRes.json();
    const messageIds: { id: string }[] = listData.messages ?? [];
    const nextPageToken: string | undefined = listData.nextPageToken;

    if (messageIds.length === 0) {
      return NextResponse.json({ messages: [], nextPageToken: null });
    }

    // Fetch each message in metadata format
    const messages = await Promise.all(
      messageIds.map(async ({ id }) => {
        const res = await gmailFetch(`/messages/${id}?format=metadata&metadataHeaders=From&metadataHeaders=To&metadataHeaders=Subject&metadataHeaders=Date`);
        if (!res.ok) return null;
        const msg: GmailMessage = await res.json();
        const headers = msg.payload?.headers ?? [];

        return {
          id: msg.id,
          threadId: msg.threadId,
          from: getHeader(headers, "From"),
          to: getHeader(headers, "To"),
          subject: getHeader(headers, "Subject"),
          snippet: msg.snippet,
          date: getHeader(headers, "Date") || new Date(parseInt(msg.internalDate)).toISOString(),
          labelIds: msg.labelIds ?? [],
          isStarred: (msg.labelIds ?? []).includes("STARRED"),
        };
      })
    );

    return NextResponse.json({
      messages: messages.filter(Boolean),
      nextPageToken: nextPageToken ?? null,
    });
  } catch (err) {
    console.error("[Gmail] List messages error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

// Gmail send — outbound email + activity logging.
//
// Every send writes an `email_sent` activity against the matching
// contact (looked up by `to` email, case-insensitive). Without this
// log the cockpit cannot tell when George last reached out, which
// breaks the Inbox Brain pillar (gap, owed-reply, stage inference).
//
// If no contact matches the recipient, we silently skip the activity
// log — outbound to unknown addresses is allowed (e.g. one-off
// admin emails). The send itself never fails because of CRM lookup.

import { NextRequest, NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";
import { createServiceClient } from "@/lib/supabase-server";
import { refreshContactInbox } from "@/lib/inbox-analyzer";
import { extractCommitments } from "@/lib/commitment-extractor";

function createRawEmail(
  to: string,
  subject: string,
  body: string,
  threadId?: string,
  inReplyTo?: string
): string {
  const boundary = "boundary_" + Date.now();
  const lines: string[] = [
    `To: ${to}`,
    `Subject: ${subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: multipart/alternative; boundary="${boundary}"`,
  ];

  if (inReplyTo) {
    lines.push(`In-Reply-To: ${inReplyTo}`);
    lines.push(`References: ${inReplyTo}`);
  }

  lines.push("", `--${boundary}`);
  lines.push("Content-Type: text/plain; charset=UTF-8", "", body);
  lines.push(
    `--${boundary}`,
    "Content-Type: text/html; charset=UTF-8",
    "",
    body.replace(/\n/g, "<br>")
  );
  lines.push(`--${boundary}--`);

  void threadId;

  const raw = lines.join("\r\n");
  return Buffer.from(raw).toString("base64url");
}

function extractRecipientEmail(to: string): string | null {
  const m = to.match(/<([^>]+)>/);
  const candidate = (m ? m[1] : to).trim().toLowerCase();
  return /.+@.+\..+/.test(candidate) ? candidate : null;
}

async function logOutboundActivity(args: {
  to: string;
  subject: string;
  body: string;
  threadId?: string;
  messageId: string;
}): Promise<void> {
  const recipient = extractRecipientEmail(args.to);
  if (!recipient) return;

  const sb = createServiceClient();
  const { data: contact } = await sb
    .from("contacts")
    .select("id")
    .ilike("email", recipient)
    .maybeSingle();

  if (!contact?.id) return;

  const now = new Date().toISOString();
  await sb.from("activities").insert({
    contact_id: contact.id,
    type: "email_sent",
    description: `Sent — ${args.subject}`.slice(0, 500),
    metadata: {
      message_id: args.messageId,
      thread_id: args.threadId ?? null,
      subject: args.subject,
      snippet: args.body.slice(0, 300),
      direction: "outbound",
    },
  });
  await sb
    .from("contacts")
    .update({ last_activity_at: now })
    .eq("id", contact.id);

  // Pillar 1 — recompute inbox state so the cockpit immediately
  // reflects the new outbound message (e.g. moves contact out of
  // owed_reply into awaiting_reply).
  await refreshContactInbox(sb, contact.id);

  // Pillar 4 (Sprint 2.3) — scan the outbound for commitments and
  // persist any found. Brief calls this "the most differentiated
  // feature in this entire system". 5-min SLA: extraction happens
  // on every send so the morning surface includes today's promises.
  try {
    const commitments = await extractCommitments(
      args.body,
      new Date().toISOString().slice(0, 10),
    );
    if (commitments.length > 0) {
      const rows = commitments.map((c) => ({
        contact_id: contact.id,
        thread_id: args.threadId ?? null,
        source_message_id: args.messageId,
        source_sent_at: now,
        commitment_text: c.commitment_text,
        commitment_summary: c.commitment_summary,
        deadline_date: c.deadline_date,
        deadline_phrase: c.deadline_phrase,
        confidence: c.confidence,
      }));
      await sb.from("commitments").insert(rows);
    }
  } catch (err) {
    console.error("[gmail/send] commitment extraction failed:", err);
  }
}

export async function POST(request: NextRequest) {
  try {
    const { to, subject, body, threadId, inReplyTo } = await request.json();

    if (!to || !body) {
      return NextResponse.json(
        { error: "Missing required fields: to, body" },
        { status: 400 }
      );
    }

    const raw = createRawEmail(to, subject ?? "", body, threadId, inReplyTo);

    const sendBody: Record<string, string> = { raw };
    if (threadId) {
      sendBody.threadId = threadId;
    }

    const res = await gmailFetch("/messages/send", {
      method: "POST",
      body: JSON.stringify(sendBody),
    });

    if (!res.ok) {
      const text = await res.text();
      return NextResponse.json({ error: text }, { status: res.status });
    }

    const data = await res.json();

    // Best-effort activity log — never fail the send because of it.
    logOutboundActivity({
      to,
      subject: subject ?? "",
      body,
      threadId,
      messageId: data.id,
    }).catch((err) => {
      console.error("[Gmail] outbound activity log failed:", err);
    });

    return NextResponse.json({ success: true, messageId: data.id });
  } catch (err) {
    console.error("[Gmail] Send error:", err);
    return NextResponse.json(
      { error: err instanceof Error ? err.message : "Unknown error" },
      { status: 500 }
    );
  }
}

// /api/gmail/star — toggle Gmail star for a message AND keep CRM in sync.
//
// 2026-05-01 — promoted from "find existing contact and bump to Warm"
// to "the canonical path for a contact landing in CRM". After the
// non-starred purge, Contacts is starred-only by design — the act of
// starring an email IS the act of saying "this is a real relationship
// I want to track". So:
//
//   • If the sender already exists → flip inbox_starred=true, bump to Warm
//   • If sender doesn't exist     → create the contact with AI-inferred
//                                    contact_type, inbox_starred=true,
//                                    source='gmail_star', and stamp the
//                                    starred message id on the contact
//
// AI categorization runs on email-domain + subject + body signature.
// Conservative fallback: anything we can't classify high-confidence
// gets contact_type=null so George can fix it from the CRM.

import { NextRequest, NextResponse } from "next/server";
import { gmailFetch } from "@/lib/google-api";
import { createServiceClient } from "@/lib/supabase-server";
import { aiChat } from "@/lib/ai";
import {
  parseFromHeader,
  companyFromEmail,
  parseSignature,
} from "@/lib/email-signature-parser";

type Header = { name: string; value: string };

function getHeader(headers: Header[] | undefined, name: string): string {
  if (!headers) return "";
  return (
    headers.find((h) => h.name.toLowerCase() === name.toLowerCase())?.value ??
    ""
  );
}

function decodeBase64Url(s: string): string {
  try {
    const b64 = s.replace(/-/g, "+").replace(/_/g, "/");
    return Buffer.from(b64, "base64").toString("utf-8");
  } catch {
    return "";
  }
}

// Recursively pull the first text/plain body from a Gmail payload
function extractTextBody(payload: {
  mimeType?: string;
  body?: { data?: string };
  parts?: Array<{
    mimeType?: string;
    body?: { data?: string };
    parts?: Array<unknown>;
  }>;
}): string {
  if (payload.mimeType === "text/plain" && payload.body?.data) {
    return decodeBase64Url(payload.body.data);
  }
  for (const part of payload.parts ?? []) {
    if (
      typeof part === "object" &&
      part &&
      "mimeType" in part &&
      "body" in part
    ) {
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const text = extractTextBody(part as any);
      if (text) return text;
    }
  }
  return "";
}

const VALID_CONTACT_TYPES = [
  "CENTRAL_AGENT",
  "B2B_PARTNER",
  "BROKER_CLIENT",
  "DIRECT_CLIENT",
  "PRESS_MEDIA",
  "INDUSTRY",
  "OUTREACH_LEAD",
] as const;

type AiClassifyResult = {
  type: (typeof VALID_CONTACT_TYPES)[number] | null;
  confidence: number;
  reason: string;
};

async function aiCategorizeContact(input: {
  email: string;
  name: string | null;
  company: string | null;
  subject: string;
  signatureTitle: string | null;
  bodySnippet: string;
}): Promise<AiClassifyResult> {
  const prompt = `You are categorizing a single inbound email contact for a Greek luxury yacht charter brokerage (George Yachts). Return JSON only.

INPUT:
  Email:        ${input.email}
  Name:         ${input.name ?? "(unknown)"}
  Company:      ${input.company ?? "(personal email or unknown)"}
  Subject:      ${input.subject}
  Title (sig):  ${input.signatureTitle ?? "(none parsed)"}
  Body snippet: ${input.bodySnippet.slice(0, 300)}

CATEGORIES (pick exactly one):
  CENTRAL_AGENT    — yacht broker representing one or more vessels (Burgess, Edmiston, Camper & Nicholsons, IYC, Fraser, Northrop & Johnson, etc). Speaks of "my fleet", "my listings", "broker of M/Y X".
  B2B_PARTNER      — luxury travel/concierge/hotel/destination platform sending or accepting referrals. Travel agencies that PASS clients to us count here.
  BROKER_CLIENT    — a retail yacht broker booking on behalf of THEIR client. Distinct from CENTRAL_AGENT (who owns inventory).
  DIRECT_CLIENT    — end customer chartering for themselves (private email common, talks about a specific trip/dates/family).
  PRESS_MEDIA      — journalist, magazine, blog, podcast, content creator.
  INDUSTRY         — captain, crew agency, supplier, marina, port authority, shipyard.
  OUTREACH_LEAD    — fallback when nothing else fits.

RULES:
  - Personal-email domains (gmail/yahoo/hotmail/outlook/icloud) → likely DIRECT_CLIENT unless the body strongly suggests trade.
  - Domains like burgessyachts.com / edmiston.com / camperandnicholsons.com / fraseryachts.com / iyc.com → CENTRAL_AGENT.
  - Domains like virtuoso.com / fora.travel / altour.com / protravelinc.com / mohg.com → B2B_PARTNER.
  - "broker representing" / "my client" → BROKER_CLIENT.
  - Press hints: byline, "writing a piece", magazine name → PRESS_MEDIA.

Return strictly:
  {"type":"<ONE_OF_THE_7>","confidence":0.0-1.0,"reason":"<one short sentence>"}`;

  try {
    const raw = await aiChat(
      "You are a fast, terse classifier. Return JSON only, no markdown.",
      prompt,
      { maxTokens: 200, temperature: 0.2 },
    );
    // Strip code-fences if AI wrapped them anyway
    const cleaned = raw
      .replace(/```json\s*/gi, "")
      .replace(/```\s*$/g, "")
      .trim();
    const parsed = JSON.parse(cleaned);
    if (
      typeof parsed.type === "string" &&
      VALID_CONTACT_TYPES.includes(parsed.type)
    ) {
      return {
        type: parsed.type,
        confidence: Number(parsed.confidence) || 0.5,
        reason: typeof parsed.reason === "string" ? parsed.reason : "",
      };
    }
  } catch (e) {
    console.error("[Gmail Star] AI categorize error:", e);
  }
  return { type: null, confidence: 0, reason: "ai-classify-failed" };
}

export async function POST(request: NextRequest) {
  try {
    const { messageId, starred } = await request.json();

    if (!messageId || typeof starred !== "boolean") {
      return NextResponse.json(
        { error: "Missing required fields: messageId, starred (boolean)" },
        { status: 400 },
      );
    }

    // 1. Toggle the Gmail star itself.
    const body = starred
      ? { addLabelIds: ["STARRED"], removeLabelIds: [] }
      : { addLabelIds: [], removeLabelIds: ["STARRED"] };

    const res = await gmailFetch(`/messages/${messageId}/modify`, {
      method: "POST",
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text();
      return NextResponse.json({ error: text }, { status: res.status });
    }

    // 2. CRM-side reflection. Only on STAR (un-star is handled by the
    //    nightly inbox-star-sync cron — it would be premature to wipe
    //    inbox_starred=false here in case the user mis-clicks).
    let crmAction: string | null = null;
    let crmContactId: string | null = null;

    if (starred) {
      try {
        // Pull full message so we have headers + body for AI classify.
        const msgRes = await gmailFetch(
          `/messages/${messageId}?format=full`,
        );
        if (msgRes.ok) {
          const msg = (await msgRes.json()) as {
            id: string;
            threadId?: string;
            payload?: {
              headers?: Header[];
              mimeType?: string;
              body?: { data?: string };
              parts?: Array<unknown>;
            };
          };
          const headers = msg.payload?.headers ?? [];
          const fromHeader = getHeader(headers, "From");
          const subject = getHeader(headers, "Subject");
