// 2026 industry benchmarks (52M+ posts analyzed). day = 0..6 (Sun=0).
// Each entry is one recommended slot with an explanation that's surfaced
// to George in the dashboard tooltip.
const INDUSTRY_WINDOWS = [
  {
    day: 2, // Tue
