// ─── Helpers ─────────────────────────────────────────────────────────────────

function startOfWeek(d: Date): Date {
  const result = new Date(d);
  const day = result.getDay();
  result.setDate(result.getDate() - day);
  result.setHours(0, 0, 0, 0);
  return result;
}

function startOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

function addDays(d: Date, n: number): Date {
  const result = new Date(d);
  result.setDate(result.getDate() + n);
  return result;
}

function isSameDay(a: Date, b: Date): boolean {
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}

function formatTime(dateStr: string): string {
  try {
    const d = new Date(dateStr);
    return d.toLocaleTimeString("en-US", {
      hour: "numeric",
      minute: "2-digit",
      hour12: true,
    });
  } catch {
    return "";
  }
}

function dayLabel(date: Date, today: Date): string {
  const tomorrow = addDays(today, 1);
  if (isSameDay(date, today)) return "Today";
  if (isSameDay(date, tomorrow)) return "Tomorrow";
  return date.toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "short",
  });
}

function formatCountdown(target: Date, now: Date): string {
  const diff = target.getTime() - now.getTime();
  if (diff < 0) return "started";
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return "any moment";
  if (mins < 60) return `in ${mins}m`;
  const hours = Math.floor(mins / 60);
  if (hours < 24) {
    const remMins = mins - hours * 60;
    return remMins > 0 ? `in ${hours}h ${remMins}m` : `in ${hours}h`;
  }
  const days = Math.floor(hours / 24);
  return days === 1 ? "tomorrow" : `in ${days} days`;
}

function getEventColor(event: CalendarEvent): {
  bg: string;
  border: string;
  text: string;
} {
  const s = (event.summary ?? "").toLowerCase();
  if (s.includes("charter") || s.includes("yacht") || s.includes("showing")) {
    return {
      bg: "bg-gold/20",
      border: "border-gold/40",
      text: "text-gold",
    };
  }
  if (s.includes("meeting") || s.includes("call") || s.includes("demo")) {
    return {
      bg: "bg-blue-500/20",
      border: "border-blue-500/40",
      text: "text-blue-400",
    };
  }
  return {
    bg: "bg-gray-500/15",
    border: "border-gray-500/30",
    text: "text-ivory/70",
  };
}

