// @ts-nocheck
/**
 * Shared brand-voice guardrails for every AI-generated output:
 * fleet captions, comment replies, DM replies, story copy, anything
 * else that writes as "George Yachts". One file, one rulebook.
 *
 * Introduced 2026-04-20 after George flagged filler phrases like
 * "unparalleled backdrop" and "unforgettable moments" slipping into
 * an auto comment reply. Those phrases weaken UHNW credibility —
 * forbidding them everywhere, not just in fleet captions.
 *
 * Pattern:
 *   1. Inject VOICE_GUARDRAILS into every AI system prompt (prepended
 *      to the caller's specific instructions).
 *   2. Post-generation, call detectBannedPhrases() on the output; log
 *      a Telegram warning if anything slipped past the model. Do NOT
 *      mangle the output — just flag for improvement.
 */

// Lowercase-only substring matches. Order doesn't matter.
export const BANNED_FILLER_PHRASES = [
  // Empty luxury superlatives (George 2026-04-20)
  "exceptional",
  "unparalleled",
  "renowned",
  "pedigree",
  "high standards",
  "incredible",
  "stunning",
  "elevated",
  "iconic",
  "unforgettable",
  // Tech / startup vocabulary (register violations)
  "primed for discovery",
  "primed",
  "unlocks",
  "leverages",
  // "journey" only when used as metaphor — tricky to detect perfectly,
  // but prompt-level instruction is stronger than post-check
  // Pricing apologetics (was previously in fleet-caption only)
  "budget-conscious",
  "surprisingly accessible",
  "affordable luxury",
  "smart investment",
  "smartly priced",
  "value-conscious",
  "price-sensitive",
  // Roberto 2026-04-22 additions — cheap-Instagram voice
  "amazing",
  "moment stands out",
  "there's a moment",
  "behind the scenes",
  "vibes",
  "awaits",
  "into perspective",
  "the sea has a way",
  "glamorous spreadsheets",
  // Fabricated client stories = brand risk (UHNW NDA culture)
  "couple from dubai",
  "couple from dallas",
  "family from",
  "i had the pleasure of assisting",
  "last season, i had",
  "last season i had",
];

// Allowed emoji whitelist — strict 4. Everything else forbidden.
// Applied to BOTH fleet captions and comment replies (webhook).
export const ALLOWED_EMOJI = ["⛵", "🌊", "⚓", "✨"];

/**
 * Block of voice rules prepended to every AI system prompt. Writes
 * as a single paragraph so it slots into existing prompts cleanly.
 */
export const VOICE_GUARDRAILS = `BRAND VOICE RULES (mandatory — these apply to every AI output for George Yachts):

PRONOUN: 'we' / 'our team'. NEVER 'I'. NEVER claim personal years of experience.

REGISTER: Write in the voice of Condé Nast Traveler or Robb Report. UHNW audience (net worth $50M+) — discerning, skeptical of hype. Greek hospitality (filotimo) at the core: quiet luxury, restraint, service through presence not performance. Avoid tech/startup vocabulary like "primed", "unlocks", "leverages", "platform", or "journey" used as metaphor.

CONCRETE > ABSTRACT. Empty luxury superlatives weaken credibility and are BANNED: "exceptional", "unparalleled", "renowned", "pedigree", "high standards", "incredible", "stunning", "elevated", "iconic", "unforgettable", "amazing", "primed for discovery", "moment stands out", "there's a moment", "behind the scenes", "vibes", "awaits", "into perspective", "the sea has a way". Replace each with a specific concrete detail — instead of "exceptional experience", write "breakfast on deck as the sun rises behind Hydra".

ONE IDEA PER POST. A caption has exactly one sensory detail + one clear offer (the yacht, the route, the feature). No list of three things. No meta-narration about the broker's life.

CLIENT PRIVACY (MYBA CONFIDENTIALITY): Never fabricate or reference specific past clients. BANNED: "couple from Dubai/Dallas/anywhere", "family from X", "last season I had the pleasure of", "I helped a family", anything that implies a real private charter. UHNW clients' NDAs forbid this. If a general anecdote is needed, use aggregate framing: "agencies we work with tell us…" not "a client told me…".

CTA: Single soft CTA at the end. Use: "Charter inquiries → link in bio", or "Save this for your summer planning", or a MYBA-appropriate invitation. Never "Book now", never "Don't miss out", never "Limited time".

PRICING: Never apologize for the price. Banned phrases: "budget-conscious", "surprisingly accessible", "affordable luxury", "smart investment", "smartly priced", "value-conscious", "price-sensitive". Quote the rate straight, once, in passing. UHNW guests do not need reassurance they can afford the boat.

EMOJI: NO emoji anywhere inside the caption/reply body. At most ONE optional emoji at the very end, chosen only from: ⛵ 🌊 ⚓ ✨. No laughing, no fire, no hearts, no 100, no party. Anything else is a violation.`;

/**
 * Detect banned filler phrases in generated text. Returns lowercased
 * matches for logging. Case-insensitive substring match.
 */
export function detectBannedPhrases(text: string): string[] {
  if (!text || typeof text !== "string") return [];
  const low = text.toLowerCase();
  const hits: string[] = [];
  for (const phrase of BANNED_FILLER_PHRASES) {
    if (low.includes(phrase)) hits.push(phrase);
  }
  return hits;
}

/**
 * Detect emoji in body that are NOT in the allow-list, or ANY emoji
 * that is not at the very end. Returns array of offending tokens.
 */
export function detectEmojiViolations(text: string): string[] {
  if (!text) return [];
  // Emoji regex: basic coverage of common emoji unicode blocks.
  const emojiRegex =
    /(\p{Extended_Pictographic}(?:\u200D\p{Extended_Pictographic})*)/gu;
  const matches = Array.from(text.matchAll(emojiRegex));
  if (matches.length === 0) return [];

  const violations: string[] = [];
  // Check last emoji: is it at the end of the string? Is it whitelisted?
  const lastMatch = matches[matches.length - 1];
  const trailingText = text.slice((lastMatch.index ?? 0) + lastMatch[0].length).trim();
  const lastAtEnd = trailingText.length === 0;
  const lastAllowed = ALLOWED_EMOJI.includes(lastMatch[0]);

  // All emoji except possibly the last should be violations.
  for (let i = 0; i < matches.length - 1; i++) {
    violations.push(matches[i][0]);
  }
  // Last emoji: violation unless it's both whitelisted AND at the end.
  if (!lastAtEnd || !lastAllowed) {
    violations.push(lastMatch[0]);
  }
  return violations;
}

import OpenAI from "openai";

// Universal AI client — works with Gemini (free), OpenAI, or Anthropic
// Change provider by updating env vars only — zero code changes
const ai = new OpenAI({
  apiKey: process.env.AI_API_KEY || "",
  baseURL: process.env.AI_BASE_URL || "https://generativelanguage.googleapis.com/v1beta/openai",
});

const MODEL = process.env.AI_MODEL || "gemini-2.5-flash";

export async function aiChat(
  systemPrompt: string,
  userMessage: string,
  options?: { maxTokens?: number; temperature?: number }
): Promise<string> {
  if (!process.env.AI_API_KEY) {
    throw new Error("AI_API_KEY not configured");
  }

  const response = await ai.chat.completions.create({
    model: MODEL,
    messages: [
      { role: "system", content: systemPrompt },
      { role: "user", content: userMessage },
    ],
    temperature: options?.temperature ?? 0.7,
    max_tokens: options?.maxTokens ?? 2000,
  });

  return response.choices[0]?.message?.content || "";
}

export async function aiStream(
  systemPrompt: string,
  messages: Array<{ role: "user" | "assistant"; content: string }>
): Promise<ReadableStream> {
  if (!process.env.AI_API_KEY) {
    throw new Error("AI_API_KEY not configured");
  }

  const response = await ai.chat.completions.create({
    model: MODEL,
    messages: [
      { role: "system", content: systemPrompt },
      ...messages,
    ],
    stream: true,
    temperature: 0.7,
    max_tokens: 2000,
  });

  const encoder = new TextEncoder();

  return new ReadableStream({
    async start(controller) {
      try {
        for await (const chunk of response) {
          const text = chunk.choices[0]?.delta?.content || "";
          if (text) {
            controller.enqueue(encoder.encode(text));
          }
        }
        controller.close();
      } catch {
        controller.close();
      }
    },
  });
}

export { MODEL };

/**
 * Deterministic auto-reply / out-of-office detection.
 *
 * Runs BEFORE any AI classification so that follow-up sequences are never
 * stopped by an automatic response. If this returns true, the caller should
 * treat the email as "no real reply yet" and keep the sequence active.
 *
 * Detection order (fastest → slowest):
 *   1. RFC-standard auto-response headers
 *   2. Subject-line phrases (most auto-replies give themselves away here)
 *   3. Body phrases (fallback for poorly-configured OOO systems)
 */

const AUTO_REPLY_HEADERS = [
  "auto-submitted",
  "x-autoreply",
  "x-autorespond",
  "x-autoresponder",
  "x-auto-response-suppress",
  "precedence", // "auto_reply" / "bulk" / "list"
];

const AUTO_REPLY_SUBJECT_PATTERNS = [
  /\bauto(?:matic)?[-\s]?reply\b/i,
  /\bauto[-\s]?responder\b/i,
  /\bout\s+of\s+(?:the\s+)?office\b/i,
  /\bo{2,}o\b/i, // "OOO"
  /\bi\s+am\s+(?:currently\s+)?out\b/i,
  /\bi['`’]?m\s+(?:currently\s+)?out\b/i,
  /\baway\s+from\s+(?:the\s+)?office\b/i,
  /\bon\s+(?:vacation|holiday|leave|annual\s+leave)\b/i,
  /\bcurrently\s+unavailable\b/i,
  /\bwill\s+be\s+back\b/i,
  /\blimited\s+(?:access|connectivity)\b/i,
  /\bdelayed\s+(?:response|reply)\b/i,
  /\bautomatisch(e)?\s+antwort\b/i, // German
  /\brisposta\s+automatica\b/i, // Italian
  /\bauto[-\s]?respuesta\b/i, // Spanish
];

const AUTO_REPLY_BODY_PATTERNS = [
  /\bi\s+am\s+(?:currently\s+)?(?:out\s+of\s+(?:the\s+)?office|on\s+(?:vacation|holiday|annual\s+leave))\b/i,
  /\bthank\s+you\s+for\s+your\s+(?:email|message)[^.]*(?:i['`’]?m\s+(?:currently\s+)?(?:out|away)|out\s+of\s+(?:the\s+)?office)/i,
  /\bi\s+will\s+(?:be\s+)?(?:back|return(?:ing)?)\s+on\b/i,
  /\bi\s+will\s+respond\s+(?:to\s+your\s+email\s+)?(?:when|upon|as\s+soon\s+as)\b/i,
  /\bfor\s+urgent\s+matters[,.]?\s+(?:please\s+)?contact\b/i,
  /\bthis\s+is\s+an\s+automated\s+(?:reply|response|message)\b/i,
];

export interface AutoReplyCheck {
  isAutoReply: boolean;
  reason: string;
}

/**
 * Check if an email is an auto-reply / out-of-office.
 *
 * @param subject Email subject line
 * @param body    Plain-text email body (HTML stripped if possible)
 * @param headers Optional map of lowercase header name → value
 */
export function detectAutoReply(
  subject: string | null | undefined,
  body: string | null | undefined,
  headers?: Record<string, string>
): AutoReplyCheck {
  // 1. Headers — the authoritative signal
  if (headers) {
    for (const name of AUTO_REPLY_HEADERS) {
      const value = headers[name]?.toLowerCase();
      if (!value) continue;
      if (name === "auto-submitted" && value !== "no") {
        return { isAutoReply: true, reason: `Auto-Submitted: ${value}` };
      }
      if (name === "precedence" && /\b(auto_reply|bulk|list|junk)\b/.test(value)) {
        return { isAutoReply: true, reason: `Precedence: ${value}` };
      }
      if (name.startsWith("x-auto")) {
        return { isAutoReply: true, reason: `${name}: ${value}` };
      }
    }
  }

  // 2. Subject
  const subj = (subject ?? "").trim();
  for (const pattern of AUTO_REPLY_SUBJECT_PATTERNS) {
    if (pattern.test(subj)) {
      return { isAutoReply: true, reason: `Subject matches ${pattern}` };
    }
  }

  // 3. Body — scan first 500 chars only (auto-replies front-load their message)
  const bodySnippet = (body ?? "").slice(0, 500);
  for (const pattern of AUTO_REPLY_BODY_PATTERNS) {
    if (pattern.test(bodySnippet)) {
      return { isAutoReply: true, reason: `Body matches ${pattern}` };
    }
  }

  return { isAutoReply: false, reason: "" };
}

// georgeyachts.com/blog article fetcher.
//
// Reads sitemap.xml to discover all /blog/* URLs, fetches the article
// HTML, extracts title + lead paragraphs + publish date. Used by the
// LinkedIn digest crons (Tue/Thu personal-profile draft + Friday
// Company Page amplify) to find articles that haven't been surfaced to
// LinkedIn yet.

const BLOG_ROOT = "https://georgeyachts.com";
const SITEMAP = `${BLOG_ROOT}/sitemap.xml`;

export type BlogArticle = {
  url: string;
  slug: string;
  title: string;
  leadParagraphs: string[];
  fullBody: string;
  publishedAt: string | null;
  coverImageUrl: string | null;
};

type SitemapEntry = {
  url: string;
  lastmod: string | null;
};

async function fetchSitemapBlogUrls(): Promise<SitemapEntry[]> {
  const res = await fetch(SITEMAP, {
    // Revalidate hourly — blog doesn't change faster than that.
    next: { revalidate: 3600 },
  });
  if (!res.ok) throw new Error(`sitemap ${SITEMAP} returned ${res.status}`);
  const xml = await res.text();
  const entries: SitemapEntry[] = [];
  const urlRegex = /<url>([\s\S]*?)<\/url>/g;
  let m;
  while ((m = urlRegex.exec(xml)) !== null) {
    const block = m[1];
    const locMatch = block.match(/<loc>([^<]+)<\/loc>/);
    const lastmodMatch = block.match(/<lastmod>([^<]+)<\/lastmod>/);
    if (!locMatch) continue;
    const url = locMatch[1].trim();
    if (!url.includes("/blog/")) continue;
    // Skip the /blog index itself
    if (url.replace(/\/$/, "").endsWith("/blog")) continue;
    entries.push({ url, lastmod: lastmodMatch?.[1]?.trim() ?? null });
  }
  return entries;
}

function parseArticleHtml(html: string, url: string): Omit<BlogArticle, "url" | "slug"> {
  // Title: prefer <h1>, fall back to <title>.
  const h1Match = html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/);
  const titleMatch = html.match(/<title>([^<]+)<\/title>/);
  const rawTitle = (h1Match?.[1] ?? titleMatch?.[1] ?? "").trim();
  const title = rawTitle
    .replace(/<[^>]+>/g, "")
    .replace(/\s*\|\s*George Yachts.*$/i, "")
    .trim();

  // Published date: look for <time datetime="...">, meta[name=date], or
  // the visible "Month Day, Year" pattern near the byline.
  const timeMatch = html.match(/<time[^>]*datetime=["']([^"']+)["']/);
  const metaDateMatch = html.match(
    /<meta[^>]+(?:property|name)=["'](?:article:published_time|date|publish_date)["'][^>]+content=["']([^"']+)["']/i,
  );
  const publishedAt = timeMatch?.[1] ?? metaDateMatch?.[1] ?? null;

  // Cover image: og:image.
  const ogImageMatch = html.match(
    /<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/,
  );
  const coverImageUrl = ogImageMatch?.[1] ?? null;

  // Body: grab <article> block if present, otherwise <main>, then strip
  // tags. Keep paragraph breaks.
  const articleBlockMatch =
    html.match(/<article[^>]*>([\s\S]*?)<\/article>/) ??
    html.match(/<main[^>]*>([\s\S]*?)<\/main>/);
  const articleHtml = articleBlockMatch?.[1] ?? html;
  const paragraphs = [
    ...articleHtml.matchAll(/<p[^>]*>([\s\S]*?)<\/p>/g),
  ]
    .map((m) => m[1].replace(/<[^>]+>/g, "").replace(/\s+/g, " ").trim())
    .filter((p) => p.length > 40); // drop nav crumbs

  const leadParagraphs = paragraphs.slice(0, 4);
  const fullBody = paragraphs.join("\n\n");

  return { title, leadParagraphs, fullBody, publishedAt, coverImageUrl };
}

export async function fetchArticle(url: string): Promise<BlogArticle> {
  const res = await fetch(url, { next: { revalidate: 3600 } });
  if (!res.ok) throw new Error(`${url} returned ${res.status}`);
  const html = await res.text();
  const parsed = parseArticleHtml(html, url);
  const slug = url.replace(/\/$/, "").split("/").pop() ?? "";
  return { url, slug, ...parsed };
}

export async function listBlogArticles(): Promise<BlogArticle[]> {
  const entries = await fetchSitemapBlogUrls();
  // Sort by lastmod descending (newest first), nulls last.
  entries.sort((a, b) => {
    if (!a.lastmod) return 1;
    if (!b.lastmod) return -1;
    return b.lastmod.localeCompare(a.lastmod);
  });
  // Only fetch the top 20 articles — the older ones aren't relevant for
  // "freshest article for LinkedIn" selection and saves bandwidth.
  const top = entries.slice(0, 20);
  const results: BlogArticle[] = [];
  for (const entry of top) {
    try {
      const article = await fetchArticle(entry.url);
      // Prefer sitemap lastmod over what's in the article HTML — the
      // sitemap is authoritative for freshness ordering.
      if (entry.lastmod && !article.publishedAt) {
        article.publishedAt = entry.lastmod;
      }
      results.push(article);
    } catch (e) {
      // Individual article failure shouldn't kill the batch.
      console.error("[blog-fetcher] article fetch failed:", entry.url, e);
    }
  }
  return results;
}

// Returns the most recently published article that hasn't yet been
// surfaced to LinkedIn (based on a DB-tracked set of seen URLs).
export async function pickNextArticleForLinkedIn(
  alreadyPostedUrls: Set<string>,
): Promise<BlogArticle | null> {
  const articles = await listBlogArticles();
  for (const article of articles) {
    if (!alreadyPostedUrls.has(article.url)) return article;
  }
  return null;
}

// Blog-to-social broadcaster.
//
// For each new blog article on georgeyachts.com:
//   1. Facebook Page: full link post (clickable, shows link preview card)
//      using the permanent Page Access Token.
//   2. Instagram Feed: image post with a short caption ending in
//      "Full article → georgeyachts.com/blog". IG doesn't make URLs in
//      captions clickable, but the URL is still visible and readers
//      know where to go.
//   3. Instagram Story: single-image story with the same cover image +
//      a CTA line overlay-style in the caption. IG Graph API does NOT
//      support adding link stickers programmatically (a long-standing
//      UI-only limitation), so we lean on the cover image + consistent
//      "georgeyachts.com/blog" verbal call-to-action.
//
// Caption generation is AI-driven (gemini-flash) with a platform-aware
// system prompt so the FB long-form version differs from the IG feed
// short hook. Zero manual work on publish day.

import { aiChat } from "@/lib/ai";
import type { BlogArticle } from "@/lib/blog-fetcher";
import { publishPhoto as facebookPublishPhoto } from "@/lib/facebook-client";

const IG_GRAPH = "https://graph.instagram.com/v21.0";

type Result<T> = { ok: true; id?: string; detail?: T } | { ok: false; error: string };

// ── Caption generators ────────────────────────────────────────────────────

const CAPTION_SYSTEM = `
You write short-form social captions for George Yachts, a MYBA yacht
charter brokerage operating in Greek waters (Cyclades / Ionian /
Saronic). George's voice is data-first, honest, specific. He never
uses these words: stunning, iconic, unparalleled, exceptional,
pedigree, curated, experience (as noun), elevate, unlock, leverage,
primed, breathtaking, hidden gem, tailored. No emoji clusters. Max
one emoji per caption, and only from this set: ⛵ 🌊 ⚓ ✨ — used at
the very end only, never mid-sentence.

CRITICAL output contract (violating any of these = broken):
  - Plain text, no markdown, no code fences, no surrounding quotes.
  - FULL caption must be present. Never stop mid-sentence.
  - Must end with a clear call to action and hashtag block as
    specified by the platform brief.
  - Hashtags only from this industry set: #YachtCharter #MYBACharter
    #CycladesCharter #IonianCharter #MediterraneanYachting
    #LuxuryCharter #YachtBrokerage. Pick 4 or 5.
  - Absolutely no consumer-y tags like #YachtLife, #Goals,
    #InstaYacht.
`.trim();

async function generateCaption(
  article: BlogArticle,
  platform: "facebook" | "instagram_feed" | "instagram_story",
): Promise<string> {
  const platformBrief = {
    facebook: `PLATFORM: Facebook Page post.
LENGTH: 120-220 words.
STRUCTURE:
  1. Data-first hook (one strong sentence with a number or concrete contrast).
  2. 2-3 short paragraphs pulled from the article's actual insight.
  3. Close with ONE blank line, then the article URL on its own line
     (Facebook will render a rich preview card off og:image).
  4. Blank line, then 4-5 industry hashtags on a single final line.

The URL MUST be: ${article.url}`,

    instagram_feed: `PLATFORM: Instagram feed caption.
LENGTH: 90-130 words.
REQUIRED STRUCTURE (do not skip any step):
  1. Opening hook: one sentence with the article's strongest number
     or counter-intuitive observation.
  2. 3-5 short lines — one thought each, NOT a paragraph. Use em-dashes
     or bullets for readability.
  3. One "why it matters for yacht charter" line tying the trend to
     Greek waters specifically.
  4. Blank line.
  5. LITERAL TEXT: "Full article → georgeyachts.com/blog"
  6. Blank line.
  7. Hashtag block: 4-5 industry hashtags separated by single spaces.

The URL stays visible but not clickable on IG — readers will type it.`,

    instagram_story: `PLATFORM: Instagram Story caption.
LENGTH: 15-30 words, single paragraph.
STRUCTURE: one tight hook sentence + "Read on georgeyachts.com/blog".
No hashtags, no URL besides the domain mention.`,
  }[platform];

  const userPrompt = `${platformBrief}

ARTICLE TITLE: ${article.title}
ARTICLE URL: ${article.url}
ARTICLE LEAD PARAGRAPHS:
${article.leadParagraphs.slice(0, 4).join("\n\n")}

Write the complete caption now. Do not add any explanation before or
after. Do not wrap in quotes or code fences. Just the caption text.`;

  const raw = await aiChat(CAPTION_SYSTEM, userPrompt, {
    maxTokens: 2000,
    temperature: 0.55,
  });

  return cleanAndGuarantee(raw, article, platform);
}

// Post-processing safety net. We never trust the model to always
// obey the output contract — so we enforce it here by:
//   - stripping markdown / quotes / code fences
//   - detecting truncated output (ends mid-word or without CTA)
//   - appending the required CTA + hashtags if the model forgot them
// Guarantees the caption is never published broken.
function cleanAndGuarantee(
  raw: string,
  article: BlogArticle,
  platform: "facebook" | "instagram_feed" | "instagram_story",
): string {
  let out = (raw || "")
    .replace(/^```[a-z]*\s*/i, "")
    .replace(/\s*```\s*$/, "")
    .replace(/^\s*["']|["']\s*$/g, "")
    .trim();

  // Truncation heuristic: ends with a preposition/article/conjunction
  // mid-phrase (classic max-tokens cutoff).
  const endsMidSentence = /\b(in|on|at|to|of|for|the|a|an|and|or|but|as|by|with|that|which|this|these|those)\s*$/i.test(
    out,
  );
  if (endsMidSentence) {
    // Drop the dangling last sentence fragment so we don't publish half-a-thought.
    out = out.replace(/[^.!?\n]+$/, "").trim();
  }

  const hashtagSet = [
    "#YachtCharter",
    "#MYBACharter",
    "#CycladesCharter",
    "#MediterraneanYachting",
    "#LuxuryCharter",
  ];

  if (platform === "instagram_feed") {
    // Guarantee CTA line present
    if (!/georgeyachts\.com\/blog/i.test(out)) {
      out = `${out}\n\nFull article → georgeyachts.com/blog`;
    }
    // Guarantee hashtag block present
    const hasHashtagBlock = /(^|\n)\s*#\w+(\s+#\w+){2,}/m.test(out);
    if (!hasHashtagBlock) {
      out = `${out}\n\n${hashtagSet.slice(0, 4).join(" ")}`;
    }
  } else if (platform === "facebook") {
    // Ensure the full article URL is literally present (for the link preview).
    if (!out.includes(article.url)) {
      out = `${out}\n\n${article.url}`;
    }
    const hasHashtagBlock = /(^|\n)\s*#\w+(\s+#\w+){2,}/m.test(out);
    if (!hasHashtagBlock) {
      out = `${out}\n\n${hashtagSet.slice(0, 4).join(" ")}`;
    }
  } else if (platform === "instagram_story") {
    if (!/georgeyachts\.com\/blog/i.test(out)) {
      out = `${out}\n\nRead on georgeyachts.com/blog`;
    }
  }

  return out.trim();
}

