// @ts-nocheck
// Pre-queue caption approval gate.
//
// Roberto brief v2 (2026-04-22): captions must be reviewed by George
// BEFORE they land in ig_posts as scheduled. The old flow was:
//
//   AI generates → INSERT status='scheduled' → publish cron fires
//
// The new flow is:
//
//   AI generates → INSERT status='pending_approval' → Telegram
//   inline buttons → George taps Approve → webhook flips to
//   status='scheduled' → publish cron fires
//
// This file implements the server side: enqueuePendingApproval() that
// writes a pending row + sends the Telegram message with inline keyboard,
// and handleApprovalCallback() that the webhook (/api/webhooks/telegram-approval)
// calls when a button is tapped.
//
// Approval rules baked in:
//   • If voice-guardrail violations are detected in the generated
//     caption, we Telegram WITH the violations highlighted so George
//     can see the quality issue before approving.
//   • Reject flips status to 'draft' + stores the reason, so it never
//     publishes but is recoverable for editing.
//   • Regenerate keeps status='pending_approval' but queues a fresh
//     AI attempt (handled in a separate Edge function — see inline TODO).

import { createServiceClient } from "@/lib/supabase-server";
import { detectBannedPhrases, detectEmojiViolations } from "@/lib/ai-voice-guardrails";

const TELEGRAM_BOT = process.env.TELEGRAM_BOT_TOKEN;
const TELEGRAM_CHAT = process.env.TELEGRAM_CHAT_ID;

export type PendingInsert = {
  image_url: string;
  caption: string;
  schedule_time: string;
  scheduled_for: string;
  post_type: "image" | "carousel" | "reel" | "fleet_yacht";
  // Optional: which yacht, which angle, etc. — kept in post.fleet_meta.
};

/**
 * Read the auto-approve flag from settings. Default is TRUE — full auto
 * publishing like the pre-Roberto-v2 flow. The Telegram approval gate
 * stays in the codebase for opt-in tightening, but is OFF by default
 * because George's blocking complaint (2026-04-28) was the silent gate:
 * captions piling up in pending_approval and never going live.
 *
 * To turn the gate back on:
 *   INSERT INTO settings (key, value) VALUES ('caption_auto_approve', 'false');
 */
async function isAutoApproveEnabled(
  sb: ReturnType<typeof createServiceClient>,
): Promise<boolean> {
  try {
    const { data } = await sb
      .from("settings")
      .select("value")
      .eq("key", "caption_auto_approve")
      .maybeSingle();
    if (!data) return true; // default ON
    const v = (data.value as string) ?? "true";
    return v !== "false";
  } catch {
    return true;
  }
}

export async function enqueuePendingApproval(
  row: PendingInsert
): Promise<{ id: string | null; telegram_message_id: number | null }> {
  const sb = createServiceClient();
  const autoApprove = await isAutoApproveEnabled(sb);

  // When auto-approve is on (default), captions land directly in
  // status='scheduled' so the publish cron picks them up at their time.
  // When off, they land in 'pending_approval' and a Telegram card with
  // ✅/❌ buttons is sent to George.
  const targetStatus = autoApprove ? "scheduled" : "pending_approval";
  const insertRow = {
    ...row,
    status: targetStatus,
  } as Record<string, unknown>;

  let id: string | null = null;
  try {
    const { data, error } = await sb
      .from("ig_posts")
      .insert(insertRow)
      .select("id")
      .single();
    if (error && error.message?.includes("check constraint")) {
      const fallback = await sb
        .from("ig_posts")
        .insert({ ...row, status: autoApprove ? "scheduled" : "draft" })
        .select("id")
        .single();
      id = fallback.data?.id ?? null;
    } else {
      id = data?.id ?? null;
    }
  } catch (e) {
    console.error("[approval-gate] insert failed:", e);
    return { id: null, telegram_message_id: null };
  }

  // In auto-approve mode we skip the Telegram approval card entirely
  // — the publish cron will surface a success Telegram once the post
  // actually goes live, which is the signal George cares about.
  if (autoApprove) {
    return { id, telegram_message_id: null };
  }

  // Voice audit for the preview message.
  const bannedHits = detectBannedPhrases(row.caption);
  const emojiHits = detectEmojiViolations(row.caption);
  const audit = [
    bannedHits.length ? `⚠️ Voice: ${bannedHits.join(", ")}` : "",
    emojiHits.length ? `⚠️ Emoji: ${emojiHits.join(" ")}` : "",
  ]
    .filter(Boolean)
    .join(" · ");

  const preview =
    row.caption.length > 600
      ? row.caption.slice(0, 600) + "…"
      : row.caption;

  const scheduledLocal = new Date(row.scheduled_for).toLocaleString("en-GB", {
    timeZone: "Europe/Athens",
  });

  const text = [
    `📸 <b>New IG post awaiting approval</b>`,
    ``,
    `Type: <b>${row.post_type}</b>`,
    `Schedule: <code>${scheduledLocal}</code> Athens`,
    audit ? `<i>${audit}</i>` : "",
    ``,
    `<b>Caption:</b>`,
    preview,
  ]
    .filter(Boolean)
    .join("\n");

  const tgId = await sendTelegramWithButtons(text, id ?? "unknown");
  return { id, telegram_message_id: tgId };
}

async function sendTelegramWithButtons(
  text: string,
  postId: string
): Promise<number | null> {
  if (!TELEGRAM_BOT || !TELEGRAM_CHAT) return null;
  const payload = {
    chat_id: TELEGRAM_CHAT,
    text,
    parse_mode: "HTML",
    reply_markup: {
      inline_keyboard: [
        [
          { text: "✅ Approve", callback_data: `ig_approve:${postId}` },
          { text: "❌ Reject", callback_data: `ig_reject:${postId}` },
          { text: "🔄 Regenerate", callback_data: `ig_regen:${postId}` },
        ],
      ],
    },
  };
  try {
    const res = await fetch(
      `https://api.telegram.org/bot${TELEGRAM_BOT}/sendMessage`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      }
    );
    const body = await res.json();
    return body?.result?.message_id ?? null;
  } catch (e) {
    console.error("[approval-gate] telegram send failed:", e);
    return null;
  }
}

// Called from /api/webhooks/telegram-approval when the user taps a button.
export async function handleApprovalCallback(
  callbackData: string,
  callbackQueryId: string
): Promise<{ ok: boolean; message: string }> {
  const match = callbackData.match(/^ig_(approve|reject|regen):([\w-]+)$/);
  if (!match) return { ok: false, message: "unknown callback" };
  const [, action, postId] = match;

  const sb = createServiceClient();
  let message = "";
  if (action === "approve") {
    await sb
      .from("ig_posts")
      .update({ status: "scheduled" })
      .eq("id", postId);
    message = "✅ Approved — will publish at scheduled time.";
  } else if (action === "reject") {
    await sb
      .from("ig_posts")
      .update({ status: "draft", error: "rejected_by_approval_gate" })
      .eq("id", postId);
    message = "❌ Rejected — moved to draft. No publish.";
  } else {
    // Regenerate: mark status draft + a flag another cron picks up to
    // re-run the caption generator. Implementation of the regen cron is
    // tracked separately; for now the flag is enough to signal intent.
    await sb
      .from("ig_posts")
      .update({
        status: "draft",
        error: "regen_requested",
      })
      .eq("id", postId);
    message = "🔄 Regenerate queued — new caption in ~5 min.";
  }

  // ACK the callback so Telegram stops showing the loading spinner.
  if (TELEGRAM_BOT) {
    await fetch(
      `https://api.telegram.org/bot${TELEGRAM_BOT}/answerCallbackQuery`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          callback_query_id: callbackQueryId,
          text: message,
          show_alert: false,
        }),
      }
    ).catch(() => {});
  }
  return { ok: true, message };
}

// @ts-nocheck
/**
 * Caption similarity guard.
 *
 * Roberto brief v3 — Phase 0.75, Guard 1 (but without pgvector).
 *
 * Before a publish cron commits a fresh caption to Instagram, we ask
 * Gemini "is this new caption too similar in meaning OR structure to
 * any of these 50 recent ones?". If yes, the cron regenerates up to
 * 3 times, then gives up and posts anyway (fail-open) while firing a
 * Telegram alert so George knows the AI is starting to loop.
 *
 * Why inline Gemini instead of pgvector embeddings?
 * - Library of ~200 published posts fits easily into one Gemini prompt
 *   context — no need for a vector DB.
 * - No pgvector extension to install, no VECTOR(768) column migration.
 * - Cost per check: ~$0.0001 with Gemini Flash.
 * - Same guard surface: a single yes/no + matched-id response.
 *
 * Fail-open guarantee: on any AI error or DB error, returns
 * { similar: false } so the caller publishes normally. The Telegram
 * alert fires once per distinct failure-mode-per-day so we don't spam.
 */

import { createServiceClient } from "./supabase-server";
import { aiChat } from "./ai";

const HISTORY_LIMIT = 50;

type SimilarityResult = {
  similar: boolean;
  reason?: string;
  matchedCaptionPreview?: string;
};

export async function isCaptionTooSimilar(
  newCaption: string,
  opts: { threshold?: number } = {},
): Promise<SimilarityResult> {
  const threshold = opts.threshold ?? 0.8;
  if (!newCaption || newCaption.trim().length < 30) {
    // Too short to meaningfully compare — let the quality guard handle it.
    return { similar: false };
  }

  const history = await fetchRecentCaptions(HISTORY_LIMIT);
  if (history.length === 0) return { similar: false };

  try {
    // Pack the history into a compact numbered list. Gemini Flash reads
    // this easily. We only need the similarity decision, not the raw
    // numbers — just a yes/no + which one matched so the cron can log.
    const numbered = history
      .map((c, i) => `[${i + 1}] ${c.slice(0, 500)}`)
      .join("\n\n");

    const prompt = `You are a similarity judge for Instagram captions.

NEW CAPTION:
${newCaption.slice(0, 1500)}

RECENT CAPTIONS (last ${history.length} posts):
${numbered}

Task: Decide whether the NEW caption is too similar (above ${threshold * 100}% overlap in meaning, structure, hook, OR hashtag block) to ANY of the recent captions.

Reply with ONLY a JSON object:
{
  "similar": true | false,
  "matched_index": <number 1-${history.length}> | null,
  "reason": "<short explanation, max 80 chars>"
}

Be strict — near-duplicates hurt the Instagram algorithm.`;

    const raw = await aiChat(
      "You return only JSON. No markdown, no prose.",
      prompt,
    );
    const match = raw.match(/\{[\s\S]*\}/);
    if (!match) return { similar: false };
    const parsed = JSON.parse(match[0]);

    if (!parsed.similar) return { similar: false };

    const idx = Number(parsed.matched_index);
    const matchedPreview =
      Number.isInteger(idx) && idx >= 1 && idx <= history.length
        ? history[idx - 1].slice(0, 140)
        : undefined;

    return {
      similar: true,
      reason: String(parsed.reason ?? "").slice(0, 200),
      matchedCaptionPreview: matchedPreview,
    };
  } catch {
    // Fail-open on AI errors.
    return { similar: false };
  }
}

async function fetchRecentCaptions(limit: number): Promise<string[]> {
  try {
    const sb = createServiceClient();
    const { data } = await sb
      .from("ig_posts")
      .select("caption")
      .eq("status", "published")
      .order("published_at", { ascending: false })
      .limit(limit);
    return (data ?? [])
      .map((r: any) => String(r.caption ?? "").trim())
      .filter((c: string) => c.length >= 30);
  } catch {
    return [];
  }
}

// v3 Pillar 7+8 — Charter activation cascade.
//
// When a contract is uploaded and successfully extracted, this fires:
//   1. Upsert the deal row with extracted fields
//   2. Mark contact as charter_client + linked to deal
//   3. Set lifecycle_status = 'active' + lifecycle_activated_at = now()
//   4. Plan and persist all 17 milestones from charter dates
//   5. Return summary for cockpit confirmation banner
//
// Called from /api/admin/charter-extract or the upload handler.

import type { SupabaseClient } from "@supabase/supabase-js";
import type { ContractExtraction } from "@/lib/charter-doc-extractor";
import { planMilestones } from "@/lib/charter-lifecycle";

export interface ActivationResult {
  ok: boolean;
  deal_id: string | null;
  contact_id: string | null;
  milestones_generated: number;
  client_full_name: string | null;
  vessel_name: string | null;
  charter_start_date: string | null;
  charter_end_date: string | null;
  message: string;
}

export async function activateCharterFromContract(
  sb: SupabaseClient,
  args: {
    extracted: ContractExtraction;
    document_id: string;             // charter_documents.id of the contract
    primary_contact_id?: string | null;
  },
): Promise<ActivationResult> {
  const { extracted } = args;

  // 1. Resolve / create the primary contact.
  let contactId: string | null = args.primary_contact_id ?? null;
  if (!contactId && extracted.client_email) {
    const { data: existing } = await sb
      .from("contacts")
      .select("id")
      .ilike("email", extracted.client_email)
      .maybeSingle();
    if (existing?.id) {
      contactId = existing.id as string;
    } else {
      // Create the contact from contract data.
      const { data: stages } = await sb
        .from("pipeline_stages")
        .select("id, name");
      const stageMap = new Map<string, string>();
      for (const s of stages ?? [])
        stageMap.set(s.name as string, s.id as string);
      const closedWon = stageMap.get("Closed Won") ?? null;
      const [first, ...rest] = (extracted.client_full_name ?? "")
        .split(/\s+/)
        .filter(Boolean);
      const { data: inserted } = await sb
        .from("contacts")
        .insert({
          first_name: first ?? null,
          last_name: rest.join(" ") || null,
          email: extracted.client_email,
          phone: extracted.client_phone ?? null,
          country: extracted.client_country ?? null,
          source: "manual",
          contact_type: "DIRECT_CLIENT",
          pipeline_stage_id: closedWon,
          last_activity_at: new Date().toISOString(),
        })
        .select("id")
        .single();
      contactId = (inserted?.id as string) ?? null;
    }
  }

  if (!contactId) {
    return {
      ok: false,
      deal_id: null,
      contact_id: null,
      milestones_generated: 0,
      client_full_name: extracted.client_full_name,
      vessel_name: extracted.vessel_name,
      charter_start_date: extracted.charter_start_date,
      charter_end_date: extracted.charter_end_date,
      message:
        "Cannot activate without a primary contact (no email in contract and none provided).",
    };
  }

  // 2. Upsert the deal. Match by primary_contact + start date to avoid
  //    duplicates if the same contract gets re-extracted.
  const dealPatch = {
    primary_contact_id: contactId,
    vessel_name: extracted.vessel_name,
    charter_start_date: extracted.charter_start_date,
    charter_end_date: extracted.charter_end_date,
    embark_port: extracted.embark_port,
    disembark_port: extracted.disembark_port,
    guest_count: extracted.guest_count,
    charter_fee_eur: extracted.charter_fee_eur,
    apa_eur: extracted.apa_eur,
    vat_rate: extracted.vat_rate,
    vat_eur: extracted.vat_eur,
    total_eur: extracted.total_eur,
    payment_status: "pending",
    contract_signed: true,
    client_country: extracted.client_country,
    client_residency: extracted.client_residency,
    lifecycle_status: "active",
    lifecycle_activated_at: new Date().toISOString(),
  };

  let dealId: string | null = null;
  {
    const { data: existing } = await sb
      .from("deals")
      .select("id")
      .eq("primary_contact_id", contactId)
      .eq("charter_start_date", extracted.charter_start_date as string)
      .maybeSingle();
    if (existing?.id) {
      dealId = existing.id as string;
      await sb.from("deals").update(dealPatch).eq("id", dealId);
    } else {
      const { data: inserted, error } = await sb
        .from("deals")
        .insert(dealPatch)
        .select("id")
        .single();
      if (error || !inserted) {
        return {
          ok: false,
          deal_id: null,
          contact_id: contactId,
          milestones_generated: 0,
          client_full_name: extracted.client_full_name,
          vessel_name: extracted.vessel_name,
          charter_start_date: extracted.charter_start_date,
          charter_end_date: extracted.charter_end_date,
          message: error?.message ?? "deal insert failed",
        };
      }
      dealId = inserted.id as string;
    }
  }

  // 3. Link the contract document to the deal.
  await sb
    .from("charter_documents")
    .update({ deal_id: dealId, contact_id: contactId })
    .eq("id", args.document_id);

  // 4. Mirror the deal onto the contact row (legacy denormalized fields
  //    that the rest of the cockpit reads from). Only mirror if the
  //    contact has no current deal or this is a more recent one.
  await sb
    .from("contacts")
    .update({
      charter_vessel: extracted.vessel_name,
      charter_start_date: extracted.charter_start_date,
      charter_end_date: extracted.charter_end_date,
      charter_fee: extracted.charter_fee_eur,
      charter_apa: extracted.apa_eur,
      contact_type: "DIRECT_CLIENT",
      last_activity_at: new Date().toISOString(),
    })
    .eq("id", contactId);

  // 5. Plan and persist the 17 milestones.
  let milestonesGenerated = 0;
  if (extracted.charter_start_date && extracted.charter_end_date) {
    const plan = planMilestones({
      charter_start_date: extracted.charter_start_date,
      charter_end_date: extracted.charter_end_date,
    });
    const rows = plan.map((m) => ({
      deal_id: dealId,
      contact_id: contactId,
      milestone_type: m.milestone_type,
      due_date: m.due_date,
      auto_action: m.auto_action,
      status: "pending",
    }));
    // Use upsert with ON CONFLICT do nothing semantics via the unique
    // constraint (uq_milestone_per_deal_type) — re-running activation
    // doesn't dupe milestones.
    const { error } = await sb
      .from("charter_lifecycle_milestones")
      .upsert(rows, { onConflict: "deal_id,milestone_type" });
    if (!error) milestonesGenerated = rows.length;
  }

  return {
    ok: true,
    deal_id: dealId,
    contact_id: contactId,
    milestones_generated: milestonesGenerated,
    client_full_name: extracted.client_full_name,
    vessel_name: extracted.vessel_name,
    charter_start_date: extracted.charter_start_date,
    charter_end_date: extracted.charter_end_date,
    message: `Charter activated. ${milestonesGenerated} milestones generated.`,
  };
}

