// ─── Generic AI extraction helper ──────────────────────────────────

async function extractWithAI<T>(
  systemPrompt: string,
  textInput: string,
  hint: string,
): Promise<ExtractResult<T>> {
  let raw: string;
  try {
    raw = await aiChat(systemPrompt, textInput, {
      maxTokens: 4000,
      temperature: 0.0,
    });
  } catch (err) {
    return {
      ok: false,
      confidence: 0,
      ai_model_used: MODEL,
      raw_response: "",
      error: err instanceof Error ? err.message : "ai call failed",
    };
  }
  const cleaned = raw
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/```\s*$/i, "")
    .trim();
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (!m) {
    return {
      ok: false,
      confidence: 0,
      ai_model_used: MODEL,
      raw_response: raw,
      error: `no JSON object found (hint: ${hint})`,
    };
  }
  try {
    const parsed = JSON.parse(m[0]) as T & { confidence?: number };
    const conf = parsed.confidence ?? 0.7;
    return {
      ok: true,
      data: parsed,
      confidence: Math.max(0, Math.min(1, conf)),
      ai_model_used: MODEL,
      raw_response: raw,
    };
  } catch (err) {
    return {
      ok: false,
      confidence: 0,
      ai_model_used: MODEL,
      raw_response: raw,
      error: err instanceof Error ? err.message : "json parse failed",
    };
  }
}

