// Sprint 2.3 — Pillar 4: commitment extractor.
//
// Scans an outbound email body for promises George made and extracts:
//   - the verbatim commitment sentence
//   - a concise summary
//   - the deadline (parsed to a date when possible)
//   - the deadline phrase (raw — useful for the cockpit display)
//
// Returns 0..N commitments per email. A single thank-you reply
// usually has 0; a partner intro email might have 2–3 ("I'll send
// you the package + loop in our captain + come back with dates").
//
// AI-driven for accuracy (the brief calls out 85% accuracy on a
// 30-message sample as the bar). Cheap heuristic pre-filter
// avoids paying the AI on emails with zero commitment-shaped
// language.

import { aiChat } from "@/lib/ai";

export interface ExtractedCommitment {
  commitment_text: string;       // verbatim sentence
  commitment_summary: string;    // 1-line AI summary
  deadline_date: string | null;  // YYYY-MM-DD
  deadline_phrase: string;       // raw phrase from the email
  confidence: number;            // 0..1
}

// Pre-filter: skip the AI call entirely when no commitment-shaped
// language is present. Saves cost on the typical "thanks!" reply.
const COMMITMENT_TRIGGERS_RE =
  /\b(i(?:'ll| will| am going to| 'm going to| shall)|let me|let's|we(?:'ll| will)|happy to|will (send|share|forward|circle\s+back|come\s+back|loop\s+in|follow\s+up|prepare|put\s+together|reach\s+out|book|get\s+back)|by\s+(monday|tuesday|wednesday|thursday|friday|saturday|sunday|tomorrow|tonight|end\s+of|the\s+end\s+of|next\s+(week|monday|tuesday|wednesday|thursday|friday)|early\s+next|this\s+(week|afternoon|evening))|tomorrow|in\s+a\s+(few|couple)\s+(days|hours)|asap|first\s+thing|over\s+the\s+weekend|before\s+(end\s+of\s+)?(today|tomorrow|monday|tuesday|wednesday|thursday|friday)|by\s+\d+(:\d+)?\s*(am|pm)?|by\s+(jan(uary)?|feb(ruary)?|mar(ch)?|apr(il)?|may|jun(e)?|jul(y)?|aug(ust)?|sep(t(ember)?)?|oct(ober)?|nov(ember)?|dec(ember)?))/i;

export function hasCommitmentLanguage(body: string): boolean {
  if (!body) return false;
  // Strip quoted lines first — we only care about NEW content George
  // wrote, not commitments in the quoted thread.
  const cleaned = body
    .split("\n")
    .filter((l) => !/^\s*>/.test(l))
    .join("\n")
    .split(/^On\b [^\n]{4,120}\bwrote:/im)[0];
  return COMMITMENT_TRIGGERS_RE.test(cleaned);
}

const SYSTEM = `You analyze a SINGLE outbound email written by George (a yacht broker) and extract any PROMISES George made to the recipient.

CRITICAL OUTPUT RULES:
- Output ONLY a raw JSON object. NO markdown fences. NO prose. Start with { end with }.
- Schema: {"commitments":[{"commitment_text":"<verbatim sentence>","commitment_summary":"<≤80 chars>","deadline_date":"<YYYY-MM-DD or null>","deadline_phrase":"<raw phrase>","confidence":<0..1>}]}
- Empty array if no commitments: {"commitments":[]}

What counts as a commitment:
- George says he'll do something specific: "I'll send the package", "I'll loop in our captain", "I'll come back to you with options"
- George commits to a deadline, even soft: "by Monday", "early next week", "tomorrow", "this afternoon"
- Conditional commitments: "happy to set up a call this week" (yes), "let me know if you're interested" (no — that's an open question, not a promise)

What does NOT count:
- Polite courtesy: "Thanks!", "Speak soon", "Talk to you Monday" (Monday is a goodbye, not a commitment)
- Suggestions: "We could discuss…", "It might make sense to…"
- Questions: "Would you like…", "When are you available…"
- Past actions: "I sent you the brochure last week"
- General intent without a specific deliverable: "I'll be in touch"

Deadline parsing rules:
- "Monday" → next Monday's calendar date
- "tomorrow" → tomorrow's date
- "early next week" → next Monday
- "end of week" → next Friday
- "by 4/5" → that exact date in current year
- "asap" / "soon" → null deadline_date but include in deadline_phrase
- Missing → null

Today's date for relative parsing is included in the user message. Be precise about dates.`;

export async function extractCommitmentsAI(
  body: string,
  todayISO: string,
): Promise<ExtractedCommitment[]> {
  const userMsg = JSON.stringify({
    today: todayISO,
    email_body: body.slice(0, 6000),
  });
  let raw: string;
  try {
    raw = await aiChat(SYSTEM, userMsg, { maxTokens: 1500, temperature: 0.1 });
  } catch (err) {
    console.error("[commitment-extractor] AI call failed:", err);
    return [];
  }
  const cleaned = raw
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/```\s*$/i, "")
    .trim();
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (!m) return [];
  try {
    const parsed = JSON.parse(m[0]) as {
      commitments?: Array<Partial<ExtractedCommitment>>;
    };
    return (parsed.commitments ?? [])
      .filter((c) => c.commitment_text && typeof c.commitment_text === "string")
      .map((c) => ({
        commitment_text: c.commitment_text!.slice(0, 400),
        commitment_summary: (c.commitment_summary ?? c.commitment_text!).slice(0, 100),
        deadline_date: c.deadline_date ?? null,
        deadline_phrase: c.deadline_phrase ?? "",
        confidence: Math.max(0, Math.min(1, c.confidence ?? 0.5)),
      }));
  } catch (err) {
    console.error("[commitment-extractor] parse failed:", err);
    return [];
  }
}

/**
 * Extract commitments from one outbound email. Returns [] if no
 * commitment-shaped language is present (skips the AI call).
 */
export async function extractCommitments(
  body: string,
  todayISO: string,
): Promise<ExtractedCommitment[]> {
  if (!hasCommitmentLanguage(body)) return [];
  return extractCommitmentsAI(body, todayISO);
}

// @ts-nocheck
/**
 * Cron execution observer.
 *
 * Lightweight instrumentation that wraps each IG cron's GET handler,
 * records START and END outcome into the `settings` KV table, and
 * lets the Thursday weekly-ops-report cron compute success / failure
 * / timeout counts + uptime %.
 *
 * Zero-DDL: uses the settings table with a `cron_run_<id>` key pattern.
 * Auto-prunes rows older than 21 days on every call.
 *
 * Pattern to wrap an existing cron (minimal edit, 4 lines):
 *
 *   // Before:
 *   export async function GET(req) { ... }
 *
 *   // After:
 *   async function _impl(req) { ... }                    // rename
 *   export async function GET(req?: any) {
 *     return observeCron("instagram-my-cron", () => _impl(req));
 *   }
 *
 * The wrapper is best-effort: if the settings writes fail, the actual
 * cron still runs and returns its response normally — observability
 * never blocks a real publish or reply.
 *
 * Timeout detection: we write a START row when the cron begins. If
 * the cron completes (any outcome), we write an END row with the
 * same run_id. If the function times out (Vercel 504 before we finish),
 * no END row is written — the weekly report sees a START without an
 * END and classifies it as "timed out".
 */

import { createServiceClient } from "./supabase-server";

type Outcome = "success" | "error" | "skipped" | "exception";

const START_PREFIX = "cron_start_";
const END_PREFIX = "cron_end_";
const PRUNE_AFTER_DAYS = 21;

function generateRunId(): string {
  return (
    Date.now().toString(36) +
    "_" +
    Math.random().toString(36).slice(2, 10)
  );
}

async function recordStart(
  sb: any,
  runId: string,
  name: string,
): Promise<void> {
  try {
    await sb.from("settings").insert({
      key: `${START_PREFIX}${runId}`,
      value: JSON.stringify({
        run_id: runId,
        name,
        started_at: new Date().toISOString(),
      }),
      updated_at: new Date().toISOString(),
    });
  } catch {
    // fail-open
  }
}

async function recordEnd(
  sb: any,
  runId: string,
  name: string,
  startedAt: number,
  endedAt: number,
  outcome: Outcome,
  detail?: string,
): Promise<void> {
  try {
    await sb.from("settings").insert({
      key: `${END_PREFIX}${runId}`,
      value: JSON.stringify({
        run_id: runId,
        name,
        started_at: new Date(startedAt).toISOString(),
        ended_at: new Date(endedAt).toISOString(),
        duration_ms: endedAt - startedAt,
        outcome,
        detail: detail ? String(detail).slice(0, 200) : null,
      }),
      updated_at: new Date().toISOString(),
    });
  } catch {
    // fail-open
  }
}

async function pruneOld(sb: any): Promise<void> {
  try {
    const cutoff = new Date(
      Date.now() - PRUNE_AFTER_DAYS * 86400000,
    ).toISOString();
    await sb.from("settings").delete().like("key", `${START_PREFIX}%`).lt("updated_at", cutoff);
    await sb.from("settings").delete().like("key", `${END_PREFIX}%`).lt("updated_at", cutoff);
  } catch {
    // fail-open
  }
}

/**
 * Wrap a cron handler with observability. The handler's Response is
 * cloned to peek at the JSON body without consuming the original, so
 * we can classify the outcome from the response shape:
 *   { error: "..." }   → "error"
 *   { skipped: "..." } → "skipped"
 *   { ok: true, ... }  → "success"
 *   anything else      → "success" (best-effort)
 */
export async function observeCron(
  name: string,
  handler: () => Promise<Response>,
): Promise<Response> {
  const sb = createServiceClient();
  const runId = generateRunId();
  const startedAt = Date.now();

  // Fire-and-forget: start record + prune.
  recordStart(sb, runId, name).catch(() => {});
  pruneOld(sb).catch(() => {});

  try {
    const response = await handler();
    const endedAt = Date.now();

    // Peek at body without consuming the original response.
    let outcome: Outcome = "success";
    let detail: string | undefined;
    try {
      const clone = response.clone();
      const body = (await clone.json()) as any;
      if (body?.error) {
        outcome = "error";
        detail = String(body.error);
      } else if (body?.skipped) {
        outcome = "skipped";
        detail = String(body.skipped);
      }
    } catch {
      // Non-JSON response (HTML, empty, etc.). Don't default to success —
      // fall through to the status-code check below so a 5xx with an
      // HTML body still gets classified as an error.
    }

    // Status-code overlay. Previously the observer only looked at the
    // response body shape, so a handler that returned `Response.json(
    // { wrong: true }, { status: 502 })` got recorded as "success" and
    // the new health-check "Cron failures (24h)" line missed it. Now any
    // non-2xx response is at least an "error" — body detail wins for
    // the message when present, otherwise we record the status text.
    if (outcome === "success" && (response.status < 200 || response.status >= 300)) {
      outcome = "error";
      detail = detail ?? `HTTP ${response.status}${response.statusText ? ` ${response.statusText}` : ""}`;
    }

    await recordEnd(sb, runId, name, startedAt, endedAt, outcome, detail);
    return response;
  } catch (err: any) {
    const endedAt = Date.now();
    await recordEnd(
      sb,
      runId,
      name,
      startedAt,
      endedAt,
      "exception",
      err?.message ?? String(err),
    );
    throw err;
  }
}

// Email signature + noise-filter helpers for the inbox-driven CRM.
//
// The "CRM is your inbox" pattern — every real inbound email creates or
// updates a contact, and the body's signature block is mined for name,
// title, company, phone, LinkedIn. We can't assume the sender is a real
// human unless we strip out the obvious noise first (newsletters,
// platform notifications, transactional mail).

export type ParsedSignature = {
  name: string | null;
  title: string | null;
  company: string | null;
  phone: string | null;
  linkedinUrl: string | null;
  website: string | null;
};

// Friendly-from parser: "George P. Biniaris <george@georgeyachts.com>"
export function parseFromHeader(from: string): {
  name: string | null;
  email: string | null;
} {
  const match = from.match(/^\s*"?([^"<]+?)"?\s*<([^>]+)>\s*$/);
  if (match) {
    return { name: match[1].trim() || null, email: match[2].trim().toLowerCase() };
  }
  // Bare email
  if (/^[^@\s]+@[^@\s]+$/.test(from.trim())) {
    return { name: null, email: from.trim().toLowerCase() };
  }
  return { name: null, email: null };
}

// Domain heuristic for "this is a real company, not a personal inbox"
const PERSONAL_DOMAINS = new Set([
  "gmail.com", "googlemail.com", "yahoo.com", "ymail.com", "rocketmail.com",
  "hotmail.com", "outlook.com", "live.com", "msn.com",
  "icloud.com", "me.com", "mac.com",
  "aol.com", "protonmail.com", "proton.me", "mail.com",
  "gmx.com", "gmx.de", "web.de", "yandex.com", "yandex.ru",
  "hey.com", "fastmail.com",
]);

export function companyFromEmail(email: string): string | null {
  const domain = email.split("@")[1]?.toLowerCase();
  if (!domain) return null;
  if (PERSONAL_DOMAINS.has(domain)) return null;
  // Strip common TLDs + subdomain noise → capitalize first segment
  const root = domain.replace(/\.(com|co\.uk|co|org|net|io|ai|us|eu|de|fr|gr|it|es|ae|ca)$/i, "");
  const first = root.split(".").pop() ?? root;
  return first.charAt(0).toUpperCase() + first.slice(1);
}

// Strong noise patterns — drop these before creating contacts. All
// lowercase substrings matched against the from-email localpart or
// full from string. Extend as we see more.
const NOISE_LOCALPARTS = [
  "no-reply", "noreply", "do-not-reply", "donotreply",
  "notifications", "notification", "alerts", "alert",
  "mailer-daemon", "postmaster", "bounce", "bounces",
  "updates@", "news@", "newsletter@",
  "billing@", "invoice@", "receipts@", "receipt@",
  "security@", "account@", "accounts@", "password@",
  "notify@",
  // Cross-domain support / system / dealer / report noise
  "support@", "team@", "info@", "hello@",
  "dealermessage", "dealermail", "dealerresponse",
  "dmarcreport", "dmarc-report", "dmarc_report", "dmarc@",
  "failed-payments", "failed_payments",
  "statements@", "statement@", "invoice+", "billing+",
  "kundenservice", // German "customer service"
  "system@", "automated@", "robot@",
  "reports@", "report@", "digest@",
  "verification@", "verify@", "confirm@", "confirmation@",
  "recruiting@", "recruit@", "talent@",
  "marketing@", "promo@", "promotions@",
  "wingfinder", // Red Bull career bot
  "tryapollo", "meetapollo", "useapollo", // Apollo platform
  "successfactors", // SAP system noise
];

const NOISE_HEADERS = (h: Record<string, string>) =>
  !!h["list-unsubscribe"] ||
  !!h["list-id"] ||
  /^(bulk|list|auto[_-]generated|auto[_-]replied)/i.test(h["precedence"] ?? "") ||
  /^(auto[_-]replied|auto[_-]generated)/i.test(h["auto-submitted"] ?? "");

export function isNoiseEmail(args: {
  from: string;
  fromEmail: string;
  subject: string;
  headers: Record<string, string>;
}): { noise: boolean; reason?: string } {
  const local = args.fromEmail.split("@")[0] ?? "";
  if (NOISE_LOCALPARTS.some((p) => args.fromEmail.includes(p) || local.startsWith(p))) {
    return { noise: true, reason: "noise_localpart" };
  }
  if (NOISE_HEADERS(args.headers)) {
    return { noise: true, reason: "bulk_headers" };
  }
  return { noise: false };
}

// Signature extraction. Real signatures almost always sit at the
// bottom of the reply (below a "--" separator, above the quoted
// thread, or after the last "Best,/Regards,/Thanks,/Kind regards"
// closer). We walk those anchors and mine the 6-10 lines that follow.
export function parseSignature(bodyRaw: string): ParsedSignature {
  const body = (bodyRaw || "")
    .replace(/\r\n?/g, "\n")
    .replace(/[ \t]+\n/g, "\n");

  // Strip quoted lines (lines starting with >) before searching
  const cleaned = body
    .split("\n")
    .filter((line) => !/^\s*>/.test(line))
    .join("\n");

  // Find signature anchor
  const sigAnchorRegex =
    /\n\s*(--|—|best(?:\s+regards)?,|kind regards,|warm(?:ly|est|est regards)?,|regards,|thanks,|thank\s+you,|cheers,|sincerely,|yours(?:\s+sincerely)?,|all the best,|talk soon,|speak soon,)\s*\n/i;
  const match = cleaned.match(sigAnchorRegex);

  const tail = match
    ? cleaned.slice(match.index! + match[0].length)
    : cleaned.slice(-1200); // fallback: last 1.2k chars

  const lines = tail
    .split("\n")
    .map((l) => l.trim())
    .filter((l) => l.length > 0 && l.length < 200)
    .slice(0, 15);

  // Phone: international-ish or US/EU formats
  const phoneRegex =
    /(?:\+?\d[\d\s().-]{7,}\d)|(?:\(\d{2,4}\)\s?\d{3,}[\s-]?\d{3,})/;
  // LinkedIn
  const linkedinRegex =
    /https?:\/\/(?:[a-z]{2,3}\.)?linkedin\.com\/(?:in|company)\/[A-Za-z0-9_\-]+/i;
  // Website (non-linkedin, non-email)
  const websiteRegex =
    /https?:\/\/(?!(?:[a-z]{2,3}\.)?linkedin\.com)[^\s<>]+/i;

  let phone: string | null = null;
  let linkedinUrl: string | null = null;
  let website: string | null = null;
  let name: string | null = null;
  let title: string | null = null;
  let company: string | null = null;

  // Name heuristic: first line that looks like a human name
  // (2-4 words, mostly letters, no email/URL/phone/company markers).
  for (const line of lines) {
    if (
      !name &&
      /^[A-Z][a-zA-Z'.-]*(?:\s[A-Z][a-zA-Z'.-]*){1,3}$/.test(line) &&
      !/\b(inc|llc|ltd|gmbh|corp|co\.?|company|agency|studios?|group|enterprises?|global|ventures?|holdings?|consulting|partners|advisors?)\b/i.test(line)
    ) {
      name = line;
      continue;
    }
    if (!phone) {
      const m = line.match(phoneRegex);
      if (m) phone = m[0].replace(/\s+/g, " ").trim();
    }
    if (!linkedinUrl) {
      const m = line.match(linkedinRegex);
      if (m) linkedinUrl = m[0];
    }
    if (!website) {
      const m = line.match(websiteRegex);
      if (m) website = m[0];
    }
    // Title pattern: "Chief X", "VP of X", "Director of X", "Founder & CEO", etc.
    if (!title && /^(chief|founder|co[- ]founder|vp|vice president|president|director|head of|managing|senior|principal|partner|ceo|cto|cfo|coo|cmo|owner|broker|agent|advisor|consultant|manager|lead)\b/i.test(line)) {
      title = line;
    }
    // Company pattern: line containing typical suffix
    if (!company && /\b(inc|llc|ltd|gmbh|s\.a\.|sa|corp|co\.?|company|agency|group|ventures?|holdings?|consulting|partners|advisors?|collection|studios?|enterprises?)\b/i.test(line)) {
      company = line;
    }
  }

  return { name, title, company, phone, linkedinUrl, website };
}

// Merge-if-missing: only fill fields that are currently null on the
// contact. Never overwrite existing values (user edits are sacred).
export function mergeContactFields<T extends Record<string, any>>(
  existing: T,
  incoming: Partial<T>,
): Partial<T> {
  const updates: Partial<T> = {};
  for (const [k, v] of Object.entries(incoming)) {
    if (v === null || v === undefined || v === "") continue;
    if (existing[k] === null || existing[k] === undefined || existing[k] === "") {
      (updates as any)[k] = v;
    }
  }
  return updates;
}

// Warmup-email detector.
//
// Cold-outreach warmup services (Mailwarm, Lemwarm, Smartlead, Warmup
// Inbox, Warmy, Warmbox, Instantly, Folderly, etc.) build sender
// reputation by swapping fake "human" emails between participant
// inboxes. They flood george@ and eleanna@ with thousands of
// "thanks!", "got it", "looks good" replies every week.
//
// We detect them with three lines of defence, strongest first:
//
//   1. Service-specific headers (X-Mailwarm, X-Lemwarm, X-Warmup-*,
//      X-Smartlead-Warmup, etc.) — these are added by the service
//      itself and are a definitive tell.
//   2. Message-ID domain — most services route through a dedicated
//      subdomain (@send.warmup-inbox.com, @mailwarm.com, etc.).
//   3. Content heuristic — very short body + generic 1-2-word reply
//      matching the classic warmup template ("thanks!", "got it",
//      "perfect", "noted", "will do", etc.).
//
// Any match → email is archived out of inbox and never touches the
// CRM. Full stop.

export type WarmupVerdict = {
  isWarmup: boolean;
  reason?: string;
  service?: string;
};

// Gmail header keys come lowercased from our cron (headersMap).
const SERVICE_HEADER_MARKERS: Array<[RegExp, string]> = [
  [/^x-mailwarm/, "mailwarm"],
  [/^x-lemwarm/, "lemwarm"],
  [/^x-warmup-inbox/, "warmup-inbox"],
  [/^x-warmupinbox/, "warmup-inbox"],
  [/^x-smartlead-warmup/, "smartlead"],
  [/^x-smartlead/, "smartlead"],
  [/^x-warmy/, "warmy"],
  [/^x-warmbox/, "warmbox"],
  [/^x-instantly-warmup/, "instantly"],
  [/^x-instantly/, "instantly"],
  [/^x-folderly/, "folderly"],
  [/^x-mailshake-warmup/, "mailshake"],
  [/^x-allegrow/, "allegrow"],
  [/^x-mailreach/, "mailreach"],
  [/^x-warmer/, "warmer"],
  [/^x-mailflow/, "mailflow"],
  [/^x-gmass-warmup/, "gmass"],
  [/^x-warmeer/, "warmeer"],
  [/^x-toldu/, "toldu"],
];

const MSG_ID_MARKERS: Array<[RegExp, string]> = [
  [/@(?:[\w-]+\.)*mailwarm\./i, "mailwarm"],
  [/@(?:[\w-]+\.)*warmup-inbox\./i, "warmup-inbox"],
  [/@(?:[\w-]+\.)*warmupinbox\./i, "warmup-inbox"],
  [/@(?:[\w-]+\.)*lemwarm\./i, "lemwarm"],
  [/@(?:[\w-]+\.)*smartlead\./i, "smartlead"],
  [/@(?:[\w-]+\.)*instantly\.(?:ai|com)/i, "instantly"],
  [/@(?:[\w-]+\.)*warmy\./i, "warmy"],
  [/@(?:[\w-]+\.)*warmbox\./i, "warmbox"],
  [/@(?:[\w-]+\.)*folderly\./i, "folderly"],
  [/@(?:[\w-]+\.)*mailreach\./i, "mailreach"],
  [/@(?:[\w-]+\.)*allegrow\./i, "allegrow"],
  [/@(?:[\w-]+\.)*mailshake\.com/i, "mailshake"],
  [/warmup[_-](?:reply|msg|id|send)/i, "generic-warmup"],
];

// Body/subject content shortcuts — only a *very* short body that is
// ALSO a classic warmup template string counts. We want zero
// false-positives for real prospects who happen to reply briefly.
const WARMUP_BODY_TEMPLATES =
  /^\s*(?:(?:great|thanks|thank\s+you|got\s+it|received|on\s+it|perfect|noted|sounds\s+good|will\s+do|appreciate\s+it|appreciate\s+this|cheers|awesome|nice|excellent|brilliant|amazing|wonderful|fantastic|looking\s+forward(?:\s+to\s+it)?|sure\s+thing|absolutely|of\s+course|agreed|sounds\s+great|looks\s+good|👍|😀|🙏)[.!]*\s*){1,4}$/i;

const WARMUP_SIGNATURE_HINTS = /(?:warmup|engagement\s*booster|deliverability\s*test|sender\s+reputation)/i;

// Instantly.ai warmup tracker subjects end with " | XXXXXXX YYYYYYY"
// — two uppercase alphanumeric tokens (6–10 chars) separated by a
// space, after a pipe. The first token is per-message, the second
// token is the recipient's warmup ID and stays constant for a given
// mailbox. Real prospect emails almost never end with this exact
// shape because legit subjects either:
//   • don't have a trailing " | TOKEN TOKEN" suffix at all,
//   • or end in single trailing words / shorter all-caps acronyms
//     that the {6,10} bound rejects.
//
// Live samples collected 2026-04-30 from George's inbox:
//   "A better way to reach your target MRR | EK438PD F8NWHHW"
//   "Eleanna - need to touch base | B1VPBNW F8NWHHW"
//   "commission-based ? | EWNCAB5 F8NWHHW"
//
// All three slipped through the existing header / body / msg-id
// rules because Instantly's warmup uses real Gmail/Outlook mailboxes
// (no x-instantly-warmup header lands in the recipient's copy) and
// the body text is varied enough to dodge WARMUP_BODY_TEMPLATES.
const INSTANTLY_SUBJECT_TRACKER =
  /\|\s+[A-Z0-9]{6,10}\s+[A-Z0-9]{6,10}\s*$/;

function stripThreadTail(body: string): string {
  // Kill quoted lines + "On … wrote:" blocks that warmup services don't have.
  return (body || "")
    .replace(/\r\n?/g, "\n")
    .split("\n")
    .filter((l) => !/^\s*>/.test(l))
    .join("\n")
    .split(/\bOn\b [^\n]{4,120}\bwrote:/i)[0]
    .split(/[\r\n]{1,2}-{2,} *(Original Message|Forwarded message|Original Mail)/i)[0]
    .trim();
}

export function detectWarmup(args: {
  from: string;
  subject: string;
  body: string;
  headers: Record<string, string>;
}): WarmupVerdict {
  // 1. Service-specific headers
  for (const key of Object.keys(args.headers)) {
    for (const [pattern, service] of SERVICE_HEADER_MARKERS) {
      if (pattern.test(key)) {
        return { isWarmup: true, reason: `header:${key}`, service };
      }
    }
  }

  // 2. Message-ID domain fingerprint (includes X-Original-Message-ID
  //    for forwarded warmup mail)
  const candidateIds = [
    args.headers["message-id"],
    args.headers["x-original-message-id"],
    args.headers["references"],
    args.headers["in-reply-to"],
  ]
    .filter(Boolean)
    .join(" ");
  for (const [pattern, service] of MSG_ID_MARKERS) {
    if (pattern.test(candidateIds)) {
      return { isWarmup: true, reason: "msg-id domain", service };
    }
  }

  // 3. Subject-trailer fingerprint — Instantly tracker codes.
  //    Matches " | XXXXXXX YYYYYYY" at end of subject. Run BEFORE
  //    the body heuristic because the tracker shape is more specific.
  if (INSTANTLY_SUBJECT_TRACKER.test(args.subject || "")) {
    return { isWarmup: true, reason: "subject-tracker", service: "instantly" };
  }

  // 4. Content heuristic — very short + matches classic templates.
  //    Keeps a tight ceiling (≤120 chars, after stripping thread tails
  //    and signatures) so real prospects' brief replies still pass.
  const trimmed = stripThreadTail(args.body).trim();
  if (trimmed.length > 0 && trimmed.length <= 120 && WARMUP_BODY_TEMPLATES.test(trimmed)) {
    return { isWarmup: true, reason: "template-body", service: "generic" };
  }
  if (WARMUP_SIGNATURE_HINTS.test(trimmed)) {
    return { isWarmup: true, reason: "signature-hint", service: "generic" };
  }

  return { isWarmup: false };
}

// Facebook Page publishing client.
//
// Posts to the George Yachts corporate Page (ID 61579547047989) via the
// Meta Graph API. Reuses the existing IG_ACCESS_TOKEN — since the IG
// Business account is linked to this Page, one call to /me/accounts
// hands back a Page Access Token we can cache.
//
// We cache the Page token in Supabase `settings` under key
// `fb_page_token` the first time we see it, and refresh lazily if the
// Graph API returns 190 (OAuth token invalid).

import { createServiceClient } from "@/lib/supabase-server";

const GRAPH = "https://graph.facebook.com/v21.0";
// Single source of truth for the FB Page ID. Re-exported so other
// modules (blog-social-publisher.ts, future FB integrations) read from
// here rather than hardcoding the literal — prevents drift if the
// Page ID ever changes.
export const FB_PAGE_ID = process.env.FB_PAGE_ID || "1056750427517361";
const PAGE_ID = FB_PAGE_ID;

type Ok<T> = { ok: true } & T;
type Err = { ok: false; error: string };
type Result<T> = Ok<T> | Err;

// Token strategy: prefer the permanent Page Access Token minted via the
// System User flow (FB_PAGE_ACCESS_TOKEN — never expires). If absent,
// fall back to exchanging IG_ACCESS_TOKEN via /me/accounts and caching.
async function getPageToken(): Promise<string> {
  const direct = process.env.FB_PAGE_ACCESS_TOKEN;
  if (direct) return direct;
  const sb = createServiceClient();
  const { data: row } = await sb
    .from("settings")
    .select("value")
    .eq("key", "fb_page_token")
    .maybeSingle();
  if (row?.value) return row.value as string;
  return refreshPageToken();
}

async function refreshPageToken(): Promise<string> {
  const userToken =
    process.env.FB_USER_ACCESS_TOKEN || process.env.IG_ACCESS_TOKEN;
  if (!userToken) throw new Error("FB_USER_ACCESS_TOKEN / IG_ACCESS_TOKEN missing");
  const res = await fetch(`${GRAPH}/me/accounts?access_token=${userToken}`);
  const json = await res.json();
  if (!res.ok) throw new Error(`/me/accounts failed: ${JSON.stringify(json)}`);
  const page = (json.data ?? []).find((p: any) => p.id === PAGE_ID);
  if (!page?.access_token) {
    throw new Error(
      `Page ${PAGE_ID} not found in /me/accounts. Available: ${(json.data ?? [])
        .map((p: any) => `${p.name} (${p.id})`)
        .join(", ")}`
    );
  }
  const sb = createServiceClient();
  await sb
    .from("settings")
    .upsert({ key: "fb_page_token", value: page.access_token });
  return page.access_token;
}

async function callGraph(
  path: string,
  body: Record<string, string>,
  retried = false
): Promise<any> {
  const token = await getPageToken();
  const params = new URLSearchParams({ ...body, access_token: token });
  const res = await fetch(`${GRAPH}${path}`, {
    method: "POST",
    body: params,
  });
  const json = await res.json();
  if (res.ok) return json;
  // OAuth token invalid → refresh and retry once. Skipped when
  // FB_PAGE_ACCESS_TOKEN is hardcoded (permanent token can't be refreshed).
  if (
    !retried &&
    json?.error?.code === 190 &&
    !process.env.FB_PAGE_ACCESS_TOKEN
  ) {
    await refreshPageToken();
    return callGraph(path, body, true);
  }
  throw new Error(json?.error?.message ?? `HTTP ${res.status}`);
}

export async function publishPhoto(args: {
  photoUrl: string;
  caption: string;
}): Promise<Result<{ post_id: string }>> {
  try {
    const json = await callGraph(`/${PAGE_ID}/photos`, {
      url: args.photoUrl,
      caption: args.caption,
      published: "true",
    });
    return { ok: true, post_id: json.post_id ?? json.id };
  } catch (e: any) {
    return { ok: false, error: e.message };
  }
}

export async function publishPhotoCarousel(args: {
  photoUrls: string[];
  caption: string;
}): Promise<Result<{ post_id: string }>> {
  try {
    // Upload each photo unpublished, collect media_fbids, then create
    // one feed post attaching all of them.
    const mediaIds: string[] = [];
    for (const url of args.photoUrls.slice(0, 10)) {
      const up = await callGraph(`/${PAGE_ID}/photos`, {
        url,
        published: "false",
      });
      mediaIds.push(up.id);
    }
    const attached: Record<string, string> = { message: args.caption };
    mediaIds.forEach((id, i) => {
      attached[`attached_media[${i}]`] = JSON.stringify({ media_fbid: id });
    });
    const post = await callGraph(`/${PAGE_ID}/feed`, attached);
    return { ok: true, post_id: post.id };
  } catch (e: any) {
    return { ok: false, error: e.message };
  }
}

export async function publishVideo(args: {
  videoUrl: string;
  caption: string;
}): Promise<Result<{ post_id: string }>> {
  try {
    const json = await callGraph(`/${PAGE_ID}/videos`, {
      file_url: args.videoUrl,
      description: args.caption,
    });
    return { ok: true, post_id: json.id };
  } catch (e: any) {
    return { ok: false, error: e.message };
  }
}

export async function listPages(): Promise<any> {
  const userToken = process.env.IG_ACCESS_TOKEN;
  if (!userToken) return { error: "IG_ACCESS_TOKEN missing" };
  const res = await fetch(`${GRAPH}/me/accounts?access_token=${userToken}`);
  return res.json();
}

