export function angleEligibleForYacht(
  yacht: FleetYacht,
  angle: FleetAngle,
): { eligible: boolean; reason?: string } {
  switch (angle) {
    case "inside_info": {
      const len = (yacht.georgeInsiderTip ?? "").trim().length;
      return len >= 200
        ? { eligible: true }
        : {
            eligible: false,
            reason: `georgeInsiderTip too short (${len} chars, need 200)`,
