]);

const HINDU_COUNTRIES = new Set([
  "IN", "India",
  "NP", "Nepal",
  "MU", "Mauritius",
]);

const JEWISH_COUNTRIES = new Set([
  "IL", "Israel",
]);

const MUSLIM_NAME_PREFIXES = [
  "mohammed", "mohamed", "muhammad", "ahmad", "ahmed", "ali",
  "hassan", "hussein", "omar", "youssef", "yusuf", "khalid",
  "fatima", "aisha", "khadija", "abdul", "abu",
];

const HINDU_NAME_PREFIXES = [
  "raj", "rahul", "amit", "anil", "rakesh", "vijay", "vikram",
  "priya", "anjali", "deepika", "kavya", "neha",
];

export function inferReligion(opts: {
  country?: string | null;
  first_name?: string | null;
  last_name?: string | null;
  email?: string | null;
}): Religion {
  const country = opts.country?.trim();
  const first = opts.first_name?.trim().toLowerCase() ?? "";
  const last = opts.last_name?.trim().toLowerCase() ?? "";
  const emailDomain =
    opts.email?.split("@")[1]?.toLowerCase().trim() ?? "";

  // STRONGEST: Greek name pattern → orthodox (regardless of country —
  // Greek diaspora is overwhelmingly Orthodox even in US/UK/AU)
  if (first && GREEK_FIRST_NAMES.has(first)) return "orthodox";
  if (last && GREEK_NAME_RE.test(last)) return "orthodox";

  // Greek email domain → orthodox
  if (emailDomain.endsWith(".gr") || emailDomain.endsWith(".cy")) {
    return "orthodox";
  }

  // STRONG: name signals override Western country defaults for
  // Muslim / Hindu names
  if (first) {
    if (MUSLIM_NAME_PREFIXES.some((p) => first.startsWith(p))) return "muslim";
    if (HINDU_NAME_PREFIXES.some((p) => first.startsWith(p))) return "hindu";
  }

  // Country-based — but ONLY for explicit signals. The old behaviour
  // assigned protestant to anyone in US/UK/etc which inflated the
  // protestant count to 73% (impossible for a Greek broker). Now
  // country gives religion ONLY when the country is explicitly set.
  if (!country) return "unknown";
  if (ORTHODOX_COUNTRIES.has(country)) return "orthodox";
  if (MUSLIM_COUNTRIES.has(country)) return "muslim";
  if (HINDU_COUNTRIES.has(country)) return "hindu";
  if (JEWISH_COUNTRIES.has(country)) return "jewish";
  // Catholic / Protestant — only when there's no Greek-name evidence
  // (already checked above).
  if (CATHOLIC_COUNTRIES.has(country)) return "catholic";
  if (PROTESTANT_COUNTRIES.has(country)) return "protestant";
  return "unknown";
}

// @ts-nocheck
/**
 * Rate-limit circuit breaker for all Instagram-acting crons.
 *
 * Roberto brief v3 — Phase 0.5 (Meta Rate Limits Bible).
 *
 * Every cron that hits the Instagram Graph API calls `checkRateLimitHealth`
 * before doing its work. If the 70%-of-cap ceiling is hit for either the
 * hourly OR the daily window, the cron exits silently and fires a single
 * Telegram alert. Prevents us from ever getting close to Meta's hard caps
 * (which cause shadowbans, not just HTTP errors).
 *
 * Action log storage: piggybacks on the existing `settings` key-value
 * table — one row per action firing, key = `rl_<action>_<nanoid>`,
 * `updated_at` = time of the action. Zero DDL required, same pattern
 * the story rotation fix uses. Pruned automatically by `pruneOldLogs`
 * on every check so the table never bloats.
 *
 * If the settings write fails the cron still runs (fail-open) — we care
 * more about staying live than about perfect accounting. The Telegram
 * alert still fires so George knows.
 */

import { createServiceClient } from "./supabase-server";
import { sendTelegram } from "./telegram";

export type RateLimitAction =
  | "post_publish" // feed post, carousel, reel — IG /media + /media_publish
  | "story_publish" // IG stories
  | "comment_outbound" // our proactive comments on other accounts' posts
  | "comment_reply" // auto-replies on OUR post comments
  | "dm_send" // outbound DMs
  | "api_call"; // catch-all for any Graph API call that doesn't fit the above

// 70% of Meta's documented hard caps (Feb 2026). Updating these is the
// single dial to tighten/loosen throttling without touching any cron.
// Hard caps for reference:
//   posts: 100/24h hard, ~10/hour burst
//   stories: ~100/24h soft
//   comments posted: ~30-40/hour (bot detection threshold)
//   comment replies on our posts: 750/hour
//   dm send: 200/hour
//   api calls: 200/hour per account (4800/h high-trust)
const CAPS: Record<RateLimitAction, { hourly: number; daily: number | null }> = {
  post_publish: { hourly: 15, daily: 70 },
  story_publish: { hourly: 10, daily: 70 },
  comment_outbound: { hourly: 25, daily: 150 },
  comment_reply: { hourly: 500, daily: 2000 },
  dm_send: { hourly: 140, daily: 500 },
  api_call: { hourly: 140, daily: null },
};

const PRUNE_AFTER_DAYS = 7;

// ─────────────────────────────────────────────────────────────────────
// Public API
// ─────────────────────────────────────────────────────────────────────

/**
 * Call before taking an action. Returns true if safe to proceed.
 * Returns false + fires a single Telegram alert if near a cap.
 *
 *   if (!(await checkRateLimitHealth("post_publish"))) {
 *     return NextResponse.json({ skipped: "rate_limit" });
 *   }
 */
export async function checkRateLimitHealth(
  action: RateLimitAction,
): Promise<boolean> {
  const sb = createServiceClient();
  const cap = CAPS[action];

  // Opportunistic prune — cheap, keeps the settings table bounded.
  pruneOldLogs(sb).catch(() => {});

  // Global pause flag — flipped by the health check cron on RED.
  // One switch, all crons stop.
  const { data: pausedRow } = await sb
    .from("settings")
    .select("value")
    .eq("key", "crons_paused")
    .maybeSingle();
  if (pausedRow?.value === "true") {
    return false;
  }

  // Count rows in the rolling windows. We use updated_at (auto-stamped
  // on insert) instead of parsing the JSON value for speed.
  const now = Date.now();
  const hourAgo = new Date(now - 60 * 60 * 1000).toISOString();
  const dayAgo = new Date(now - 24 * 60 * 60 * 1000).toISOString();

  const hourlyCount = await countSince(sb, action, hourAgo);
  if (hourlyCount >= cap.hourly) {
    await sendTelegram(
      `⚠ <b>Rate limit circuit breaker</b>\nAction: <code>${action}</code>\nHourly: ${hourlyCount}/${cap.hourly} — auto-paused this cron.`,
    );
    return false;
  }

  if (cap.daily !== null) {
    const dailyCount = await countSince(sb, action, dayAgo);
    if (dailyCount >= cap.daily) {
      await sendTelegram(
        `⚠ <b>Daily cap approaching</b>\nAction: <code>${action}</code>\nLast 24h: ${dailyCount}/${cap.daily} — auto-paused until reset.`,
      );
      return false;
    }
  }

  return true;
}

/**
 * Record that an action just happened. Call this AFTER the IG API call
 * returned success. Safe to call from multiple concurrent invocations —
 * key collisions are extraordinarily unlikely and the worst case is one
 * extra row.
 */
export async function logRateLimitAction(
  action: RateLimitAction,
  metadata?: Record<string, unknown>,
): Promise<void> {
  const sb = createServiceClient();
  const id = generateId();
  const key = `rl_${action}_${id}`;
  const value = JSON.stringify({
    action,
    at: Date.now(),
    ...(metadata ? { meta: metadata } : {}),
  });
  try {
    await sb
      .from("settings")
      .insert({ key, value, updated_at: new Date().toISOString() });
  } catch {
    // Fail-open — logging failure never blocks the real action.
  }
}

/**
 * Add a random 0-120 second delay to a cron execution. Every IG-facing
 * publish cron calls this once at the start. Spreads our activity
 * across the clock so we don't look like a bot firing at X:00:00.
 *
 * Why 120s and not 15 minutes like the brief suggested:
 * Vercel serverless functions cap at 300s on Pro (our plan) and 60s
 * on Hobby. A jitter up to 15 min (900s) silently killed ~40% of
 * publish invocations with 504 Gateway Timeout — confirmed by
 * runtime logs on 2026-04-20. With jitter capped at 120s, we still
 * break the exact-on-the-minute bot signal (Meta's detection) while
 * leaving plenty of headroom (180s) for carousel container creation,
 * processing poll, and publish.
 *
 * For local dev, set DISABLE_IG_JITTER=1 to skip the wait.
 */
const JITTER_MAX_MS = 120 * 1000;

export async function applyPublishJitter(): Promise<void> {
  if (process.env.DISABLE_IG_JITTER === "1") return;
  const jitterMs = Math.floor(Math.random() * JITTER_MAX_MS);
  if (jitterMs < 100) return; // trivial, skip the log noise
  console.log(`[jitter] sleeping ${(jitterMs / 1000).toFixed(1)}s`);
  await new Promise((r) => setTimeout(r, jitterMs));
}

// ─────────────────────────────────────────────────────────────────────
// Internals
// ─────────────────────────────────────────────────────────────────────

async function countSince(
  sb: ReturnType<typeof createServiceClient>,
  action: RateLimitAction,
  sinceIso: string,
): Promise<number> {
  const { count } = await sb
    .from("settings")
    .select("*", { count: "exact", head: true })
    .like("key", `rl_${action}_%`)
    .gt("updated_at", sinceIso);
  return count ?? 0;
}

async function pruneOldLogs(
  sb: ReturnType<typeof createServiceClient>,
): Promise<void> {
  const cutoff = new Date(
    Date.now() - PRUNE_AFTER_DAYS * 24 * 60 * 60 * 1000,
  ).toISOString();
  await sb.from("settings").delete().like("key", "rl_%").lt("updated_at", cutoff);
}

function generateId(): string {
  // 10 chars base36, collision-safe enough for our volume.
  return Math.random().toString(36).slice(2, 12) + Date.now().toString(36);
}

// @ts-nocheck
/**
 * Sanity CMS fleet fetcher.
 *
 * Phase D.1 — pulls yacht documents from the public `ecqr94ey`
 * production dataset via the CDN REST API. No @sanity/client dep
 * needed (the fetches are read-only, public, and simple GROQ queries).
 *
 * Pool filter applied at query level: `count(images) >= 6`. Yachts
 * below that threshold can't produce a carousel of 5+ slides, so we
 * never surface them — independent of per-angle eligibility which is
 * decided later in fleet-rotation.ts.
 */

const SANITY_PROJECT = "ecqr94ey";
const SANITY_DATASET = "production";
const SANITY_API_VERSION = "2024-01-01";

// CDN endpoint is fine for read-only fleet queries (fresher than raw
// API for our 2026 latency profile, public dataset, no auth needed).
const SANITY_CDN = `https://${SANITY_PROJECT}.apicdn.sanity.io/v${SANITY_API_VERSION}/data/query/${SANITY_DATASET}`;

export type FleetYacht = {
  _id: string;
  name: string;
  slug: string | null;
  subtitle: string | null;
  category:
    | "motor-yachts"
    | "sailing-catamarans"
    | "power-catamarans"
    | "sailing-monohulls"
    | null;
  fleetTier: "private" | "explorer" | "both" | null;
  georgeInsiderTip: string | null;
  length: string | null;
  sleeps: string | null;
  cabins: string | null;
  crew: string | null;
  builder: string | null;
  yearBuiltRefit: string | null;
  cruisingRegion: string | null;
  weeklyRatePrice: string | null;
  features: string[];
  toys: string[];
  idealFor: string | null;
  images: Array<{ url: string; alt: string | null }>;
};

const FLEET_QUERY = `*[_type == "yacht" && count(images) >= 6]{
  _id,
  name,
  "slug": slug.current,
  subtitle,
  category,
  fleetTier,
  georgeInsiderTip,
  length,
  sleeps,
  cabins,
  crew,
  builder,
  yearBuiltRefit,
  cruisingRegion,
  weeklyRatePrice,
  "features": coalesce(features, []),
  "toys": coalesce(toys, []),
  idealFor,
  "images": images[]{
    "url": asset->url,
    alt
  }
}`;

/**
 * Fetch the full fleet pool (yachts with ≥6 images).
 * Returns [] on any error so the caller can fall back silently.
 */
export async function fetchFleetPool(): Promise<FleetYacht[]> {
  try {
    const url = `${SANITY_CDN}?query=${encodeURIComponent(FLEET_QUERY)}`;
    const res = await fetch(url, {
      // Don't ISR-cache — fleet data (especially prices) should refresh
      // on every cron firing. Sanity's CDN already caches server-side
      // so this isn't a cost issue.
      cache: "no-store",
    });
    if (!res.ok) return [];
    const body = await res.json();
    const result = Array.isArray(body?.result) ? body.result : [];
    return result.filter((y: any) => y && y._id && y.name);
  } catch {
    return [];
  }
}

/**
 * Fetch a single yacht by Sanity _id. Used by the dryrun endpoint.
 */
export async function fetchYachtById(id: string): Promise<FleetYacht | null> {
  try {
    const query = `*[_type == "yacht" && _id == $id][0]{
      _id, name, "slug": slug.current, subtitle, category, fleetTier,
      georgeInsiderTip, length, sleeps, cabins, crew, builder,
      yearBuiltRefit, cruisingRegion, weeklyRatePrice,
      "features": coalesce(features, []),
      "toys": coalesce(toys, []),
      idealFor,
      "images": images[]{ "url": asset->url, alt }
    }`;
    const url = `${SANITY_CDN}?query=${encodeURIComponent(query)}&$id=${encodeURIComponent(JSON.stringify(id))}`;
    const res = await fetch(url, { cache: "no-store" });
    if (!res.ok) return null;
    const body = await res.json();
    return body?.result ?? null;
  } catch {
    return null;
  }
}

/**
 * Build the UTM campaign string for a fleet post. Logged so the bio
 * link page (future Phase) can surface the right active campaign.
 */
export function buildFleetUTM(yacht: FleetYacht, angle: string): string {
  const slug = (yacht.slug ?? yacht._id).replace(/[^a-z0-9-]/gi, "-").toLowerCase();
  const params = new URLSearchParams({
    utm_source: "instagram",
    utm_medium: "bio",
    utm_campaign: `boat_${slug}`,
    utm_content: `angle_${angle}`,
  });
  return `https://georgeyachts.com/ig?${params.toString()}`;
}

