export function isSoundEnabled(): boolean {
  if (typeof window === 'undefined') return false;
  const saved = localStorage.getItem('gy-sounds');
  if (saved !== null) {
    soundEnabled = saved !== 'off';
  }
  return soundEnabled;
}

