/**
 * Send a message to the configured Telegram chat via Bot API.
 *
 * Hardened 2026-04-23 after the gmail-poll 05:48 incident where ~40
 * HOT/WARM classifications fired in a single tick and hit Telegram's
 * per-chat rate limit (≈1 msg/sec per chat, ≈30/sec global), producing
 * the runtime-log 429 storm.
 *
 * Two layers of protection:
 *   1. **Global serialization** — a module-scoped promise chain so no
 *      two sendTelegram() calls ever run concurrently. We also space
 *      sends by 1100ms minimum to stay inside the 1/sec per-chat cap.
 *   2. **429 retry with honored retry_after** — on 429, we read the
 *      Telegram response's retry_after field, sleep exactly that long
 *      (+250ms jitter), then retry once. No infinite loops.
 *
 * Return value unchanged: true on success, false on any failure.
 */
const MIN_GAP_MS = 1100;
let chain: Promise<unknown> = Promise.resolve();
let lastSendAt = 0;

function sleep(ms: number): Promise<void> {
  return new Promise((r) => setTimeout(r, ms));
}

async function sendOnce(
  token: string,
  chatId: string,
  message: string,
  disablePreview: boolean,
): Promise<{ ok: boolean; retryAfter?: number; status: number; body: string }> {
  const res = await fetch(
    `https://api.telegram.org/bot${token}/sendMessage`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        chat_id: chatId,
        text: message,
        parse_mode: "HTML",
        ...(disablePreview && { disable_web_page_preview: true }),
      }),
    },
  );
  const body = await res.text();
  if (res.ok) return { ok: true, status: res.status, body };
  let retryAfter: number | undefined;
  if (res.status === 429) {
    try {
      const parsed = JSON.parse(body);
      if (typeof parsed?.parameters?.retry_after === "number") {
        retryAfter = parsed.parameters.retry_after;
      }
    } catch {
      /* fall through */
    }
  }
  return { ok: false, status: res.status, body, retryAfter };
}

export async function sendTelegram(
  message: string,
  opts?: { disablePreview?: boolean },
): Promise<boolean> {
  const token =
    process.env.TELEGRAM_BOT_TOKEN ||
    "8773911706:AAFixtS_3kQLWB4G3FL9vMt4v5AKh9sNtqo";
  const chatId = process.env.TELEGRAM_CHAT_ID || "8478263770";

  if (!token || !chatId) {
    console.warn("[Telegram] Missing TELEGRAM_BOT_TOKEN or TELEGRAM_CHAT_ID");
    return false;
  }

  const disablePreview = !!opts?.disablePreview;

  const task = async (): Promise<boolean> => {
    // Respect min-gap since last send (serialized via chain → safe).
    const gap = Date.now() - lastSendAt;
    if (gap < MIN_GAP_MS) await sleep(MIN_GAP_MS - gap);

    try {
      let r = await sendOnce(token, chatId, message, disablePreview);
      if (!r.ok && r.status === 429 && r.retryAfter != null) {
        const wait = Math.min(r.retryAfter * 1000 + 250, 30_000);
        console.warn(`[Telegram] 429 — sleeping ${wait}ms then retrying`);
        await sleep(wait);
        r = await sendOnce(token, chatId, message, disablePreview);
      }
      lastSendAt = Date.now();
      if (!r.ok) {
        console.error("[Telegram] Send failed:", r.status, r.body.slice(0, 200));
        return false;
      }
      return true;
    } catch (err) {
      lastSendAt = Date.now();
      console.error("[Telegram] Network error:", err);
      return false;
    }
  };

  // Serialize all sends module-wide.
  const next = chain.then(task, task);
  chain = next.catch(() => undefined);
  return next;
}

// Sprint 2.2 — AI-generated suggested action per cockpit thread.
//
// Per refocus brief §2.3: "Each row shows a one-line suggested
// action. This is the difference between a list and a strategist."
//
// Examples from the brief:
//   "Reply to Villy's meeting request — offer 3 slots in her 20–24
//    April window (now overdue)"
//   "Send catamaran package to Domenico (committed Monday 4/5)"
//   "Final follow-up on Halilcan — engage or close, this is the
//    last touch"
//
// Generated nightly per top-N threads (cost cap) and cached on the
// contact row (next-touch_suggestion + next_touch_suggestion_at).
// Only regenerated when the inbox state changes meaningfully.

import { aiChat } from "@/lib/ai";

export interface ThreadContext {
  contact_name: string;
  inbox_stage: string;
  gap_days: number;
  last_direction: "inbound" | "outbound" | null;
  last_subject: string | null;
  last_snippet: string | null;
  pipeline_stage: string | null;
  charter_fee: number | null;
  open_commitments: Array<{
    summary: string;
    deadline_date: string | null;
    days_overdue: number;
  }>;
  health_score: number | null;
}

const SYSTEM = `You write a single-line suggested action for George (a yacht broker) based on one inbox thread's state.

CRITICAL OUTPUT RULES:
- Output ONLY raw JSON. NO markdown fences. NO prose.
- Schema: {"suggestion":"<≤120 chars action with rationale in parens>"}

Style:
- Imperative voice: "Reply to X with…", "Send Y package", "Final follow-up on…"
- Reference the specific commitment / deadline / state when present
- Add the "why" in parens: (now overdue), (committed Monday), (last touch before close)
- Greek or English — match the contact's language if obvious
- Never generic ("Follow up with X"). Always specific.

Examples:
- "Reply to Villy's meeting request — offer 3 slots in her 20-24 April window (now overdue)"
- "Send Domenico the catamaran package + Kyllini report (committed Monday 4/5)"
- "Final follow-up on Halilcan — engage or close, this is the last touch"
- "No action needed — Lisa parked herself until end of 2026"`;

export async function suggestAction(
  ctx: ThreadContext,
): Promise<string | null> {
  const userMsg = JSON.stringify(ctx);
  let raw: string;
  try {
    raw = await aiChat(SYSTEM, userMsg, { maxTokens: 200, temperature: 0.4 });
  } catch {
    return null;
  }
  const cleaned = raw
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/```\s*$/i, "")
    .trim();
  const m = cleaned.match(/\{[\s\S]*\}/);
  if (!m) return null;
  try {
    const parsed = JSON.parse(m[0]) as { suggestion?: string };
    if (parsed.suggestion && parsed.suggestion.length > 0) {
      return parsed.suggestion.slice(0, 200);
    }
    return null;
  } catch {
    return null;
  }
}

/**
 * Composite priority score 0-100 (per brief §2.2).
 * Combines stage band + sentiment + relationship tier + deal value
 * + commitment + parked penalty + decline penalty into a single
 * decision-ready number.
 */
export function compositePriorityScore(ctx: {
  inbox_stage: string;
  gap_days: number;
  starred: boolean;
  pipeline_stage: string | null;
  charter_fee: number | null;
  health_score: number | null;
  has_open_commitment: boolean;
  has_overdue_commitment: boolean;
  parked_until: string | null;
  declined_at: string | null;
}): number {
  if (ctx.declined_at) return 0;
  if (
    ctx.parked_until &&
    new Date(ctx.parked_until) > new Date()
  )
    return 0;

  let s = 0;
  // Stage band (0-40)
  switch (ctx.inbox_stage) {
    case "owed_reply":
      s += ctx.gap_days <= 7 ? 40 : ctx.gap_days <= 30 ? 30 : 20;
      break;
    case "new_lead":
      s += 32;
      break;
    case "needs_followup":
      s += 28;
      break;
    case "cold":
      s += 12;
      break;
    case "active":
      s += 18;
      break;
    case "awaiting_reply":
      s += 8;
      break;
    default:
      s += 5;
  }
  // Star (huge — manual signal)
  if (ctx.starred) s += 25;
  // CRM stage
  const PRIO = new Set([
    "Hot",
    "Warm",
    "Negotiation",
    "Proposal Sent",
    "Meeting Booked",
    "Contract Sent",
    "Closed Won",
  ]);
  if (ctx.pipeline_stage && PRIO.has(ctx.pipeline_stage)) s += 10;
  // Deal money
  if (ctx.charter_fee && ctx.charter_fee > 0) {
    s += Math.min(15, Math.round(Math.log10(ctx.charter_fee + 1) * 2));
  }
  // Health (warming = boost, cooling = lower priority since no
  // immediate action will help)
  if (typeof ctx.health_score === "number") {
    s += Math.round((ctx.health_score - 50) / 10);
  }
  // Open commitment
  if (ctx.has_overdue_commitment) s += 12;
  else if (ctx.has_open_commitment) s += 4;

  return Math.max(0, Math.min(100, s));
}

// @ts-nocheck
// Thin TikTok Content Posting API wrapper.
//
// Spec: https://developers.tiktok.com/doc/content-posting-api-reference
//
// Three things this file does, nothing else:
//   1. Refresh the stored OAuth token when it's about to expire.
//   2. Upload a video/photo and start a post.
//   3. Poll post status until PUBLISH_COMPLETE (or fail).
//
// Token storage: a single row in `settings` (key='tiktok_oauth') with
// a JSON value = { access_token, refresh_token, expires_at }. The
// OAuth callback route (/api/auth/tiktok/callback) writes the first
// token after George connects @george.yachts; this helper refreshes
// it when needed.
//
// Why not use a TikTok SDK? Their official Node SDK is incomplete for
// Content Posting (focuses on Login Kit). Raw fetch is cleaner and
// easier to read in ~200 lines.

import { createServiceClient } from "@/lib/supabase-server";

const TT_CLIENT_KEY = process.env.TIKTOK_CLIENT_KEY;
const TT_CLIENT_SECRET = process.env.TIKTOK_CLIENT_SECRET;
const TT_API_BASE = "https://open.tiktokapis.com/v2";

type TikTokTokenRow = {
  access_token: string;
  refresh_token: string;
  expires_at: number; // ms epoch
  open_id?: string;
};

async function loadToken(): Promise<TikTokTokenRow | null> {
  const sb = createServiceClient();
  const { data } = await sb
    .from("settings")
    .select("value")
    .eq("key", "tiktok_oauth")
    .maybeSingle();
  if (!data?.value) return null;
  try {
    return typeof data.value === "string" ? JSON.parse(data.value) : data.value;
  } catch {
    return null;
  }
}

async function saveToken(row: TikTokTokenRow): Promise<void> {
  const sb = createServiceClient();
  await sb
    .from("settings")
    .upsert(
      { key: "tiktok_oauth", value: JSON.stringify(row) },
      { onConflict: "key" }
    );
}

// Returns a valid access token, refreshing on the fly if <5 min left.
export async function getValidAccessToken(): Promise<string | null> {
  const row = await loadToken();
  if (!row) return null;
  const fiveMinFromNow = Date.now() + 5 * 60 * 1000;
  if (row.expires_at > fiveMinFromNow) return row.access_token;

  // Refresh
  const body = new URLSearchParams({
    client_key: TT_CLIENT_KEY ?? "",
    client_secret: TT_CLIENT_SECRET ?? "",
    grant_type: "refresh_token",
    refresh_token: row.refresh_token,
  });
  try {
    const res = await fetch(`${TT_API_BASE}/oauth/token/`, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
    });
    const data = await res.json();
    if (!data?.access_token) return null;
    const fresh: TikTokTokenRow = {
      access_token: data.access_token,
      refresh_token: data.refresh_token ?? row.refresh_token,
      expires_at: Date.now() + (data.expires_in ?? 3600) * 1000,
      open_id: row.open_id,
    };
    await saveToken(fresh);
    return fresh.access_token;
  } catch {
    return null;
  }
}

// ── Video publish (single reel/video file) ──
// We use the PULL_FROM_URL path so TikTok fetches the video from our
// Supabase public bucket. Avoids the 2-step chunked upload when the
// video is already accessible on the open internet.
export async function publishVideo({
  videoUrl,
  caption,
}: {
  videoUrl: string;
  caption: string;
}): Promise<{ ok: boolean; publish_id?: string; error?: string }> {
  const token = await getValidAccessToken();
  if (!token) return { ok: false, error: "no_token" };

  try {
    const res = await fetch(`${TT_API_BASE}/post/publish/video/init/`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        post_info: {
          title: caption.slice(0, 2200),
          privacy_level: "PUBLIC_TO_EVERYONE",
          disable_duet: false,
          disable_comment: false,
          disable_stitch: false,
          brand_content_toggle: false,
        },
        source_info: {
          source: "PULL_FROM_URL",
          video_url: videoUrl,
        },
      }),
    });
    const data = await res.json();
    if (data?.data?.publish_id) {
      return { ok: true, publish_id: data.data.publish_id };
    }
    return { ok: false, error: data?.error?.message ?? "publish_init_failed" };
  } catch (e) {
    return { ok: false, error: String(e).slice(0, 200) };
  }
}

// ── Photo carousel publish ──
// Up to 35 images. Good fit for our existing IG photo posts that we
// want to mirror.
export async function publishPhotos({
  photoUrls,
  caption,
}: {
  photoUrls: string[];
  caption: string;
}): Promise<{ ok: boolean; publish_id?: string; error?: string }> {
  const token = await getValidAccessToken();
  if (!token) return { ok: false, error: "no_token" };
  if (photoUrls.length === 0) return { ok: false, error: "no_photos" };

  try {
    const res = await fetch(`${TT_API_BASE}/post/publish/content/init/`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        post_info: {
          title: caption.slice(0, 2200),
          privacy_level: "PUBLIC_TO_EVERYONE",
          disable_comment: false,
          auto_add_music: true,
        },
        source_info: {
          source: "PULL_FROM_URL",
          photo_images: photoUrls.slice(0, 35),
          photo_cover_index: 0,
        },
        post_mode: "DIRECT_POST",
        media_type: "PHOTO",
      }),
    });
    const data = await res.json();
    if (data?.data?.publish_id) {
      return { ok: true, publish_id: data.data.publish_id };
    }
    return { ok: false, error: data?.error?.message ?? "publish_init_failed" };
  } catch (e) {
    return { ok: false, error: String(e).slice(0, 200) };
  }
}

// Poll publish status. TikTok reports SEND_TO_USER_INBOX when the
// video is uploaded but not yet approved, and PUBLISH_COMPLETE once
// it's live on the feed. We wait up to ~2 min then give up and
// return PENDING.
export async function pollPublishStatus(
  publishId: string,
  maxPolls = 24
): Promise<{ status: string; raw?: unknown }> {
  const token = await getValidAccessToken();
  if (!token) return { status: "NO_TOKEN" };
  for (let i = 0; i < maxPolls; i++) {
    try {
      const res = await fetch(`${TT_API_BASE}/post/publish/status/fetch/`, {
        method: "POST",
        headers: {
          Authorization: `Bearer ${token}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ publish_id: publishId }),
      });
      const data = await res.json();
      const status = data?.data?.status ?? "UNKNOWN";
      if (status === "PUBLISH_COMPLETE") return { status, raw: data };
      if (status === "FAILED") return { status, raw: data };
      await new Promise((r) => setTimeout(r, 5000));
    } catch {
      // ignore, retry
    }
  }
  return { status: "PENDING" };
}

